                      : "bg-white/5 border-white/10 text-gray-400"
                )}>
                  <Clock size={10} />
                  <span className="font-mono">{remaining}</span>
                </div>
              </div>
            )}

            {/* Expiry progress bar */}
            {remaining && !expired && (
              <div className="mx-4 mt-1">
                <div className="h-[3px] w-full bg-white/5 rounded-full overflow-hidden">
                  <div
