import { motion } from 'motion/react';
import { memo } from 'react';

interface Props {
  altitude: number;
  displayAltitude: string;
}

const TICK_HEIGHT = 32;
const VISIBLE_TICKS = 12;

function AltitudeTape({ altitude, displayAltitude }: Props) {
  const baseAlt = Math.floor(altitude / 100) * 100;
  const offset = ((altitude % 100) / 100) * TICK_HEIGHT;

  const ticks: number[] = [];
  const half = Math.floor(VISIBLE_TICKS / 2);
  for (let i = -half; i <= half; i++) {
    ticks.push(baseAlt + i * 100);
  }

  return (
    <div className="relative w-[120px] h-[320px] bg-zinc-900/80 border border-zinc-700 rounded-l-md overflow-hidden select-none">
      {/* Moving scale */}
      <div className="absolute inset-0 overflow-hidden">
        <motion.div
          animate={{ y: offset }}
          transition={{ type: 'tween', duration: 0.3, ease: 'linear' }}
          className="absolute w-full"
          style={{ top: '50%', marginTop: -(VISIBLE_TICKS / 2) * TICK_HEIGHT }}
        >
          {ticks.map((val, i) => {
            const isMajor = val % 500 === 0;
            return (
              <div
                key={i}
                className="flex items-center justify-end pr-2"
                style={{ height: TICK_HEIGHT }}
              >
                <span
                  className={`text-right tabular-nums ${
                    isMajor
                      ? 'text-[11px] font-semibold text-zinc-300'
                      : 'text-[9px] text-zinc-600'
                  }`}
                >
                  {isMajor ? val.toLocaleString() : ''}
                </span>
                <div
                  className={`ml-1.5 bg-zinc-600 ${isMajor ? 'w-4 h-[1px]' : 'w-2 h-[1px]'}`}
                />
              </div>
            );
          })}
        </motion.div>
      </div>

      {/* Center readout box */}
      <div className="absolute top-1/2 -translate-y-1/2 left-[-2px] right-[-2px] h-14 bg-black border-2 border-cyan-400 z-10 flex items-center justify-center shadow-[0_0_20px_rgba(34,211,238,0.35)]">
        <span className="text-[26px] font-bold text-cyan-400 tabular-nums tracking-tight">
          {displayAltitude}
        </span>
        <span className="text-[9px] text-cyan-700 font-bold ml-1 self-end mb-2.5">FT</span>
      </div>

      {/* Gradient fades top/bottom */}
      <div className="absolute inset-x-0 top-0 h-10 bg-gradient-to-b from-zinc-900/90 to-transparent z-[5] pointer-events-none" />
      <div className="absolute inset-x-0 bottom-0 h-10 bg-gradient-to-t from-zinc-900/90 to-transparent z-[5] pointer-events-none" />
    </div>
  );
}

export default memo(AltitudeTape, (prev, next) => {
  return prev.altitude === next.altitude && prev.displayAltitude === next.displayAltitude;
});

import { motion } from 'motion/react';
import { memo } from 'react';

interface Props {
  heading: number; // 0-359
}

const DEG_PER_TICK = 5;
const PX_PER_DEG = 4;
const TOTAL_TICKS = 360 / DEG_PER_TICK; // 72
const TAPE_WIDTH = TOTAL_TICKS * DEG_PER_TICK * PX_PER_DEG; // 1440px

const CARDINAL: Record<number, string> = { 0: 'N', 90: 'E', 180: 'S', 270: 'W' };
const ORDINAL: Record<number, string> = { 45: 'NE', 135: 'SE', 225: 'SW', 315: 'NW' };

function buildTicks() {
  const ticks = [];
  for (let i = 0; i < TOTAL_TICKS; i++) {
    const deg = i * DEG_PER_TICK;
    const isMajor = deg % 30 === 0;
    const label = CARDINAL[deg] || ORDINAL[deg] || (deg % 10 === 0 ? String(deg) : '');
    ticks.push({ deg, isMajor, label });
  }
  return ticks;
}
const TICKS = buildTicks();

function HeadingTape({ heading }: Props) {
  // Normalize heading to [0, 360)
  const hdg = ((heading % 360) + 360) % 360;

  // We render 3 copies of the tape for seamless wrapping at 0°/360°
  const translateX = -(hdg * PX_PER_DEG) - TAPE_WIDTH;

  return (
    <div className="relative w-full h-[56px] bg-zinc-900/90 border border-zinc-700 rounded-md overflow-hidden select-none">
      {/* Center lubber line */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[2px] h-3 bg-orange-500 z-20" />

      {/* Scrolling tape */}
      <div className="absolute inset-0 overflow-hidden">
        <motion.div
          animate={{ x: translateX }}
          transition={{ type: 'tween', duration: 0.3, ease: 'linear' }}
          className="flex items-end h-full"
          style={{ paddingLeft: '50%', width: TAPE_WIDTH * 3 }}
        >
          {[0, 1, 2].map((copy) =>
            TICKS.map((t, i) => (
              <div
                key={`${copy}-${i}`}
                className="flex-shrink-0 flex flex-col items-center"
                style={{ width: DEG_PER_TICK * PX_PER_DEG }}
              >
                <span
                  className={`text-[9px] mb-0.5 tabular-nums ${
                    CARDINAL[t.deg]
                      ? 'text-white font-bold'
                      : t.isMajor
                      ? 'text-zinc-400 font-semibold'
                      : 'text-zinc-700'
                  }`}
                >
                  {t.label}
                </span>
                <div
                  className={`w-[1px] ${
                    t.isMajor ? 'h-3 bg-zinc-500' : 'h-1.5 bg-zinc-700'
                  }`}
                />
              </div>
            ))
          )}
        </motion.div>
      </div>

      {/* Digital heading readout */}
      <div className="absolute inset-x-0 bottom-1 flex justify-center z-10">
        <span className="bg-black/80 px-2.5 py-0.5 border border-zinc-700 rounded text-[11px] font-bold text-cyan-400 tabular-nums">
          {Math.round(hdg).toString().padStart(3, '0')}°
        </span>
      </div>
    </div>
  );
}

export default memo(HeadingTape, (prev, next) => {
  return Math.abs(prev.heading - next.heading) < 1;
});

