function getBuffer(): object[] {
  try {
    return JSON.parse(localStorage.getItem(BUFFER_KEY) || '[]');
  } catch { return []; }
}

function pushBuffer(payload: object) {
  const buf = getBuffer();
  buf.push(payload);
  localStorage.setItem(BUFFER_KEY, JSON.stringify(buf.slice(-20))); // cap at 20
}

function clearBuffer() {
  localStorage.removeItem(BUFFER_KEY);
}

async function flushBuffer(): Promise<void> {
  const buf = getBuffer();
  if (buf.length === 0) return;
  console.log(`[Discord] Flushing ${buf.length} buffered message(s)...`);
  const remaining: object[] = [];
  for (const payload of buf) {
    const code = await sendEmbed(payload);
    if (code === null || (code >= 400 && code !== 429)) {
      remaining.push(payload); // keep if still failing
    }
  }
  if (remaining.length > 0) {
    localStorage.setItem(BUFFER_KEY, JSON.stringify(remaining));
  } else {
    clearBuffer();
  }
}

// Start buffer flush interval (every 60s)
let _flushInterval: ReturnType<typeof setInterval> | null = null;
function ensureFlushLoop() {
  if (_flushInterval) return;
  _flushInterval = setInterval(() => flushBuffer().catch(() => {}), 60_000);
}

// ── Core Send ────────────────────────────────────────────────────

async function sendEmbed(payload: object): Promise<number | null> {
  try {
    const res = await fetch(WEBHOOK_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    console.log(`[Discord] Webhook response: ${res.status}`);
    return res.status;
  } catch (err) {
    console.error('[Discord] Webhook error:', err);
    return null;
  }
}

async function sendWithBuffer(payload: object): Promise<void> {
  ensureFlushLoop();
  const code = await sendEmbed(payload);
  if (code === null || (code >= 400 && code !== 204 && code !== 200)) {
    console.warn('[Discord] Buffering payload for retry');
    pushBuffer(payload);
  }
}

// ── Diagnostic Handshake (one-time) ──────────────────────────────

const VERIFIED_KEY = 'LVT_DISCORD_VERIFIED';

export async function runDiscordDiagnostic(): Promise<void> {
  // Diagnostic is now silent — no embed posted to Discord channel.
  // We still mark as verified so the check doesn't run repeatedly.
  if (localStorage.getItem(VERIFIED_KEY) === 'true') {
    console.log('[Discord] Webhook already verified — skipping diagnostic.');
    return;
  }
  console.log('[Discord] Connection diagnostic: webhook URL configured.');
  localStorage.setItem(VERIFIED_KEY, 'true');
}

// ── Flight Notifications ─────────────────────────────────────────

export async function notifyFlightStarted(event: FlightEvent): Promise<void> {
  await sendWithBuffer({
    embeds: [{
      title: '✈️  Flight Started',
      color: GOLD,
      fields: [
        { name: 'Pilot', value: `${safe(event.pilotName)} (${safe(event.pilotId)})`, inline: true },
        { name: 'Callsign', value: safe(event.callsign), inline: true },
        { name: 'Aircraft', value: safe(event.aircraftType), inline: true },
        { name: 'Route', value: `${safe(event.departureIcao)} → ${safe(event.arrivalIcao)}`, inline: true },
        ...(event.route ? [{ name: 'Planned Route', value: safe(event.route), inline: false }] : []),
      ],
      timestamp: new Date().toISOString(),
      footer: { text: 'Levant ACARS v3.1.7' },
    }],
  });
}

export async function notifyFlightEnded(
  event: FlightEvent & { score?: number; landingGrade?: string; flightTime?: string; landingRate?: number },
): Promise<void> {
  const fpm = event.landingRate ?? 0;
  const grade = event.landingGrade || getLandingGrade(fpm);
  const score = event.score ?? getLandingScore(fpm);
  const color = getGradeColor(grade);

  // Exact format string requested
  const reportString = `${safe(event.callsign)} has landed at ${safe(event.arrivalIcao)} with a landing rate of ${fpm.toFixed(2)}fpm and performance score of ${score}%.`;

  await sendWithBuffer({
    content: reportString,
    embeds: [{
      title: `🛬  Landing Grade: ${grade}`,
      color,
      fields: [
        { name: 'Pilot', value: `${safe(event.pilotName)} (${safe(event.pilotId)})`, inline: true },
        { name: 'Callsign', value: safe(event.callsign), inline: true },
        { name: 'Route', value: `${safe(event.departureIcao)} → ${safe(event.arrivalIcao)}`, inline: true },
        { name: 'Landing Rate', value: `${fpm.toFixed(0)} FPM`, inline: true },
        { name: 'Score', value: `${score}%`, inline: true },
        { name: 'Grade', value: grade, inline: true },
        ...(event.flightTime ? [{ name: 'Flight Time', value: event.flightTime, inline: true }] : []),
      ],
      timestamp: new Date().toISOString(),
      footer: { text: 'Levant ACARS v3.1.7' },
    }],
  });
}

// ── Landing Black Box Touchdown Notification ─────────────────────

export async function notifyTouchdown(
  event: FlightEvent,
  landing: LandingData,
): Promise<void> {
  const color = getGradeColor(landing.grade);
  await sendWithBuffer({
    embeds: [{
      title: `🛬 Touchdown Recorded — ${landing.grade}`,
      color,
      fields: [
        { name: 'Rate', value: `${landing.fpm.toFixed(0)} FPM`, inline: true },
        { name: 'G-Force', value: `${landing.gForce.toFixed(2)}G`, inline: true },
        { name: 'Score', value: `${landing.score}%`, inline: true },
        { name: 'Callsign', value: safe(event.callsign), inline: true },
        { name: 'Arrival', value: safe(event.arrivalIcao), inline: true },
      ],
      timestamp: new Date().toISOString(),
      footer: { text: 'Levant ACARS v3.1.7 — Black Box' },
    }],
  });
}

// ── Logbook Persistence (localStorage) ───────────────────────────

const LOGBOOK_KEY = 'LVT_LOGBOOK';

export interface LogbookEntry {
  date: string;
  callsign: string;
  route: string;
  departureIcao: string;
  arrivalIcao: string;
  aircraftType: string;
  fpm: number;
  score: number;
  grade: string;
  flightTime: string;
  report: string;
}

export function saveFlightToLogbook(entry: LogbookEntry): void {
  try {
    const logbook: LogbookEntry[] = JSON.parse(localStorage.getItem(LOGBOOK_KEY) || '[]');
    logbook.unshift(entry);
    // Keep last 200 entries
    localStorage.setItem(LOGBOOK_KEY, JSON.stringify(logbook.slice(0, 200)));
    console.log('[Logbook] Flight saved:', entry.callsign, entry.route);
  } catch (err) {
    console.error('[Logbook] Failed to save:', err);
  }
}

export function getLogbook(): LogbookEntry[] {
  try {
    return JSON.parse(localStorage.getItem(LOGBOOK_KEY) || '[]');
  } catch { return []; }
}

export function clearLogbook(): void {
  localStorage.removeItem(LOGBOOK_KEY);
}

import { useState, useCallback, useMemo, useRef, useEffect } from 'react';

/** ISA constants */
const ISA_SEA_LEVEL_PRESSURE_HPA = 1013.25;
const HPA_PER_INHG = 33.8639;

/** US transition altitude (FL180) */
const TRANSITION_ALT_FT = 18000;

export interface AltimeterState {
  /** Indicated altitude in feet (adjusted for QNH) */
  indicatedAltitude: number;
  /** Pressure altitude in feet (std 1013.25 hPa) */
  pressureAltitude: number;
  /** Formatted altitude string for PFD display (rounded to nearest 10 ft) */
  displayAltitude: string;
  /** Current QNH in hPa */
  qnhHpa: number;
  /** Current QNH in inHg */
  qnhInHg: string;
  /** Whether standard pressure is active */
  isStandard: boolean;
  /** Warning: above transition altitude but not on STD */
  transitionWarning: boolean;
  /** Vertical speed in ft/min (smoothed) */
  verticalSpeed: number;
  /** Toggle between STD and local QNH */
  toggleStandard: () => void;
  /** Set local QNH (hPa) */
  setLocalQnh: (hpa: number) => void;
}

/**
 * Barometric altitude hook using the International Standard Atmosphere model.
 *
 * Hypsometric formula (below 36,089 ft / 11,000 m):
 *   h = (T₀ / L) × [1 − (P / P₀)^(R·L / g·M)]
 *
 * Simplified linear approximation for small QNH deviations:
 *   indicated_alt ≈ pressure_alt + (QNH − 1013.25) × 27
 */
export function useAltimeter(
  rawPressureAltitudeFt: number | null,
  rawVerticalSpeed: number,
): AltimeterState {
  const [isStandard, setIsStandard] = useState(false);
  const [localQnh, setLocalQnh] = useState(ISA_SEA_LEVEL_PRESSURE_HPA);

  // ── Smoothed VS via low-pass filter ────────────────────────────
  const prevVsRef = useRef(0);
  const smoothedVs = useRef(0);

  useEffect(() => {
    const alpha = 0.15; // smoothing factor
    smoothedVs.current = smoothedVs.current + alpha * (rawVerticalSpeed - smoothedVs.current);
    prevVsRef.current = rawVerticalSpeed;
  }, [rawVerticalSpeed]);

  const activeQnh = isStandard ? ISA_SEA_LEVEL_PRESSURE_HPA : localQnh;

  const calculations = useMemo(() => {
    if (rawPressureAltitudeFt === null || rawPressureAltitudeFt === undefined) {
      return {
        pressureAltitude: 0,
        indicatedAltitude: 0,
        displayAltitude: '-----',
        transitionWarning: false,
      };
    }

    // Pressure altitude is what we get from FSUIPC (referenced to 1013.25)
    const pressureAltitude = rawPressureAltitudeFt;

    // Apply QNH correction: ~27 ft per hPa deviation from standard
    const qnhCorrectionFt = (activeQnh - ISA_SEA_LEVEL_PRESSURE_HPA) * 27;
    const indicatedAltitude = pressureAltitude + qnhCorrectionFt;

    // Round to nearest 10 ft for display
    const rounded = Math.round(indicatedAltitude / 10) * 10;
    const displayAltitude = rounded.toLocaleString('en-US', {
      minimumIntegerDigits: 1,
      useGrouping: false,
    });

    // Transition warning: above FL180 but not on STD
    const transitionWarning = indicatedAltitude > TRANSITION_ALT_FT && !isStandard;

    return { pressureAltitude, indicatedAltitude, displayAltitude, transitionWarning };
  }, [rawPressureAltitudeFt, activeQnh, isStandard]);

  const toggleStandard = useCallback(() => setIsStandard(prev => !prev), []);
  const setLocalQnhCb = useCallback((hpa: number) => setLocalQnh(hpa), []);

  return {
    indicatedAltitude: calculations.indicatedAltitude,
    pressureAltitude: calculations.pressureAltitude,
    displayAltitude: calculations.displayAltitude,
    qnhHpa: activeQnh,
    qnhInHg: (activeQnh / HPA_PER_INHG).toFixed(2),
    isStandard,
    transitionWarning: calculations.transitionWarning,
    verticalSpeed: Math.round(smoothedVs.current),
    toggleStandard,
    setLocalQnh: setLocalQnhCb,
  };
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { onBridgeMessage, SimBridge } from '../bridge';
import {
  runDiscordDiagnostic,
  getLandingGrade,
  getLandingScore,
  saveFlightToLogbook,
} from '../discord';
import { pushToast } from '../components/ToastOverlay';
import type {
  TelemetryData,
  FlightState,
  ScoreResult,
  UILogEntry,
  ConnectionState,
  AuthState,
  WeatherData,
  BidData,
  TouchdownPoint,
  BridgeMessage
} from '../types';

// ── Default state factories ───────────────────────────────────────

const defaultTelemetry: TelemetryData = {
  type: 'telemetry',
  latitude: 0,
  longitude: 0,
  altitude: 0,
  radioAltitude: 0,
  heading: 0,
  groundSpeed: 0,
  ias: 0,
  verticalSpeed: 0,
  pitch: 0,
  bank: 0,
  gForce: 1.0,
  onGround: true,
  enginesOn: false,
  totalFuel: 0,
  flapsPosition: 0,
  gearPosition: 0,
  parkingBrake: false,
  throttle: 0,
  stallWarning: false,
  overspeedWarning: false,
  aircraftTitle: 'N/A',
  phase: 'Preflight',
  fuelPercent: 0,
  simRate: 1.0,
  isPaused: false,
  totalPauseSeconds: 0,
  isNonStandard: false,
  integrityScore: 100,
  flightProgress: 0,
  distanceFlownNm: 0,
  plannedDistanceNm: 0,
};

const defaultAuth: AuthState = {
  type: 'auth',
  isLoggedIn: false,
  pilotName: '',
  pilotId: '',
  pilotRank: '',
  pilotAvatar: '',
  pilotHours: 0,
  pilotXp: 0,
  weightUnit: 'lbs',
  deviceCode: '',
  isLoggingIn: false,
};

const defaultConnection: ConnectionState = {
  type: 'connection',
  simConnected: false,
  apiConnected: false,
};

const defaultFlight: FlightState = {
  type: 'flight',
  isActive: false,
  flightNumber: '',
  callsign: '',
  departureIcao: '',
  arrivalIcao: '',
  aircraftType: '',
  currentPhase: 'Preflight',
  flightTime: '00:00',
  comfortScore: 100,
  exceedanceCount: 0,
  distanceNm: 0,
  fuelUsed: 0,
  landingRate: 0,
  progress: 0,
  oooi: { gateOut: '', wheelsOff: '', wheelsOn: '', gateIn: '' },
};

// ── Helpers ───────────────────────────────────────────────────────

const SUCCESS_KEYWORDS = ['takeoff', 'landing', 'arrived', 'departed', 'completed', 'started', 'cruise', 'pushback', 'taxi', 'boarding', 'reached'];
const WARNING_KEYWORDS = ['warning', 'alert', 'exceed', 'violation', 'overspeed', 'stall', 'fail'];

function classifyLog(message: string): 'success' | 'warning' | 'info' {
  const lower = message.toLowerCase();
  if (WARNING_KEYWORDS.some(k => lower.includes(k))) return 'warning';
  if (SUCCESS_KEYWORDS.some(k => lower.includes(k))) return 'success';
  return 'info';
}

// ── Hook ──────────────────────────────────────────────────────────

export function useTelemetry() {
  const [telemetry, setTelemetry] = useState<TelemetryData>(defaultTelemetry);
  const [auth, setAuth] = useState<AuthState>(defaultAuth);
  const [connection, setConnection] = useState<ConnectionState>(defaultConnection);
  const [flight, setFlight] = useState<FlightState>(defaultFlight);
  const [score, setScore] = useState<ScoreResult | null>(null);
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [discordVerified, setDiscordVerified] = useState(false);
  const [updateStatus, setUpdateStatus] = useState<{ status: string; message: string; version?: string; progress?: number } | null>(null);
  const qnhRef = useRef(1013.25);
  const [bid, setBid] = useState<BidData | null>(null);
  const [touchdownPoint, setTouchdownPoint] = useState<TouchdownPoint | null>(null);
  const [activityLog, setActivityLog] = useState<UILogEntry[]>([]);
  const [exceedanceLog, setExceedanceLog] = useState<UILogEntry[]>([]);
  const logIdRef = useRef(0);
  const authRef = useRef(auth);
  authRef.current = auth;

  // ── Landing Black Box ──────────────────────────────────────────
  const blackBoxRef = useRef({
    armed: false,
    touchdownFPM: 0,
    maxGForce: 1.0,
    fired: false,
  });

  // Throttle: skip telemetry setState if nothing visually changed (reduces re-renders)
  // Increased thresholds to reduce GPU strain and prevent Vulkan device loss
  const lastTelemetryRef = useRef<TelemetryData | null>(null);
  function telemetryChanged(a: TelemetryData, b: TelemetryData): boolean {
    return a.phase !== b.phase || a.onGround !== b.onGround
      || a.stallWarning !== b.stallWarning || a.overspeedWarning !== b.overspeedWarning
      || Math.abs(a.altitude - b.altitude) > 20 || Math.abs(a.ias - b.ias) > 3
      || Math.abs(a.groundSpeed - b.groundSpeed) > 3 || Math.abs(a.heading - b.heading) > 2
      || Math.abs(a.verticalSpeed - b.verticalSpeed) > 50 || Math.abs(a.gForce - b.gForce) > 0.02
      || Math.abs(a.radioAltitude - b.radioAltitude) > 5;
  }

  const handleMessage = useCallback((data: unknown) => {
    const msg = data as BridgeMessage;
    if (!msg || typeof msg !== 'object' || !('type' in msg)) return;

    switch (msg.type) {
      case 'telemetry': {
        const t = msg as TelemetryData;

        // Skip state update if values haven't changed enough to matter visually
        if (lastTelemetryRef.current && !telemetryChanged(lastTelemetryRef.current, t)) return;
        lastTelemetryRef.current = t;

        setTelemetry(prev => {
          // Detect phase changes and push toast
          if (prev.phase && t.phase && prev.phase !== t.phase && t.phase !== 'Preflight') {
            pushToast('info', `Phase: ${prev.phase} → ${t.phase}`);
          }
          // Stall/overspeed toast (once per activation)
          if (t.stallWarning && !prev.stallWarning) pushToast('danger', 'STALL WARNING — Increase speed!');
          if (t.overspeedWarning && !prev.overspeedWarning) pushToast('danger', 'OVERSPEED — Reduce speed!');

          // ── Landing Black Box: arm below 50ft, capture VS at touchdown ──
          // Uses Weight-on-Wheels (onGround) + radioAlt <= 1 for reliable detection
          const bb = blackBoxRef.current;
          if (t.radioAltitude < 50 && t.radioAltitude > 1 && !t.onGround) {
            bb.armed = true;
            // Continuously capture the last VS before wheels touch — most accurate FPM
            if (t.verticalSpeed < bb.touchdownFPM) bb.touchdownFPM = t.verticalSpeed;
            if (t.gForce > bb.maxGForce) bb.maxGForce = t.gForce;
          }
          if (bb.armed && !bb.fired && t.onGround && t.radioAltitude <= 1 && t.groundSpeed > 30) {
            bb.fired = true;
            const fpm = bb.touchdownFPM;
            const gf = bb.maxGForce;
            const grade = getLandingGrade(fpm);
            const score = getLandingScore(fpm);
            console.log(`[BlackBox] Touchdown: ${fpm.toFixed(0)} FPM, ${gf.toFixed(2)}G, ${grade}, ${score}%`);
            pushToast('info', `Touchdown: ${fpm.toFixed(0)} FPM — ${grade}`);
            // Touchdown notification is handled by C# DiscordWebhookService — no React-side webhook needed
          }
          // Reset black box when airborne again
          if (!t.onGround && t.radioAltitude > 50) {
            bb.armed = false;
            bb.fired = false;
            bb.touchdownFPM = 0;
            bb.maxGForce = 1.0;
          }

          return t;
        });
        break;
      }
      case 'auth':
        setAuth(msg as AuthState);
        break;
      case 'connection': {
        const c = msg as ConnectionState;
        setConnection(prev => {
          if (c.simConnected && !prev.simConnected) pushToast('success', 'FSUIPC Connected');
          if (!c.simConnected && prev.simConnected) pushToast('warning', 'FSUIPC Disconnected');
          return c;
        });
        break;
      }
      case 'flight': {
        const f = msg as FlightState;
        setFlight(prev => {
          // Detect flight start transition (was inactive → now active)
          if (f.isActive && !prev.isActive && f.callsign) {
            console.log('[useTelemetry] Flight started:', f.callsign);
            // Webhook notification handled by C# DiscordWebhookService — no React-side webhook needed
          }
          return f;
        });
        break;
      }
      case 'score': {
        const s = msg as ScoreResult;
        setScore(s);
        // Webhook notification handled by C# DiscordWebhookService — save to local logbook only
        setFlight(prev => {
          if (prev.callsign) {
            const fpm = prev.landingRate || blackBoxRef.current.touchdownFPM || 0;
            const grade = s.landingGrade || getLandingGrade(fpm);
            const reportString = `${prev.callsign} has landed at ${prev.arrivalIcao} with a landing rate of ${fpm.toFixed(2)}fpm and performance score of ${s.finalScore}%.`;
            saveFlightToLogbook({
              date: new Date().toLocaleDateString(),
              callsign: prev.callsign,
              route: `${prev.departureIcao}-${prev.arrivalIcao}`,
              departureIcao: prev.departureIcao,
              arrivalIcao: prev.arrivalIcao,
              aircraftType: prev.aircraftType,
              fpm,
              score: s.finalScore,
              grade,
              flightTime: prev.flightTime,
              report: reportString,
            });
          }
          return prev;
        });
        break;
      }
      case 'activity': {
        const raw = msg as { message: string; timestamp?: string };
        const entry: UILogEntry = {
          id: ++logIdRef.current,
          kind: classifyLog(raw.message),
          event: raw.message,
          timestamp: raw.timestamp || new Date().toLocaleTimeString('en-GB', { hour12: false }),
        };
        // Deduplicate: skip if the most recent activity has the same message
        setActivityLog(prev => {
          if (prev.length > 0 && prev[0].event === raw.message) return prev;
          return [entry, ...prev].slice(0, 100);
        });
        break;
      }
      case 'exceedance': {
        const raw = msg as { message: string; timestamp?: string };
        const entry: UILogEntry = {
          id: ++logIdRef.current,
          kind: 'warning',
          event: raw.message,
          timestamp: raw.timestamp || new Date().toLocaleTimeString('en-GB', { hour12: false }),
        };
        // Deduplicate: skip if the most recent exceedance has the same message
        setExceedanceLog(prev => {
          if (prev.length > 0 && prev[0].event === raw.message) return prev;
          return [entry, ...prev].slice(0, 100);
        });
        pushToast('warning', raw.message);
        break;
      }
      case 'weather': {
        const w = msg as WeatherData;
        // Parse QNH from pressure field or metar
        if (w.qnh && w.qnh > 0) {
          qnhRef.current = w.qnh;
        } else if (w.pressure) {
          const match = w.pressure.match(/(\d{3,4}\.?\d*)/); 
          if (match) {
            const val = parseFloat(match[1]);
            // If value looks like inHg (28-32 range), convert to hPa
            qnhRef.current = val < 100 ? val * 33.8639 : val;
          }
        }
        setWeather(w);
        break;
      }
      case 'touchdown': {
        const td = msg as TouchdownPoint & { type: string };
        setTouchdownPoint({ latitude: td.latitude, longitude: td.longitude, landingRate: td.landingRate, groundSpeed: td.groundSpeed });
        break;
      }
      case 'bid': {
        const b = msg as BidData;
        const resolved = b.callsign ? b : null;
        console.log('[useTelemetry] bid message received:', resolved?.callsign ?? 'null');
        setBid(resolved);
        break;
      }
      case 'updateStatus': {
        const u = msg as { status: string; message: string; version?: string; progress?: number };
        setUpdateStatus(u);
        // Auto-dismiss "up to date" and "error" after 4s
        if (u.status === 'upToDate' || u.status === 'error') {
          setTimeout(() => setUpdateStatus(null), 4000);
        }
        break;
      }
    }
  }, []);

  useEffect(() => {
    const unsub = onBridgeMessage(handleMessage);
    return unsub;
  }, [handleMessage]);

  // Auto-fetch bid when logged in + periodic poll (every 30s)
  const prevLoggedIn = useRef(false);
  const prevPilotId = useRef('');
  useEffect(() => {
    if (auth.isLoggedIn && !prevLoggedIn.current) {
      // Just logged in — fetch bid + run one-time Discord diagnostic
      if (auth.pilotId) SimBridge.fetchBid();
      runDiscordDiagnostic()
        .then(() => { setDiscordVerified(localStorage.getItem('LVT_DISCORD_VERIFIED') === 'true'); })
        .catch(() => {});
    }
    // Also fetch bid when pilotId arrives after login (race condition fix)
    if (auth.isLoggedIn && auth.pilotId && !prevPilotId.current) {
      console.log('[useTelemetry] pilotId arrived, fetching bid:', auth.pilotId);
      SimBridge.fetchBid();
    }
    prevLoggedIn.current = auth.isLoggedIn;
    prevPilotId.current = auth.pilotId || '';

    if (!auth.isLoggedIn) return;
    const iv = setInterval(() => {
      if (!flight.isActive && auth.pilotId) SimBridge.fetchBid();
    }, 30000);
    return () => clearInterval(iv);
  }, [auth.isLoggedIn, auth.pilotId, flight.isActive]);

  const clearScore = useCallback(() => setScore(null), []);
  const clearLogs = useCallback(() => {
    setActivityLog([]);
    setExceedanceLog([]);
  }, []);

  // Cancel active flight — call C# bridge + reset all UI state to default
  const cancelFlight = useCallback(() => {
    SimBridge.cancelFlight();
    setFlight(defaultFlight);
    setScore(null);
    setBid(null);
    setTouchdownPoint(null);
    setActivityLog([]);
    setExceedanceLog([]);
    // Reset black box
    blackBoxRef.current = { armed: false, touchdownFPM: 0, maxGForce: 1.0, fired: false };
    pushToast('info', 'Flight cancelled — ACARS reset');
  }, []);

  // Submit / end the active flight — call C# bridge
  const submitFlight = useCallback(() => {
    SimBridge.endFlight();
    pushToast('info', 'Submitting flight...');
  }, []);

  // Allow external QNH injection (e.g. from IVAO METAR)
  const setQnhOverride = useCallback((qnh: number) => {
    if (qnh > 0) qnhRef.current = qnh;
  }, []);

  // Direct bid injection (bypasses C# bridge for React-side API calls)
  const injectBid = useCallback((b: BidData | null) => {
    console.log('[useTelemetry] injectBid:', b?.callsign ?? 'null');
    setBid(b);
  }, []);

  // Programmatic log entry
  const addLogEntry = useCallback((message: string) => {
    const entry: UILogEntry = {
      id: ++logIdRef.current,
      kind: classifyLog(message),
      event: message,
      timestamp: new Date().toLocaleTimeString('en-GB', { hour12: false }),
    };
    setActivityLog(prev => [entry, ...prev].slice(0, 100));
  }, []);

  // ── QNH-Corrected Altitude ─────────────────────────────────────
  // Formula: Altitude_Indicated = Altitude_Pressure + ((QNH - 1013.25) * 27.3)
  const qnhAltitude = Math.round(
    telemetry.altitude + (qnhRef.current - 1013.25) * 27.3
  );

  return {
    telemetry,
    auth,
    connection,
    flight,
    score,
    weather,
    discordVerified,
    updateStatus,
    bid,
    touchdownPoint,
    activityLog,
    exceedanceLog,
    qnhAltitude,
    injectBid,
    addLogEntry,
    setQnhOverride,
    clearScore,
    clearLogs,
    cancelFlight,
    submitFlight,
  };
}

