import { NextRequest, NextResponse } from 'next/server';
import { jwtVerify } from 'jose';
import connectDB from '@/lib/database';
import Bid from '@/models/Bid';
import mongoose from 'mongoose';

export async function POST(request: NextRequest) {
    try {
        const token = request.cookies.get('lva_session')?.value;

        if (!token) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const secret = new TextEncoder().encode(process.env.JWT_SECRET || "");
        const { payload } = await jwtVerify(token, secret);

        const body = await request.json();
        const { bidId } = body;

        await connectDB();

        const userId = payload.id as string;
        const pilotIdString = payload.pilotId as string;

        let result;

        if (bidId) {
            // Cancel specific bid (verify ownership)
            const result = await Bid.updateOne(
                {
                    _id: bidId,
                    pilot_id: new mongoose.Types.ObjectId(userId)
                },
                { status: 'Cancelled' }
            );
        } else {
             // Cancel all active bids for this pilot
            const result = await Bid.updateMany(
                {
                    pilot_id: new mongoose.Types.ObjectId(userId),
                    status: 'Active'
                },
                {
                    $set: {
                        status: 'Cancelled',
                        cancelled_at: new Date(),
                        cancelled_by: userId
                    }
                }
            );
        }

        if (result) {
            return NextResponse.json({ success: true, message: 'Booking cancelled' });
        } else {
             return NextResponse.json({ success: true, message: 'No active booking found or already cancelled' });
        }

    } catch (error: any) {
        console.error('Cancel booking error:', error);
        return NextResponse.json(
            { error: 'Failed to cancel booking' },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/database';
import { verifyAuth } from '@/lib/auth';
import { PilotModel } from '@/models';
import PilotAward from '@/models/PilotAward';
import Award from '@/models/Award';
import Event from '@/models/Event';
import Bid from '@/models/Bid';
import mongoose from 'mongoose';

// GET /api/portal/dashboard-extras — returns rank progress, awards, next event, weather
export async function GET(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    try {
        await connectDB();

        const pilot = await PilotModel.findById(session.id).select('pilot_id').lean();
        if (!pilot) return NextResponse.json({ error: 'Pilot not found' }, { status: 404 });


        // --- Recent Awards (Medal Case) ---
        const recentAwards = await PilotAward.find({
            pilot_id: new mongoose.Types.ObjectId(session.id)
        })
            .select('award_id earned_at')
            .sort({ earned_at: -1 })
            .limit(6)
            .lean();

        const awardIds = recentAwards.map((pa: any) => pa.award_id);
        const awards = await Award.find({ _id: { $in: awardIds } }).lean();
        const awardMap = new Map(awards.map((a: any) => [a._id.toString(), a]));

        const medalCase = recentAwards.map((pa: any) => {
            const award = awardMap.get(pa.award_id?.toString());
            return {
                name: (award as any)?.name || 'Unknown Award',
                description: (award as any)?.description || '',
                image_url: (award as any)?.imageUrl || '',
                awarded_at: pa.earned_at,
            };
        });

        // --- Next Event Countdown ---
        const now = new Date();
        const nextEvent = await Event.findOne({
            is_active: true,
            $or: [
                { start_datetime: { $gt: now } },
                { start_time: { $gt: now } },
            ],
        }).sort({ start_datetime: 1, start_time: 1 }).lean();

        let eventCountdown = null;
        if (nextEvent) {
            const start = new Date((nextEvent as any).start_datetime || (nextEvent as any).start_time);
            const diffMs = start.getTime() - now.getTime();
            const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
            const diffHours = Math.floor((diffMs % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const diffMins = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
            eventCountdown = {
                name: (nextEvent as any).title || (nextEvent as any).name || 'Upcoming Event',
                description: (nextEvent as any).description || '',
                start_datetime: (nextEvent as any).start_datetime,
                location: (nextEvent as any).departure_icao || (nextEvent as any).location || '',
                reward_points: (nextEvent as any).reward_points || 0,
                days: diffDays,
                hours: diffHours,
                minutes: diffMins,
            };
        }

        // --- Active Bid Weather ---
        let weather = null;
        const activeBids = await Bid.find({
            pilot_id: new mongoose.Types.ObjectId(session.id),
            status: 'active'
        })
            .select('departure_icao arrival_icao')
            .sort({ created_at: -1 })
            .limit(1)
            .lean();
        if (activeBids.length > 0) {
            try {
                const [depMetar, arrMetar] = await Promise.all([
                    fetchMetar(activeBids[0].departure_icao),
                    fetchMetar(activeBids[0].arrival_icao),
                ]);
                weather = {
                    departure_icao: activeBids[0].departure_icao,
                    arrival_icao: activeBids[0].arrival_icao,
                    departure_metar: depMetar,
                    arrival_metar: arrMetar,
                };
            } catch { /* non-fatal */ }
        }

        const res = NextResponse.json({
            rankProgress: null,
            medalCase,
            eventCountdown,
            weather,
        });
        res.headers.set('Cache-Control', 'private, max-age=30, stale-while-revalidate=60');
        return res;
    } catch (error: any) {
        console.error('Dashboard extras error:', error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

async function fetchMetar(icao: string): Promise<string> {
    try {
        const res = await fetch(`https://metar.vatsim.net/metar.php?id=${icao}`, { cache: 'no-store' });
        if (res.ok) {
            const text = await res.text();
            return text.trim() || `No METAR for ${icao}`;
        }
    } catch { /* ignore */ }
    return `No METAR for ${icao}`;
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/database';
import { verifyAuth } from '@/lib/auth';
import ActiveFlight from '@/models/ActiveFlight';

// GET /api/portal/delays — show pilots currently experiencing delays (headwinds, holding, slow ground speed)
export async function GET(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    try {
        await connectDB();

        const flights = await ActiveFlight.find({
            status: { $in: ['Airborne', 'InFlight'] },
        }).lean();

        const delays: any[] = [];

        for (const f of flights as any[]) {
            const reasons: string[] = [];

            // Detect holding pattern: low ground speed + high altitude + circling (bank angle)
            if (f.ground_speed < 180 && f.altitude > 5000 && Math.abs(f.bank || 0) > 15) {
                reasons.push('Holding Pattern');
            }

            // Detect strong headwinds: IAS much higher than ground speed
            if (f.ias && f.ground_speed && f.ias > 0) {
                const headwind = f.ias - f.ground_speed;
                if (headwind > 50) {
                    reasons.push(`Strong Headwind (~${Math.round(headwind)}kt)`);
                }
            }

            // Detect approach delays: low altitude, low speed, phase is approach for extended time
            if (f.phase === 'Approach' && f.ground_speed < 160 && f.altitude < 3000) {
                reasons.push('Extended Approach');
            }

            if (reasons.length > 0) {
                delays.push({
                    callsign: f.callsign,
                    pilot_name: f.pilot_name,
                    departure_icao: f.departure_icao,
                    arrival_icao: f.arrival_icao,
                    aircraft_type: f.aircraft_type,
                    altitude: Math.round(f.altitude),
                    ground_speed: Math.round(f.ground_speed),
                    ias: Math.round(f.ias || 0),
                    phase: f.phase,
                    reasons,
                });
            }
        }

        return NextResponse.json({ success: true, delays });
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

