            is_active: true,
            $or: [
                { end_time: { $gte: now } },
                { end_datetime: { $gte: now } },
                { end_time: { $exists: false } },
                { end_datetime: { $exists: false } },
            ],
        }).sort({ start_time: 1, start_datetime: 1 });

