import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/database';
import { verifyAuth } from '@/lib/auth';
import ActiveFlight from '@/models/ActiveFlight';

// GET /api/portal/flight-wings — detect pilots flying the same route at the same time
export async function GET(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    try {
        await connectDB();

        const flights = await ActiveFlight.find({
            status: { $in: ['Airborne', 'InFlight', 'Preflight', 'Taxi'] },
        }).lean() as any[];

        // Group by route (dep-arr pair)
        const routeMap = new Map<string, any[]>();
        for (const f of flights) {
            if (!f.departure_icao || !f.arrival_icao) continue;
            const key = `${f.departure_icao}-${f.arrival_icao}`;
            if (!routeMap.has(key)) routeMap.set(key, []);
            routeMap.get(key)!.push({
                callsign: f.callsign,
                pilot_name: f.pilot_name,
                aircraft_type: f.aircraft_type,
                altitude: Math.round(f.altitude || 0),
                ground_speed: Math.round(f.ground_speed || 0),
                phase: f.phase,
                latitude: f.latitude,
                longitude: f.longitude,
            });
        }

        // Only return routes with 2+ pilots (flight wings)
        const wings: any[] = [];
        for (const [route, pilots] of routeMap) {
            if (pilots.length >= 2) {
                const [dep, arr] = route.split('-');
                wings.push({
                    route: `${dep} → ${arr}`,
                    departure_icao: dep,
                    arrival_icao: arr,
                    pilots,
                    count: pilots.length,
                });
            }
        }

        return NextResponse.json({ success: true, wings });
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { verifyAuth } from '@/lib/auth';
import connectDB from '@/lib/database';
import MultiplayerEvent from '@/models/MultiplayerEvent';

// GET - List public multiplayer events for pilots
export async function GET(request: NextRequest) {
    try {
        await connectDB();

        const now = new Date();

        // Auto-transition scheduled events to active if start time has passed
        await MultiplayerEvent.updateMany(
            {
                status: 'scheduled',
                startTime: { $lte: now }
            },
            {
                $set: { status: 'active' }
            }
        );

        const { searchParams } = new URL(request.url);
        const filter = searchParams.get('filter') || 'upcoming';

        let query: any = { isPublic: true };

        switch (filter) {
            case 'upcoming':
                query.status = 'scheduled';
                query.startTime = { $gte: now };
                break;
            case 'active':
                query.status = 'active';
                break;
            case 'completed':
                query.status = 'completed';
                break;
            case 'all':
                // No additional filter
                break;
        }

        const events = await MultiplayerEvent.find(query)
            .sort({ startTime: filter === 'completed' ? -1 : 1 })
            .select('-discordWebhook -createdBy')
            .lean();

        return NextResponse.json({ success: true, events });
    } catch (error: any) {
        console.error('Get public events error:', error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

// POST - Join an event
export async function POST(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    try {
        await connectDB();

        const { eventId } = await request.json();

        if (!eventId) {
            return NextResponse.json({ error: 'Event ID required' }, { status: 400 });
        }

        const event = await MultiplayerEvent.findById(eventId);

        if (!event) {
            return NextResponse.json({ error: 'Event not found' }, { status: 404 });
        }

        // Check if event is full
        if (event.maxParticipants && event.participants.length >= event.maxParticipants) {
            return NextResponse.json({ error: 'Event is full' }, { status: 400 });
        }

        // Check if already joined
        const alreadyJoined = event.participants.some((p: any) => p.pilotId === session.pilotId);
        if (alreadyJoined) {
            return NextResponse.json({ error: 'Already joined this event' }, { status: 400 });
        }

        // Check if event has started
        if (event.status !== 'scheduled') {
            return NextResponse.json({ error: 'Cannot join event that has already started' }, { status: 400 });
        }

        // Add participant
        event.participants.push({
            pilotId: session.pilotId,
            pilotName: (session as any).pilotName || session.pilotId,
            joinedAt: new Date(),
            status: 'registered',
        } as any);

        await event.save();

        return NextResponse.json({ 
            success: true,
            message: 'Successfully joined the event!',
            event 
        });
    } catch (error: any) {
        console.error('Join event error:', error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

// DELETE - Leave an event
export async function DELETE(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    try {
        await connectDB();

        const { searchParams } = new URL(request.url);
        const eventId = searchParams.get('eventId');

        if (!eventId) {
            return NextResponse.json({ error: 'Event ID required' }, { status: 400 });
        }

        const event = await MultiplayerEvent.findById(eventId);

        if (!event) {
            return NextResponse.json({ error: 'Event not found' }, { status: 404 });
        }

        // Check if event has started
        if (event.status !== 'scheduled') {
            return NextResponse.json({ error: 'Cannot leave event that has already started' }, { status: 400 });
        }

        // Remove participant
        event.participants = event.participants.filter((p: any) => p.pilotId !== session.pilotId);
        await event.save();

        return NextResponse.json({ 
            success: true,
            message: 'Successfully left the event' 
        });
    } catch (error: any) {
        console.error('Leave event error:', error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/database';
import { ActiveFlightModel } from '@/models';
import { verifyAuth } from '@/lib/auth';
import Bid from '@/models/Bid';
import Fleet from '@/models/Fleet';

// Merged Live Ops Route
export async function GET(request: NextRequest) {
    const { searchParams } = new URL(request.url);
    const network = searchParams.get('network'); // 'vatsim' | null

    try {
        await connectDB();

        const fiveMinutesAgo = new Date(Date.now() - 5 * 60 * 1000);

        // Clean up stale flights (no heartbeat for 5+ minutes)
        const staleFlights = await ActiveFlightModel.find({ last_update: { $lt: fiveMinutesAgo } });
        if (staleFlights.length > 0) {
            for (const sf of staleFlights) {
                await Bid.updateMany(
                    { pilot_id: sf.pilot_id, status: 'Active' },
                    { $set: { status: 'Cancelled' } }
                );
                if (sf.aircraft_type) {
                    await Fleet.updateMany(
                        { status: 'InFlight', aircraft_type: sf.aircraft_type },
                        { $set: { status: 'Available' } }
                    );
                }
            }
            await ActiveFlightModel.deleteMany({ last_update: { $lt: fiveMinutesAgo } });
        }

        // Cancel expired bids (lazy cleanup)
        await Bid.updateMany(
            { status: 'Active', expires_at: { $lte: new Date() } },
            { $set: { status: 'Cancelled' } }
        );

        // 1. Fetch Internal ACARS Flights
        const internalFlights = await ActiveFlightModel.find({
            last_update: { $gte: fiveMinutesAgo }
        }).sort({ last_update: -1 });

        // Map Internal to Common Format (matches DashboardMap interface)
        const mappedInternal = internalFlights.map(f => ({
            _id: f.id,
            callsign: f.callsign,
            pilot: f.pilot_name,
            pilot_name: f.pilot_name,
            departure: f.departure_icao,
            departure_icao: f.departure_icao,
            arrival: f.arrival_icao,
            arrival_icao: f.arrival_icao,
            equipment: f.aircraft_type,
            aircraft_type: f.aircraft_type,
            latitude: f.latitude,
            longitude: f.longitude,
            altitude: f.altitude,
            heading: f.heading,
            groundSpeed: f.ground_speed,
            ground_speed: f.ground_speed,
            verticalSpeed: f.vertical_speed,
            ias: f.ias,
            fuel: f.fuel,
            phase: f.phase,
            status: f.status,
            comfort_score: f.comfort_score,
            network: 'LEVANT'
        }));

        let finalFlights = [...mappedInternal];

        // 2. Fetch Network Traffic if requested
        if (network && network !== 'off') {
            const baseUrl = request.nextUrl.origin;
            try {
                const endpoint = `${baseUrl}/api/network/vatsim`;

                const netRes = await fetch(endpoint, { cache: 'no-store' });
                const netData = await netRes.json();

                if (netData.pilots) {
                    finalFlights = [...finalFlights, ...netData.pilots];
                }
            } catch (err) {
                console.error(`Failed to fetch ${network} traffic:`, err);
            }
        }

        return NextResponse.json({ 
            success: true, 
            flights: finalFlights,
            stats: {
                total: finalFlights.length,
                levant: mappedInternal.length,
                network: finalFlights.length - mappedInternal.length
            }
        });

    } catch (error) {
        console.error('Error fetching live operations:', error);
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/database';
import Flight from '@/models/Flight';
import { verifyAuth } from '@/lib/auth';

export async function GET(request: NextRequest) {
    try {
        await connectDB();

        // Verify session
        const auth = await verifyAuth();
        if (!auth) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const { searchParams } = new URL(request.url);
        const id = searchParams.get('id');

        if (!id) {
            return NextResponse.json({ error: 'Missing flight ID' }, { status: 400 });
        }

        const report = await Flight.findById(id).lean();

        if (!report) {
            return NextResponse.json({ error: 'Report not found' }, { status: 404 });
        }

        return NextResponse.json({ report });

    } catch (error) {
        console.error('Error fetching report detail:', error);
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

export async function PATCH(request: NextRequest) {
    try {
        await connectDB();
        const auth = await verifyAuth();
        if (!auth) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const body = await request.json();
        const { id, comments, notes } = body;

        if (!id) return NextResponse.json({ error: 'Missing ID' }, { status: 400 });

        const report = await Flight.findById(id);
        if (!report) return NextResponse.json({ error: 'Not found' }, { status: 404 });

        // Security: Only owner or admin
        if (report.pilot_id.toString() !== auth.id && !auth.isAdmin) {
             return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
        }

        // Only allow editing if pending? (Optional rule)
        // if (report.approved_status !== 0) return NextResponse.json({ error: 'Cannot edit processed PIREP' }, { status: 400 });

        if (comments !== undefined) report.comments = comments;

        await report.save();
        return NextResponse.json({ success: true, report });

    } catch (error) {
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

export async function DELETE(request: NextRequest) {
    try {
        await connectDB();
        const auth = await verifyAuth();
        if (!auth) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const { searchParams } = new URL(request.url);
        const id = searchParams.get('id');

        if (!id) return NextResponse.json({ error: 'Missing ID' }, { status: 400 });

        const report = await Flight.findById(id);
        if (!report) return NextResponse.json({ error: 'Not found' }, { status: 404 });

        // Security: Only owner or admin
        if (report.pilot_id.toString() !== auth.id && !auth.isAdmin) {
             return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
        }

        await Flight.findByIdAndDelete(id);
        return NextResponse.json({ success: true });

    } catch (error) {
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { verifyAuth } from '@/lib/auth';
import connectDB from '@/lib/database';
import { FlightModel } from '@/models';
import mongoose from 'mongoose';

export async function GET(request: Request) {
    const session = await verifyAuth();
    if (!session) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    try {
        await connectDB();

        const { searchParams } = new URL(request.url);
        const pilotId = searchParams.get('pilotId');
        const limit = parseInt(searchParams.get('limit') || '10', 10);

        // Query for pilot's flights - pilot_id is stored as ObjectId in database
        const query: any = { 
            pilot_id: new mongoose.Types.ObjectId(session.id),
            approved_status: { $in: [0, 1, 2] }
        };

        const flights = await FlightModel.find(query)
            .select('flight_number callsign departure_icao arrival_icao aircraft_type flight_time landing_rate landing_grade score approved_status submitted_at pilot_name log')
            .sort({ submitted_at: -1 })
            .limit(limit)
            .lean();

        const formattedReports = flights.map((f: any) => {
            // pilot data is stored directly in pilot_name field
            const pilotNameParts = (f.pilot_name || 'Unknown Pilot').split(' ');
            const firstName = pilotNameParts[0] || 'Unknown';
            const lastName = pilotNameParts.slice(1).join(' ') || 'Pilot';

            return {
                ...f,
                pilot: { 
                    first_name: firstName, 
                    last_name: lastName, 
                    pilot_id: f.pilot_id || 'N/A' 
                },
                id: `PIREP-${(f._id?.toString() || '').slice(-6).toUpperCase()}`,
                route: `${f.departure_icao} → ${f.arrival_icao}`,
                aircraft: f.aircraft_type,
                date: new Date(f.submitted_at).toLocaleDateString(),
                status: f.approved_status === 1 ? 'Accepted' : f.approved_status === 2 ? 'Rejected' : 'Pending',
                approved_status: f.approved_status,
                log: f.log
            };
        });

        return NextResponse.json({ flights: formattedReports, reports: formattedReports });

    } catch (error: any) {
        console.error('Recent reports API Error:', error);
        return NextResponse.json({ 
            error: 'Failed to fetch reports',
            details: error.message,
            reports: [] 
        }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/database';
import { verifyAuth } from '@/lib/auth';
import Bid from '@/models/Bid';
import { ActiveFlightModel, PilotModel } from '@/models';
import mongoose from 'mongoose';

export async function POST(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    try {
        await connectDB();
        const pilot = await PilotModel.findById(session.id);

        if (!pilot) {
            return NextResponse.json({ error: 'Pilot not found' }, { status: 404 });
        }

        const simbriefId = pilot.simbrief_id;
        if (!simbriefId) {
            return NextResponse.json({ 
                error: 'SimBrief ID not configured. Please add your SimBrief ID in Settings.' 
            }, { status: 400 });
        }

        const pilotName = [pilot.first_name, pilot.last_name].filter(Boolean).join(' ') || pilot.pilot_id;
        console.log(`[SimBrief-to-Bid] Fetching SimBrief for pilot ${pilot.pilot_id} (${pilotName}), SimBrief ID: ${simbriefId}`);

        // Fetch from SimBrief
        let sbRes;
        try {
            sbRes = await fetch(
                `https://www.simbrief.com/api/xml.fetcher.php?userid=${simbriefId}&json=v2`,
                { cache: 'no-store', headers: { 'User-Agent': 'LevantVA/1.0' } }
            );
        } catch (fetchErr: any) {
            console.error('[SimBrief-to-Bid] Network error fetching SimBrief:', fetchErr.message);
            return NextResponse.json({ 
                error: 'Could not connect to SimBrief. Please try again later.' 
            }, { status: 502 });
        }

        if (!sbRes.ok) {
            console.error(`[SimBrief-to-Bid] SimBrief HTTP error: ${sbRes.status}`);
            return NextResponse.json({ 
                error: `SimBrief returned an error (HTTP ${sbRes.status}). Check your SimBrief ID.` 
            }, { status: 502 });
        }

        let sbData;
        try {
            sbData = await sbRes.json();
        } catch (parseErr) {
            console.error('[SimBrief-to-Bid] Failed to parse SimBrief response');
            return NextResponse.json({ 
                error: 'Invalid response from SimBrief. Please try again.' 
            }, { status: 502 });
        }

        if (sbData?.fetch?.status !== 'Success') {
            return NextResponse.json({ 
                error: 'No flight plan found on SimBrief. Create one at simbrief.com first.' 
            }, { status: 404 });
        }

        // Validate critical SimBrief fields
        const depIcao = sbData.origin?.icao_code;
        const arrIcao = sbData.destination?.icao_code;
        const callsign = sbData.atc?.callsign || pilot.pilot_id;
        const aircraftType = sbData.aircraft?.icaocode;

        if (!depIcao || !arrIcao) {
            return NextResponse.json({ 
                error: 'SimBrief flight plan is missing departure or arrival airport.' 
            }, { status: 400 });
        }

        if (!aircraftType) {
            return NextResponse.json({ 
                error: 'SimBrief flight plan is missing aircraft type.' 
            }, { status: 400 });
        }

        // Delete any existing active/in-progress bids for this pilot
        await Bid.deleteMany({ pilot_id: pilot._id, status: { $in: ['Active', 'InProgress'] } });
        console.log(`[SimBrief-to-Bid] Cleared existing bids for pilot ${pilot.pilot_id}`);

        // Create bid from SimBrief data
        const bid = await Bid.create({
            pilot_id: pilot._id,
            pilot_name: pilotName,
            callsign,
            departure_icao: depIcao,
            arrival_icao: arrIcao,
            aircraft_type: aircraftType,
            aircraft_registration: sbData.aircraft?.reg || '',
            route: sbData.general?.route || '',
            pax: parseInt(sbData.weights?.pax_count || '0') || 0,
            cargo: parseInt(sbData.weights?.cargo || '0') || 0,
            simbrief_ofp_id: sbData.params?.ofp_id || '',
            planned_fuel: parseInt(sbData.fuel?.plan_ramp || '0') || 0,
            status: 'Active',
            created_at: new Date(),
            expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000)
        });

        console.log(`[SimBrief-to-Bid] ========== BID CREATED ==========`);
        console.log(`[SimBrief-to-Bid] Bid ID: ${bid._id}`);
        console.log(`[SimBrief-to-Bid] Pilot ID (string): ${pilot.pilot_id}`);
        console.log(`[SimBrief-to-Bid] Pilot _id (ObjectId): ${pilot._id}`);
        console.log(`[SimBrief-to-Bid] Bid pilot_id field: ${bid.pilot_id}`);
        console.log(`[SimBrief-to-Bid] Bid pilot_id type: ${typeof bid.pilot_id}`);
        console.log(`[SimBrief-to-Bid] Route: ${depIcao} → ${arrIcao}`);
        console.log(`[SimBrief-to-Bid] Aircraft: ${aircraftType}`);
        console.log(`[SimBrief-to-Bid] Status: ${bid.status}`);
        console.log(`[SimBrief-to-Bid] =====================================`);

        return NextResponse.json({ 
            success: true,
            bid: {
                id: bid._id,
                flightNumber: callsign,
                callsign: bid.callsign,
                departureIcao: bid.departure_icao,
                arrivalIcao: bid.arrival_icao,
                aircraftType: bid.aircraft_type,
                route: bid.route || '',
            }
        });
    } catch (error: any) {
        console.error('[SimBrief-to-Bid] Unexpected error:', error.message, error.stack);
        return NextResponse.json({ 
            error: 'Failed to create bid from SimBrief: ' + (error.message || 'Unknown error')
        }, { status: 500 });
    }
}

// GET: Fetch current active bid for the authenticated pilot
export async function GET(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    try {
        await connectDB();
        const bid = await Bid.findOne({
            pilot_id: new mongoose.Types.ObjectId(session.id),
            status: { $in: ['Active', 'InProgress'] } 
        }).sort({ created_at: -1 }).lean();

        if (!bid) return NextResponse.json({ bid: null });

        // Check if there's an active flight for this bid
        const activeFlight = await ActiveFlightModel.findOne({
            pilot_id: new mongoose.Types.ObjectId(session.id)
        }).lean();

        return NextResponse.json({
            bid: {
                id: bid._id,
                flightNumber: bid.callsign,
                callsign: bid.callsign,
                departureIcao: bid.departure_icao,
                arrivalIcao: bid.arrival_icao,
                aircraftType: bid.aircraft_type,
                route: bid.route || '',
                status: bid.status,
            },
            hasActiveFlight: !!activeFlight,
        });
    } catch (error: any) {
        console.error('[SimBrief-to-Bid GET] Error:', error.message);
        return NextResponse.json({ error: 'Failed to fetch bid' }, { status: 500 });
    }
}

// DELETE: Cancel active bid and active flight
export async function DELETE(request: NextRequest) {
    const session = await verifyAuth();
    if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    try {
        await connectDB();

        // Cancel all active/in-progress bids for this pilot
        const bidResult = await Bid.updateMany(
            { pilot_id: session.id, status: { $in: ['Active', 'InProgress'] } },
            { $set: { status: 'Cancelled' } }
        );

        // Remove any active flight tracking
        const flightResult = await ActiveFlightModel.deleteMany({ pilot_id: session.id });

        console.log(`[Cancel Flight] Pilot ${session.pilotId}: cancelled ${bidResult.modifiedCount} bid(s), removed ${flightResult.deletedCount} active flight(s)`);

        return NextResponse.json({ 
            success: true,
            message: 'Flight cancelled successfully',
            cancelledBids: bidResult.modifiedCount,
            removedFlights: flightResult.deletedCount,
        });
    } catch (error: any) {
        console.error('[Cancel Flight] Error:', error.message);
        return NextResponse.json({ error: 'Failed to cancel flight' }, { status: 500 });
    }
}

