/**
 * VA Settings API Endpoints
 * GET, PATCH for global configuration management
 */

import { NextRequest, NextResponse } from 'next/server';
import { verifyAuth } from '@/lib/auth';
import connectDB from '@/lib/database';
import VASettingsModel from '@/models/VASettings';
import type { VASettings } from '@/types/settings';

// ============================================================================
// GET - Fetch current settings
// ============================================================================

export async function GET(request: NextRequest) {
    try {
        await connectDB();

        const settings = await VASettingsModel.findOne().lean();

        if (!settings) {
            // Create default settings if none exist
            const defaultSettings = await VASettingsModel.create({
                updated_by: 'system',
            });

            return NextResponse.json({
                success: true,
                settings: {
                    id: defaultSettings._id.toString(),
                    ...defaultSettings.toObject(),
                },
            });
        }

        return NextResponse.json({
            success: true,
            settings: {
                id: settings._id.toString(),
                ...settings,
            },
        });
    } catch (error: any) {
        console.error('Failed to fetch VA settings:', error);
        return NextResponse.json(
            { success: false, error: error.message },
            { status: 500 }
        );
    }
}

// ============================================================================
// PATCH - Update settings (Admin only)
// ============================================================================

export async function PATCH(request: NextRequest) {
    const session = await verifyAuth();

    if (!session?.isAdmin) {
        return NextResponse.json(
            { success: false, error: 'Unauthorized' },
            { status: 403 }
        );
    }

    try {
        await connectDB();

        const updates = await request.json();

        // Get current settings
        let settings = await VASettingsModel.findOne();

        if (!settings) {
            // Create with updates
            settings = await VASettingsModel.create({
                ...updates,
                updated_by: session.pilotId || session.id,
            });
        } else {
            // Update existing
            Object.assign(settings, updates);
            settings.updated_by = session.pilotId || session.id;
            await settings.save();
        }

        // Broadcast update to all connected clients
        // In production, use WebSocket or Supabase Realtime
        const settingsData = {
            id: settings._id.toString(),
            ...settings.toObject(),
        };

        return NextResponse.json({
            success: true,
            settings: settingsData,
            message: 'Settings updated successfully',
        });
    } catch (error: any) {
        console.error('Failed to update VA settings:', error);
        return NextResponse.json(
            { success: false, error: error.message },
            { status: 500 }
        );
    }
}

// ============================================================================
// POST - Reset to defaults (Admin only)
// ============================================================================

export async function POST(request: NextRequest) {
    const session = await verifyAuth();

    if (!session?.isAdmin) {
        return NextResponse.json(
            { success: false, error: 'Unauthorized' },
            { status: 403 }
        );
    }

    try {
        await connectDB();

        // Delete existing settings
        await VASettingsModel.deleteMany({});

        // Create fresh default settings
        const settings = await VASettingsModel.create({
            updated_by: session.pilotId || session.id,
        });

        return NextResponse.json({
            success: true,
            settings: {
                id: settings._id.toString(),
                ...settings.toObject(),
            },
            message: 'Settings reset to defaults',
        });
    } catch (error: any) {
        console.error('Failed to reset VA settings:', error);
        return NextResponse.json(
            { success: false, error: error.message },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { DownloadLog } from '@/models/DownloadLog';
import connectDB from '@/lib/database';

export async function POST(req: NextRequest) {
    try {
        await connectDB();
        const { version, platform } = await req.json();

        const ip = req.headers.get('x-forwarded-for') || 'unknown';
        const ua = req.headers.get('user-agent') || 'unknown';

        await DownloadLog.create({
            file_name: `Levant-ACARS-v${version || 'unknown'}.msi`,
            ip_address: ip,
            user_agent: ua,
        });

        return NextResponse.json({ success: true });
    } catch (error) {
        console.error('Download tracking error:', error);
        return NextResponse.json({ success: false }, { status: 500 });
    }
}

'use client';

import { useState } from 'react';
import Link from 'next/link';

export default function ForgotPasswordPage() {
    const [email, setEmail] = useState('');
    const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [message, setMessage] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setStatus('loading');
        setMessage('');

        try {
            const res = await fetch('/api/auth/forgot-password', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email }),
            });

            const data = await res.json();

            if (res.ok) {
                setStatus('success');
                setMessage(data.message);
            } else {
                setStatus('error');
                setMessage(data.error || 'Something went wrong');
            }
        } catch (err) {
            setStatus('error');
            setMessage('Network error');
        }
    };

    return (
        <div className="min-h-screen py-6 px-4 flex flex-col justify-center items-center">
            <div className="fixed inset-0 bg-gradient-to-br from-dark-900 via-primary-900/10 to-dark-900 -z-10" />

            <div className="w-full max-w-md glass-card p-8">
                <div className="text-center mb-8">
                    <h1 className="text-2xl font-bold text-white mb-2">Reset Password</h1>
                    <p className="text-gray-400 text-sm">Enter your email to receive a reset link</p>
                </div>

                {status === 'success' ? (
                    <div className="text-center">
                        <div className="bg-green-500/20 text-green-400 p-4 rounded-lg mb-6">
                            {message}
                        </div>
                        <p className="text-gray-400 text-sm">
                            Check your email inbox (and spam folder).
                        </p>
                        <Link href="/login" className="btn-primary w-full mt-6 block text-center">
                            Back to Login
                        </Link>
                    </div>
                ) : (
                    <form onSubmit={handleSubmit} className="space-y-6">
                        {status === 'error' && (
                            <div className="bg-red-500/20 text-red-400 p-3 rounded-lg text-sm">
                                {message}
                            </div>
                        )}
                        <div>
                            <label className="block text-gray-400 text-sm mb-2">Email Address</label>
                            <input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                className="w-full bg-dark-700 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-accent-gold transition-colors"
                            />
                        </div>
                        <button
                            type="submit"
                            disabled={status === 'loading'}
                            className="w-full btn-primary py-3 disabled:opacity-50"
                        >
                            {status === 'loading' ? 'Sending...' : 'Send Reset Link'}
                        </button>
                        <div className="text-center mt-4">
                            <Link href="/login" className="text-gray-400 hover:text-white text-sm transition-colors">
                                Back to Login
                            </Link>
                        </div>
                    </form>
                )}
            </div>
        </div>
    );
}

