                                </tr>
                            ) : logs.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="py-20 text-center">
                                        <History className="w-12 h-12 text-gray-700 mx-auto mb-4" />
                                        <p className="text-sm font-medium text-gray-500">No transactions found.</p>
