                                />
                            </div>
                        </div>

                        <div className="p-6 bg-gradient-to-r from-[#0c0c0c] to-[#0a0a0a] border-t border-white/[0.08] flex justify-end gap-3">
                            <button 
                                onClick={closeModal}
                                className="px-5 py-2.5 text-sm font-bold text-gray-400 hover:text-white bg-gradient-to-br from-[#0a0a0a] to-[#0d0d0d] border border-white/[0.08] rounded-xl transition-all hover:border-white/[0.15]"
                            >
                                Cancel
                            </button>
                            <button 
                                onClick={handleAction}
                                disabled={submitting}
                                className={`px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-lg ${
                                    activeModal === 'deposit' ? 'bg-gradient-to-r from-emerald-500 to-emerald-600 hover:from-emerald-600 hover:to-emerald-700 text-white shadow-emerald-500/20 hover:shadow-emerald-500/40' :
                                    activeModal === 'withdraw' ? 'bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 text-white shadow-red-500/20 hover:shadow-red-500/40' :
                                    activeModal?.startsWith('purchase') ? 'bg-gradient-to-r from-amber-500 to-amber-600 hover:from-amber-600 hover:to-amber-700 text-white shadow-amber-500/20 hover:shadow-amber-500/40' :
                                    'bg-gradient-to-r from-purple-500 to-purple-600 hover:from-purple-600 hover:to-purple-700 text-white shadow-purple-500/20 hover:shadow-purple-500/40'
                                } disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                {submitting && <Loader2 className="w-4 h-4 animate-spin" />}
                                Confirm {
                                    activeModal === 'deposit' ? 'Deposit' : 
                                    activeModal === 'withdraw' ? 'Withdrawal' : 
                                    activeModal?.startsWith('purchase') ? 'Purchase' :
                                    'Bonus'
                                }
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Calendar, Users, Trophy, Plus, Edit, Trash2, Plane, MapPin, Clock, Target, Loader2, CheckCircle, XCircle } from 'lucide-react';

interface MultiplayerEvent {
    _id: string;
    title: string;
    description: string;
    eventType: 'group_flight' | 'formation' | 'race';
    status: 'scheduled' | 'active' | 'completed' | 'cancelled';
    startTime: string;
    departureIcao: string;
    departureAirport?: string;
    arrivalIcao: string;
    arrivalAirport?: string;
    route?: string;
    aircraft?: string;
    estimatedFlightTime?: string;
    localTime?: boolean;
    reminderMinutes?: number;
    participants: any[];
    scoringEnabled: boolean;
    isPublic: boolean;
}

export default function AdminMultiplayerEventsPage() {
    const [events, setEvents] = useState<MultiplayerEvent[]>([]);
    const [loading, setLoading] = useState(true);
    const [showCreate, setShowCreate] = useState(false);
    const [editingEvent, setEditingEvent] = useState<MultiplayerEvent | null>(null);
    const [statusFilter, setStatusFilter] = useState<'all' | 'scheduled' | 'active' | 'completed'>('all');

    // Form state
    const [formData, setFormData] = useState({
        eventType: 'group_flight',
        startTime: '',
        departureIcao: '',
        departureAirport: '',
        arrivalIcao: '',
        arrivalAirport: '',
        route: '',
        aircraft: '',
        estimatedFlightTime: '',
        localTime: true,
        reminderMinutes: '15',
        scoringEnabled: false,
        isPublic: true,
    });

    const [fetchingAirport, setFetchingAirport] = useState<'departure' | 'arrival' | null>(null);
    const [showAnnouncement, setShowAnnouncement] = useState(false);

    useEffect(() => {
        fetchEvents();
    }, [statusFilter]);

    const fetchEvents = async () => {
        try {
            const url = statusFilter === 'all' 
                ? '/api/admin/multiplayer-events'
                : `/api/admin/multiplayer-events?status=${statusFilter}`;
            const res = await fetch(url);
            const data = await res.json();
            if (data.success) setEvents(data.events);
        } catch (error) {
            console.error('Fetch events error:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        try {
            // Auto-generate title from route
            const title = `${formData.departureIcao} → ${formData.arrivalIcao} Group Flight`;
            const description = `Group flight from ${formData.departureAirport || formData.departureIcao} to ${formData.arrivalAirport || formData.arrivalIcao}`;

            // Convert datetime-local format (YYYY-MM-DDTHH:mm) to ISO string with Z timezone
            // This treats the input as literal UTC time without any conversion
            const utcTime = formData.startTime.includes('T') 
                ? formData.startTime + ':00.000Z' 
                : formData.startTime;

            const payload = {
                ...formData,
                title,
                description,
                startTime: utcTime,
                reminderMinutes: formData.reminderMinutes ? parseInt(formData.reminderMinutes) : 15,
            };

            const res = await fetch('/api/admin/multiplayer-events', {
                method: editingEvent ? 'PUT' : 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(editingEvent ? { eventId: editingEvent._id, ...payload } : payload),
            });

            const data = await res.json();
            if (data.success) {
                fetchEvents();
                resetForm();
            }
        } catch (error) {
            console.error('Submit error:', error);
        }
    };

    const handleDelete = async (eventId: string) => {
        if (!confirm('Delete this event?')) return;

        try {
            const res = await fetch(`/api/admin/multiplayer-events?eventId=${eventId}`, {
                method: 'DELETE',
            });
            const data = await res.json();
            if (data.success) fetchEvents();
        } catch (error) {
            console.error('Delete error:', error);
        }
    };

    const handleStatusChange = async (eventId: string, newStatus: 'active' | 'completed' | 'cancelled') => {
        const confirmMessages = {
            active: 'Start this group flight? It will move to the Active tab.',
            completed: 'Mark this group flight as completed? It will move to the Completed tab.',
            cancelled: 'Cancel this group flight?'
        };

        if (!confirm(confirmMessages[newStatus])) return;

        try {
            const res = await fetch('/api/admin/multiplayer-events/status', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ eventId, status: newStatus }),
            });
            const data = await res.json();
            if (data.success) {
                fetchEvents();
            } else {
                alert(data.error || 'Failed to update status');
            }
        } catch (error) {
            console.error('Status update error:', error);
            alert('Failed to update status');
        }
    };

    const fetchAirportName = async (icao: string, type: 'departure' | 'arrival') => {
        if (icao.length !== 4) return;

        setFetchingAirport(type);
        try {
            const res = await fetch(`https://airportdb.io/api/v1/airport/${icao}?apiToken=9cade662e6ead0aeb8104ee946ffc365e061a7f3e30db6f0c45322944bdbea25111c511f3894d6c7e4b76b370da8a105`);
            const data = await res.json();
            if (data && data.name) {
                const airportName = data.name;
                if (type === 'departure') {
                    setFormData(prev => ({ ...prev, departureAirport: airportName }));
                } else {
                    setFormData(prev => ({ ...prev, arrivalAirport: airportName }));
                }
            }
        } catch (error) {
            console.error('Fetch airport error:', error);
        } finally {
            setFetchingAirport(null);
        }
    };

    const resetForm = () => {
        setFormData({
            eventType: 'group_flight',
            startTime: '',
            departureIcao: '',
            departureAirport: '',
            arrivalIcao: '',
            arrivalAirport: '',
            route: '',
            aircraft: '',
            estimatedFlightTime: '',
            localTime: true,
            reminderMinutes: '15',
            scoringEnabled: false,
            isPublic: true,
        });
        setShowCreate(false);
        setEditingEvent(null);
    };

    const startEdit = (event: MultiplayerEvent) => {
        setFormData({
            eventType: event.eventType,
            startTime: new Date(event.startTime).toISOString().slice(0, 16),
            departureIcao: event.departureIcao,
            departureAirport: event.departureAirport || '',
            arrivalIcao: event.arrivalIcao,
            arrivalAirport: event.arrivalAirport || '',
            route: event.route || '',
            aircraft: event.aircraft || '',
            estimatedFlightTime: event.estimatedFlightTime || '',
            localTime: event.localTime ?? true,
            reminderMinutes: event.reminderMinutes?.toString() || '15',
            scoringEnabled: event.scoringEnabled,
            isPublic: event.isPublic,
        });
        setEditingEvent(event);
        setShowCreate(true);
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-96">
                <Loader2 className="w-8 h-8 animate-spin text-accent-gold" />
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-white">Group Flights</h1>
                    <p className="text-sm text-gray-400 mt-1">Create and manage coordinated VA group flights</p>
                </div>
                <button
                    onClick={() => setShowCreate(!showCreate)}
                    className="flex items-center gap-2 px-4 py-2 bg-accent-gold text-black rounded-lg hover:bg-accent-gold/90 transition-colors font-medium"
                >
                    <Plus size={18} />
                    Create Group Flight
                </button>
            </div>

            {/* Status Filter Tabs */}
            <div className="flex gap-2 border-b border-white/10">
                {(['all', 'scheduled', 'active', 'completed'] as const).map((status) => (
                    <button
                        key={status}
                        onClick={() => setStatusFilter(status)}
                        className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 ${
                            statusFilter === status
                                ? 'border-accent-gold text-accent-gold'
                                : 'border-transparent text-gray-400 hover:text-white'
                        }`}
                    >
                        {status.charAt(0).toUpperCase() + status.slice(1)}
                    </button>
                ))}
            </div>

            {/* Create/Edit Form */}
            {showCreate && (
                <form onSubmit={handleSubmit} className="bg-[#111] border border-white/10 rounded-xl p-6 space-y-4">
                    <h2 className="text-xl font-bold text-white mb-4">{editingEvent ? 'Edit Group Flight' : 'Create Group Flight'}</h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Start Time (UTC/Zulu)</label>
                            <input
                                type="datetime-local"
                                value={formData.startTime}
                                onChange={(e) => setFormData({ ...formData, startTime: e.target.value })}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white"
                                required
                            />
                            <p className="text-xs text-gray-500 mt-1">Enter time in UTC/Zulu timezone</p>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Departure ICAO</label>
                            <input
                                type="text"
                                value={formData.departureIcao}
                                onChange={(e) => {
                                    const icao = e.target.value.toUpperCase();
                                    setFormData({ ...formData, departureIcao: icao });
                                    if (icao.length === 4) fetchAirportName(icao, 'departure');
                                }}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white uppercase"
                                maxLength={4}
                                required
                            />
                            {formData.departureAirport && (
                                <p className="text-xs text-accent-gold mt-1">{formData.departureAirport}</p>
                            )}
                            {fetchingAirport === 'departure' && (
                                <p className="text-xs text-gray-500 mt-1">Fetching airport...</p>
                            )}
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Arrival ICAO</label>
                            <input
                                type="text"
                                value={formData.arrivalIcao}
                                onChange={(e) => {
                                    const icao = e.target.value.toUpperCase();
                                    setFormData({ ...formData, arrivalIcao: icao });
                                    if (icao.length === 4) fetchAirportName(icao, 'arrival');
                                }}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white uppercase"
                                maxLength={4}
                                required
                            />
                            {formData.arrivalAirport && (
                                <p className="text-xs text-accent-gold mt-1">{formData.arrivalAirport}</p>
                            )}
                            {fetchingAirport === 'arrival' && (
                                <p className="text-xs text-gray-500 mt-1">Fetching airport...</p>
                            )}
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Route (Optional)</label>
                            <input
                                type="text"
                                value={formData.route}
                                onChange={(e) => setFormData({ ...formData, route: e.target.value })}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Aircraft (Optional)</label>
                            <input
                                type="text"
                                value={formData.aircraft}
                                onChange={(e) => setFormData({ ...formData, aircraft: e.target.value })}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white"
                                placeholder="e.g., A320, B737"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Estimated Flight Time</label>
                            <input
                                type="text"
                                value={formData.estimatedFlightTime}
                                onChange={(e) => setFormData({ ...formData, estimatedFlightTime: e.target.value })}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white"
                                placeholder="e.g., 3:00 H"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-400 mb-2">Reminder (Minutes Before)</label>
                            <input
                                type="number"
                                value={formData.reminderMinutes}
                                onChange={(e) => setFormData({ ...formData, reminderMinutes: e.target.value })}
                                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-2 text-white"
                                placeholder="15"
                            />
                        </div>

                        <div className="col-span-2 flex gap-4">
                            <label className="flex items-center gap-2 text-sm text-gray-400">
                                <input
                                    type="checkbox"
                                    checked={formData.localTime}
                                    onChange={(e) => setFormData({ ...formData, localTime: e.target.checked })}
                                    className="rounded"
                                />
                                Show Local Time
                            </label>
                            <label className="flex items-center gap-2 text-sm text-gray-400">
                                <input
                                    type="checkbox"
                                    checked={formData.scoringEnabled}
                                    onChange={(e) => setFormData({ ...formData, scoringEnabled: e.target.checked })}
                                    className="rounded"
                                />
                                Enable Scoring/Leaderboard
                            </label>
                            <label className="flex items-center gap-2 text-sm text-gray-400">
                                <input
                                    type="checkbox"
                                    checked={formData.isPublic}
                                    onChange={(e) => setFormData({ ...formData, isPublic: e.target.checked })}
                                    className="rounded"
                                />
                                Public Event
                            </label>
                        </div>
                    </div>

                    <div className="flex gap-2 justify-end">
                        <button
                            type="button"
                            onClick={resetForm}
                            className="px-4 py-2 bg-white/10 text-white rounded-lg hover:bg-white/20 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            className="px-4 py-2 bg-accent-gold text-black rounded-lg hover:bg-accent-gold/90 transition-colors font-medium"
                        >
                            {editingEvent ? 'Update Group Flight' : 'Create Group Flight'}
                        </button>
                    </div>
                </form>
            )}

            {/* Events List */}
            <div className="grid gap-4">
                {events.map((event) => (
                    <div key={event._id} className="bg-[#111] border border-white/10 rounded-xl p-6">
                        <div className="flex items-start justify-between">
                            <div className="flex-1">
                                <div className="flex items-center gap-3 mb-2">
                                    <h3 className="text-lg font-bold text-white">{event.title}</h3>
                                    <span className={`px-2 py-1 rounded text-xs font-bold ${
                                        event.status === 'scheduled' ? 'bg-blue-500/20 text-blue-400' :
                                        event.status === 'active' ? 'bg-green-500/20 text-green-400' :
                                        event.status === 'completed' ? 'bg-gray-500/20 text-gray-400' :
                                        'bg-red-500/20 text-red-400'
                                    }`}>
                                        {event.status.toUpperCase()}
                                    </span>
                                    <span className="px-2 py-1 rounded text-xs font-bold bg-purple-500/20 text-purple-400">
                                        {event.eventType.replace('_', ' ').toUpperCase()}
                                    </span>
                                </div>
                                <p className="text-sm text-gray-400 mb-4">{event.description}</p>

                                <div className="grid grid-cols-4 gap-4 text-sm">
                                    <div className="flex items-center gap-2 text-gray-400">
                                        <MapPin size={14} />
                                        <span>{event.departureIcao} → {event.arrivalIcao}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-400">
                                        <Clock size={14} />
                                        <span>{new Date(event.startTime).toLocaleDateString()}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-gray-400">
                                        <Users size={14} />
                                        <span>{event.participants.length} Pilots</span>
                                    </div>
                                    {event.scoringEnabled && (
                                        <div className="flex items-center gap-2 text-accent-gold">
                                            <Trophy size={14} />
                                            <span>Competitive</span>
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="flex gap-2">
                                {event.status === 'scheduled' && (
                                    <button
                                        onClick={() => handleStatusChange(event._id, 'active')}
                                        className="px-3 py-2 bg-green-500/20 text-green-400 rounded-lg hover:bg-green-500/30 transition-colors text-xs font-bold flex items-center gap-1"
                                        title="Start this group flight"
                                    >
                                        <CheckCircle size={14} />
                                        Start
                                    </button>
                                )}
                                {event.status === 'active' && (
                                    <button
                                        onClick={() => handleStatusChange(event._id, 'completed')}
                                        className="px-3 py-2 bg-blue-500/20 text-blue-400 rounded-lg hover:bg-blue-500/30 transition-colors text-xs font-bold flex items-center gap-1"
                                        title="Mark as completed"
                                    >
                                        <CheckCircle size={14} />
                                        Complete
                                    </button>
                                )}
                                <button
                                    onClick={() => startEdit(event)}
                                    className="p-2 bg-white/10 text-white rounded-lg hover:bg-white/20 transition-colors"
                                >
                                    <Edit size={16} />
                                </button>
                                {event.status === 'scheduled' && (
                                    <button
                                        onClick={() => handleStatusChange(event._id, 'cancelled')}
                                        className="p-2 bg-orange-500/20 text-orange-400 rounded-lg hover:bg-orange-500/30 transition-colors"
                                        title="Cancel event"
                                    >
                                        <XCircle size={16} />
                                    </button>
                                )}
                                <button
                                    onClick={() => handleDelete(event._id)}
                                    className="p-2 bg-red-500/20 text-red-400 rounded-lg hover:bg-red-500/30 transition-colors"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>
                    </div>
                ))}

                {events.length === 0 && (
                    <div className="text-center py-12 text-gray-500">
                        No events created yet. Click "Create Event" to get started!
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Plus, Edit, Trash2, Bell, Calendar, Megaphone, AlertTriangle, X } from 'lucide-react';

interface Notam {
    _id: string;
    title: string;
    content: string;
    type: 'news' | 'notam' | 'event';
    priority: 'normal' | 'important' | 'urgent';
    author_name: string;
    event_date?: string;
    event_location?: string;
    bonus_credits?: number;
    active: boolean;
    created_at: string;
}

export default function AdminNotamsPage() {
    const [notams, setNotams] = useState<Notam[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editing, setEditing] = useState<Notam | null>(null);
    const [saving, setSaving] = useState(false);

    // Form state
    const [title, setTitle] = useState('');
    const [content, setContent] = useState('');
    const [type, setType] = useState<'news' | 'notam' | 'event'>('news');
    const [priority, setPriority] = useState<'normal' | 'important' | 'urgent'>('normal');
    const [eventDate, setEventDate] = useState('');
    const [eventLocation, setEventLocation] = useState('');
    const [bonusCredits, setBonusCredits] = useState('');

    const fetchNotams = () => {
        setLoading(true);
        fetch('/api/admin/notams')
            .then(res => res.json())
            .then(data => setNotams(data.notams || []))
            .catch(console.error)
            .finally(() => setLoading(false));
    };

    useEffect(() => { fetchNotams(); }, []);

    const resetForm = () => {
        setTitle('');
        setContent('');
        setType('news');
        setPriority('normal');
        setEventDate('');
        setEventLocation('');
        setBonusCredits('');
        setEditing(null);
    };

    const openNew = () => {
        resetForm();
        setShowModal(true);
    };

    const openEdit = (notam: Notam) => {
        setEditing(notam);
        setTitle(notam.title);
        setContent(notam.content);
        setType(notam.type);
        setPriority(notam.priority);
        setEventDate(notam.event_date ? new Date(notam.event_date).toISOString().slice(0, 16) : '');
        setEventLocation(notam.event_location || '');
        setBonusCredits(notam.bonus_credits?.toString() || '');
        setShowModal(true);
    };

    const handleSave = async () => {
        if (!title.trim() || !content.trim()) {
            alert('Title and content are required');
            return;
        }

        setSaving(true);
        try {
            const body = {
                ...(editing && { id: editing._id }),
                title,
                content,
                type,
                priority,
                eventDate: eventDate || undefined,
                eventLocation: eventLocation || undefined,
                bonusCredits: bonusCredits ? parseInt(bonusCredits) : undefined,
            };

            const res = await fetch('/api/admin/notams', {
                method: editing ? 'PUT' : 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            });

            if (res.ok) {
                setShowModal(false);
                resetForm();
                fetchNotams();
            }
        } catch (error) {
            console.error('Save error:', error);
        } finally {
            setSaving(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Are you sure you want to delete this?')) return;

        await fetch(`/api/admin/notams?id=${id}`, { method: 'DELETE' });
        fetchNotams();
    };

    const toggleActive = async (notam: Notam) => {
        await fetch('/api/admin/notams', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ id: notam._id, active: !notam.active }),
        });
        fetchNotams();
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <Bell className="w-8 h-8 text-accent-gold" />
                    <h1 className="text-2xl font-bold text-white">Manage News & NOTAMs</h1>
                </div>
                <button 
                    onClick={openNew}
                    className="btn-primary flex items-center gap-2"
                >
                    <Plus className="w-5 h-5" />
                    New Post
                </button>
            </div>

            {loading ? (
                <div className="glass-card p-12 text-center text-gray-400">Loading...</div>
            ) : notams.length === 0 ? (
                <div className="glass-card p-12 text-center text-gray-400">
                    <Megaphone className="w-12 h-12 mx-auto mb-4 opacity-30" />
                    <p>No announcements yet</p>
                </div>
            ) : (
                <div className="glass-card overflow-hidden">
                    <table className="w-full">
                        <thead className="bg-[#111]">
                            <tr>
                                <th className="text-left p-4 text-gray-400 font-medium">Title</th>
                                <th className="text-left p-4 text-gray-400 font-medium">Type</th>
                                <th className="text-left p-4 text-gray-400 font-medium">Priority</th>
                                <th className="text-left p-4 text-gray-400 font-medium">Status</th>
                                <th className="text-left p-4 text-gray-400 font-medium">Date</th>
                                <th className="text-right p-4 text-gray-400 font-medium">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {notams.map((notam) => (
                                <tr key={notam._id} className="border-t border-white/[0.06] hover:bg-white/5">
                                    <td className="p-4 text-white">{notam.title}</td>
                                    <td className="p-4">
                                        <span className={`text-xs px-2 py-1 rounded uppercase ${
                                            notam.type === 'event' ? 'bg-purple-500/30 text-purple-300' :
                                            notam.type === 'notam' ? 'bg-yellow-500/30 text-yellow-300' :
                                            'bg-blue-500/30 text-blue-300'
                                        }`}>
                                            {notam.type}
                                        </span>
                                    </td>
                                    <td className="p-4">
                                        <span className={`text-xs px-2 py-1 rounded uppercase ${
                                            notam.priority === 'urgent' ? 'bg-red-500/30 text-red-300' :
                                            notam.priority === 'important' ? 'bg-yellow-500/30 text-yellow-300' :
                                            'bg-gray-500/30 text-gray-300'
                                        }`}>
                                            {notam.priority}
                                        </span>
                                    </td>
                                    <td className="p-4">
                                        <button 
                                            onClick={() => toggleActive(notam)}
                                            className={`text-xs px-2 py-1 rounded ${
                                                notam.active 
                                                    ? 'bg-green-500/30 text-green-300' 
                                                    : 'bg-gray-500/30 text-gray-400'
                                            }`}
                                        >
                                            {notam.active ? 'Active' : 'Hidden'}
                                        </button>
                                    </td>
                                    <td className="p-4 text-gray-400">
                                        {new Date(notam.created_at).toLocaleDateString()}
                                    </td>
                                    <td className="p-4 text-right">
                                        <button 
                                            onClick={() => openEdit(notam)}
                                            className="text-blue-400 hover:text-blue-300 p-2"
                                        >
                                            <Edit className="w-4 h-4" />
                                        </button>
                                        <button 
                                            onClick={() => handleDelete(notam._id)}
                                            className="text-red-400 hover:text-red-300 p-2"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
                    <div className="bg-[#0a0a0a] rounded-xl w-full max-w-xl max-h-[90vh] overflow-y-auto">
                        <div className="flex items-center justify-between p-6 border-b border-white/10">
                            <h2 className="text-xl font-bold text-white">
                                {editing ? 'Edit Post' : 'New Post'}
                            </h2>
                            <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-white">
                                <X className="w-6 h-6" />
                            </button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm text-gray-400 mb-2">Title</label>
                                <input
                                    type="text"
                                    value={title}
                                    onChange={e => setTitle(e.target.value)}
                                    className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                />
                            </div>
                            <div>
                                <label className="block text-sm text-gray-400 mb-2">Content</label>
                                <textarea
                                    value={content}
                                    onChange={e => setContent(e.target.value)}
                                    rows={5}
                                    className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm text-gray-400 mb-2">Type</label>
                                    <select
                                        value={type}
                                        onChange={e => setType(e.target.value as any)}
                                        className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                    >
                                        <option value="news">News</option>
                                        <option value="notam">NOTAM</option>
                                        <option value="event">Event</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-sm text-gray-400 mb-2">Priority</label>
                                    <select
                                        value={priority}
                                        onChange={e => setPriority(e.target.value as any)}
                                        className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                    >
                                        <option value="normal">Normal</option>
                                        <option value="important">Important</option>
                                        <option value="urgent">Urgent</option>
                                    </select>
                                </div>
                            </div>
                            {type === 'event' && (
                                <>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-sm text-gray-400 mb-2">Event Date</label>
                                            <input
                                                type="datetime-local"
                                                value={eventDate}
                                                onChange={e => setEventDate(e.target.value)}
                                                className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-sm text-gray-400 mb-2">Bonus Credits</label>
                                            <input
                                                type="number"
                                                value={bonusCredits}
                                                onChange={e => setBonusCredits(e.target.value)}
                                                className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-sm text-gray-400 mb-2">Event Location</label>
                                        <input
                                            type="text"
                                            value={eventLocation}
                                            onChange={e => setEventLocation(e.target.value)}
                                            className="w-full bg-[#111] border border-white/[0.08] rounded px-4 py-3 text-white"
                                        />
                                    </div>
                                </>
                            )}
                        </div>
                        <div className="flex justify-end gap-3 p-6 border-t border-white/10">
                            <button
                                onClick={() => setShowModal(false)}
                                className="px-6 py-2 text-gray-400 hover:text-white"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleSave}
                                disabled={saving}
                                className="btn-primary px-6 py-2 disabled:opacity-50"
                            >
                                {saving ? 'Saving...' : 'Save'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { 
    Users, 
    Plane, 
    FileText, 
    ShoppingBag, 
    Map, 
    Bell, 
    Settings,
    ArrowRight,
    Loader2,
    Check,
} from 'lucide-react';
import { DownloadStatsCard } from '@/components/admin/DownloadStatsCard';

interface AdminStats {
    totalPilots: number;
    activeFlights: number;
    totalFlights: number;
    pendingPireps: number;
    airlineBalance: number;
}

export default function AdminPage() {
    const [stats, setStats] = useState<AdminStats | null>(null);
    const [loading, setLoading] = useState(true);

    const fetchStats = async () => {
        try {
            const res = await fetch('/api/admin/stats');
            const data = await res.json();
            if (res.ok) {
                setStats(data.stats);
            }
        } catch (error) {
            console.error('Failed to fetch admin stats:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchStats();
    }, []);

    const adminActions = [
        { 
            title: 'Manage Pilots', 
            description: 'Activate, suspend, or update pilot roles.',
            icon: <Users className="w-8 h-8 text-blue-400" />,
            link: '/portal/admin/pilots',
            count: stats?.totalPilots
        },
        { 
            title: 'Store Management', 
            description: 'Manage items, prices, and download links.',
            icon: <ShoppingBag className="w-8 h-8 text-accent-gold" />,
            link: '/portal/admin/store'
        },
        { 
            title: 'Tour Management', 
            description: 'Create multi-leg tours and rewards.',
            icon: <Map className="w-8 h-8 text-green-400" />,
            link: '/portal/admin/tours'
        },
        { 
            title: 'Audit PIREPs', 
            description: 'Review and approve pending flight reports.',
            icon: <FileText className="w-8 h-8 text-yellow-400" />,
            link: '/portal/admin/reports',
            count: stats?.pendingPireps,
            alert: (stats?.pendingPireps || 0) > 0
        },
    ];

    const statCards = [
        { label: 'Airline Balance', value: stats?.airlineBalance, format: (v: number) => `${v.toLocaleString()} cr`, color: 'text-emerald-400', icon: ShoppingBag, iconBg: 'bg-emerald-500/10' },
        { label: 'Total Pilots', value: stats?.totalPilots, color: 'text-white', icon: Users, iconBg: 'bg-blue-500/10' },
        { label: 'Active Flights', value: stats?.activeFlights, color: 'text-accent-gold', icon: Plane, iconBg: 'bg-accent-gold/10' },
        { label: 'Total PIREPs', value: stats?.totalFlights, color: 'text-white', icon: FileText, iconBg: 'bg-white/[0.04]' },
        { label: 'Pending Approval', value: stats?.pendingPireps, color: 'text-amber-400', icon: Clock, iconBg: 'bg-amber-500/10' },
    ];

    return (
        <div className="space-y-6">
            {/* Header */}
            <div>
                <h1 className="text-2xl font-bold text-white">Admin Control Center</h1>
                <p className="text-gray-500 text-xs mt-0.5">Levant Virtual Airline operations and management</p>
            </div>

            {/* Stats Summary */}
            <div className="grid grid-cols-2 lg:grid-cols-5 gap-3">
                {statCards.map(s => (
                    <div key={s.label} className="bg-[#0a0a0a] border border-white/[0.06] rounded-2xl p-4 flex items-center gap-3">
                        <div className={`w-10 h-10 rounded-xl ${s.iconBg} flex items-center justify-center flex-shrink-0`}>
                            <s.icon className={`w-5 h-5 ${s.color}`} />
                        </div>
                        <div className="min-w-0">
                            <div className="text-[9px] text-gray-500 uppercase tracking-widest font-bold">{s.label}</div>
                            <div className={`text-xl font-bold font-mono ${s.color}`}>
                                {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : (s.format ? s.format(s.value || 0) : (s.value || 0).toLocaleString())}
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Main Actions Grid */}
            <div className="grid md:grid-cols-2 gap-3">
                {adminActions.map((action) => (
                    <Link key={action.title} href={action.link} className="bg-[#0a0a0a] border border-white/[0.06] rounded-2xl p-5 hover:border-accent-gold/20 transition-all group">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-4">
                                <div className="p-2.5 bg-white/[0.04] rounded-xl group-hover:bg-accent-gold/10 transition-colors">
                                    {action.icon}
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h3 className="text-sm font-bold text-white group-hover:text-accent-gold transition-colors">{action.title}</h3>
                                        {action.count !== undefined && (
                                            <span className={`px-1.5 py-0.5 rounded-md text-[10px] font-bold ${action.alert ? 'bg-amber-500/20 text-amber-400 border border-amber-500/20' : 'bg-white/[0.06] text-gray-500'}`}>
                                                {action.count}
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-gray-500 text-xs mt-0.5">{action.description}</p>
                                </div>
                            </div>
                            <ArrowRight className="w-4 h-4 text-gray-700 group-hover:text-accent-gold transition-colors" />
                        </div>
                    </Link>
                ))}
            </div>

            {/* Analytics & Stats */}
            <DownloadStatsCard />

            {/* Secondary Actions */}
            <div className="grid grid-cols-3 gap-3">
                 <button className="bg-[#0a0a0a] border border-white/[0.06] rounded-2xl p-4 flex flex-col items-center gap-2 text-gray-600 cursor-not-allowed">
                     <Bell className="w-4 h-4" />
                     <span className="text-[10px] font-bold uppercase tracking-widest">Broadcast</span>
                 </button>
                 <button className="bg-[#0a0a0a] border border-white/[0.06] rounded-2xl p-4 flex flex-col items-center gap-2 text-gray-600 cursor-not-allowed">
                     <Settings className="w-4 h-4" />
                     <span className="text-[10px] font-bold uppercase tracking-widest">Settings</span>
                 </button>
                 <div className="bg-[#0a0a0a] border border-white/[0.06] rounded-2xl p-4 flex flex-col items-center gap-2 text-center">
                     <span className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">System</span>
                     <span className="flex items-center gap-1.5 text-emerald-400 text-xs font-bold"><span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" /> Online</span>
                 </div>
            </div>
        </div>
    );
}

function Clock({ className }: { className?: string }) {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
            <circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>
        </svg>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { 
    Users, 
    Search, 
    Edit, 
    Shield, 
    ShieldAlert, 
    UserCheck, 
    UserX, 
    Clock,
    X,
    Check,
    AlertCircle,
    Loader2,
    Filter
} from 'lucide-react';

interface Pilot {
    id: string;
    pilotId: string;
    firstName: string;
    lastName: string;
    email: string;
    role: 'Pilot' | 'Admin';
    status: 'Pending' | 'Active' | 'Inactive' | 'Blacklist';
    rank: string;
    totalHours: number;
    totalFlights: number;
    totalCredits: number;
    lastActivity?: string;
    homeBase?: string;
    hub_manager?: string;
}

export default function AdminPilotsPage() {
    const [pilots, setPilots] = useState<Pilot[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [filterStatus, setFilterStatus] = useState<string>('all');

    // Modal state
    const [editing, setEditing] = useState<Pilot | null>(null);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const fetchPilots = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/admin/users');
            const data = await res.json();
            if (res.ok) {
                setPilots(data.users || []);
            }
        } catch (error) {
            console.error('Failed to fetch pilots:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchPilots();

        // Poll for updates every 60 seconds to catch rank changes
        const pollInterval = setInterval(() => {
            fetchPilots();
        }, 60000);

        return () => clearInterval(pollInterval);
    }, []);

    const handleUpdate = async (userId: string, updates: any) => {
        setSaving(true);
        setError(null);
        try {
            const res = await fetch('/api/admin/users', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ userId, ...updates }),
            });

            if (res.ok) {
                setEditing(null);
                fetchPilots();
            } else {
                const data = await res.json();
                setError(data.error || 'Failed to update user');
            }
        } catch (error) {
            setError('Connection error');
        } finally {
            setSaving(false);
        }
    };

    const filteredPilots = pilots.filter(p => {
        const matchesSearch = `${p.pilotId} ${p.firstName} ${p.lastName} ${p.email}`.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = filterStatus === 'all' || p.status.toLowerCase() === filterStatus.toLowerCase();
        return matchesSearch && matchesStatus;
    });

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'Active': return <UserCheck className="w-4 h-4 text-green-500" />;
            case 'Pending': return <Clock className="w-4 h-4 text-yellow-500" />;
            case 'Inactive': return <UserX className="w-4 h-4 text-red-500" />;
            case 'Blacklist': return <ShieldAlert className="w-4 h-4 text-red-600 font-bold" />;
            default: return null;
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                    <Users className="w-8 h-8 text-accent-gold" />
                    <div>
                        <h1 className="text-2xl font-bold text-white">Pilot Management</h1>
                        <p className="text-gray-400">Manage {pilots.length} registered pilots</p>
                    </div>
                </div>
            </div>

            {/* Filters */}
            <div className="grid md:grid-cols-3 gap-4">
                <div className="relative md:col-span-2">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                    <input
                        type="text"
                        placeholder="Search by ID, Name or Email..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="w-full bg-[#0a0a0a] border border-white/[0.08] rounded-lg pl-12 pr-4 py-3 text-white focus:outline-none focus:border-accent-gold"
                    />
                </div>
                <div className="relative">
                    <Filter className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                    <select
                        value={filterStatus}
                        onChange={(e) => setFilterStatus(e.target.value)}
                        className="w-full bg-[#0a0a0a] border border-white/[0.08] rounded-lg pl-12 pr-4 py-3 text-white focus:outline-none focus:border-accent-gold appearance-none"
                    >
                        <option value="all">All Statuses</option>
                        <option value="active">Active</option>
                        <option value="pending">Pending</option>
                        <option value="inactive">Inactive</option>
                        <option value="blacklist">Blacklist</option>
                    </select>
                </div>
            </div>

            {loading ? (
                <div className="glass-card p-12 text-center text-gray-400">
                    <Loader2 className="w-8 h-8 animate-spin mx-auto mb-4 text-accent-gold" />
                    Loading pilots...
                </div>
            ) : (
                <div className="glass-card overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead className="bg-[#111]/50">
                                <tr className="text-left text-gray-500 text-xs uppercase tracking-widest border-b border-white/[0.06]">
                                    <th className="p-4">Pilot</th>
                                    <th className="p-4">Rank & Stats</th>
                                    <th className="p-4">Role</th>
                                    <th className="p-4">Status</th>
                                    <th className="p-4">Last Activity</th>
                                    <th className="p-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {filteredPilots.map((pilot) => (
                                    <tr key={pilot.id} className="hover:bg-white/5 transition-colors group">
                                        <td className="p-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full bg-accent-gold/10 border border-accent-gold/20 flex items-center justify-center text-accent-gold font-bold">
                                                    {pilot.firstName[0]}{pilot.lastName[0]}
                                                </div>
                                                <div>
                                                    <p className="text-white font-medium">{pilot.firstName} {pilot.lastName}</p>
                                                    <p className="text-accent-gold font-mono text-xs">{pilot.pilotId}</p>
                                                    <p className="text-gray-500 text-[10px] lowercase">{pilot.email}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="p-4">
                                            <span className="text-gray-300 text-sm">{pilot.rank}</span>
                                            <div className="flex gap-3 mt-1">
                                                <span className="text-[10px] text-gray-400 capitalize">{Math.round(pilot.totalHours)}h / {pilot.totalFlights} flights</span>
                                            </div>
                                        </td>
                                        <td className="p-4">
                                            <div className="flex items-center gap-2">
                                                {pilot.role === 'Admin' ? (
                                                    <span className="bg-purple-500/10 text-purple-400 px-2 py-0.5 rounded text-[10px] font-bold border border-purple-500/20 flex items-center gap-1">
                                                        <Shield className="w-3 h-3" /> ADMIN
                                                    </span>
                                                ) : (
                                                    <span className="text-gray-400 text-[10px] font-bold">PILOT</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="p-4">
                                            <div className="flex items-center gap-2 text-xs">
                                                {getStatusIcon(pilot.status)}
                                                <span className={
                                                    pilot.status === 'Active' ? 'text-green-500' :
                                                    pilot.status === 'Pending' ? 'text-yellow-500' :
                                                    'text-red-500'
                                                }>
                                                    {pilot.status}
                                                </span>
                                            </div>
                                        </td>
                                        <td className="p-4 text-gray-500 text-xs">
                                            {pilot.lastActivity ? new Date(pilot.lastActivity).toLocaleDateString() : 'Never'}
                                        </td>
                                        <td className="p-4 text-right">
                                            <button 
                                                onClick={() => setEditing(pilot)}
                                                className="p-2 text-gray-400 hover:text-accent-gold transition-colors"
                                            >
                                                <Edit className="w-4 h-4" />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Edit Modal */}
            {editing && (
                <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
                    <div className="bg-[#0a0a0a] rounded-xl w-full max-w-md border border-white/[0.08] shadow-2xl overflow-hidden">
                        <div className="p-6 border-b border-white/10 flex justify-between items-center">
                            <div>
                                <h2 className="text-xl font-bold text-white">Edit Pilot</h2>
                                <p className="text-xs text-accent-gold font-mono uppercase tracking-widest mt-0.5">{editing.pilotId}</p>
                            </div>
