    flight_number: string;
    callsign: string;
    pilot_id: string;
    departure_icao: string;
    arrival_icao: string;
    alternate_icao?: string;
    route?: string;
    aircraft?: string;
    comments?: string;
    admin_comments?: string;
    approved_status: number;
    duration?: string;
    distance?: number;
    fuel?: number;
    pax?: number;
    cargo?: number;
    departure_time?: string;
    arrival_time?: string;
    landing_rate?: number;
    score?: number;
