                    </thead>
                    <tbody className="divide-y divide-white/[0.04]">
                        {loading ? (
                            <tr>
                                <td colSpan={7} className="px-6 py-16 text-center text-gray-500 animate-pulse">
                                    <FileText className="w-10 h-10 mx-auto mb-3 text-gray-700" />
