    email: string;
    order: number;
    color: string;
}

interface StaffMember {
    _id: string;
    pilot_id: {
        _id: string;
        first_name: string;
        last_name: string;
        pilot_id: string;
        rank: string;
    };
    role_id: StaffRole;
    is_head: boolean;
    name?: string;
    callsign?: string;
    email?: string;
    picture?: string;
    discord?: string;
}

export default function AdminStaffPage() {
    const [members, setMembers] = useState<StaffMember[]>([]);
    const [loading, setLoading] = useState(true);

    // New Staff Form State
    const [pilotIdInput, setPilotIdInput] = useState('');
    const [memberDetails, setMemberDetails] = useState({ 
        roleTitle: '', 
        name: '', 
        email: '', 
        discord: '' 
    });
    const [editingMemberId, setEditingMemberId] = useState<string | null>(null);
    const [assigning, setAssigning] = useState(false);
    const [showEditModal, setShowEditModal] = useState(false);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/staff/members');
            const data = await res.json();
            if (data.success) setMembers(data.members);
        } catch (e) {
            console.error('Failed to fetch staff data', e);
        } finally {
            setLoading(false);
        }
    };

    const handleAddOrUpdateStaff = async (e: React.FormEvent) => {
        e.preventDefault();
        setAssigning(true);
        try {
            const url = editingMemberId 
                ? `/api/staff/members/${editingMemberId}` 
                : '/api/staff/members';
            const method = editingMemberId ? 'PUT' : 'POST';

            const res = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ 
                    pilotId: pilotIdInput, 
                    ...memberDetails
                })
            });
            const data = await res.json();
            if (data.success) {
                if (editingMemberId) {
                    setMembers(members.map(m => m._id === editingMemberId ? data.member : m));
                } else {
                    setMembers([data.member, ...members]);
