                                        <input type="file" ref={fileInputRef} className="hidden" accept={category === 'Skin' ? ".zip" : "*"} onChange={(e) => handleFileUpload(e, 'zip')} />
                                    </div>

                                    {/* Live Preview Card */}
                                    {name && (
                                        <div className="p-4 bg-white/[0.02] rounded-xl border border-white/[0.06]">
