                                                    Book Flight <ArrowRight className="w-5 h-5" />
                                                </>
                                            )}
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}

                    {events.length === 0 && (
                        <div className="text-center py-12 text-gray-500">
                            No upcoming events on the radar. Check back soon.
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

