                                    </>
                                )}
                            </button>
                        </div>
                    )}
                </motion.div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Calendar, Users, MapPin, Clock, Plane, Trophy, Loader2, UserPlus, UserMinus, CheckCircle } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';

interface GroupFlight {
    _id: string;
    title: string;
    description: string;
    eventType: string;
    status: string;
    startTime: string;
    departureIcao: string;
    departureAirport?: string;
    arrivalIcao: string;
    arrivalAirport?: string;
    route?: string;
    aircraft?: string;
    estimatedFlightTime?: string;
    reminderMinutes?: number;
    maxParticipants?: number;
    participants: any[];
    scoringEnabled: boolean;
}

export default function GroupFlightsPage() {
    const { user } = useAuth();
    const [flights, setFlights] = useState<GroupFlight[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState<'upcoming' | 'active' | 'completed'>('upcoming');
    const [joiningId, setJoiningId] = useState<string | null>(null);

    useEffect(() => {
        fetchFlights();

        // Poll for status updates every 30 seconds
        const interval = setInterval(() => {
            fetchFlights();
        }, 30000);

        return () => clearInterval(interval);
    }, [filter]);

    const fetchFlights = async () => {
        try {
            const res = await fetch(`/api/portal/multiplayer-events?filter=${filter}`);
            const data = await res.json();
            if (data.success) setFlights(data.events);
        } catch (error) {
            console.error('Fetch flights error:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleJoin = async (eventId: string) => {
        setJoiningId(eventId);
        try {
            const res = await fetch('/api/portal/multiplayer-events', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ eventId }),
            });
            const data = await res.json();
            if (data.success) {
                fetchFlights();
            } else {
                alert(data.error || 'Failed to join');
            }
        } catch (error) {
            console.error('Join error:', error);
            alert('Failed to join group flight');
        } finally {
            setJoiningId(null);
        }
    };

    const handleLeave = async (eventId: string) => {
        if (!confirm('Leave this group flight?')) return;

        try {
            const res = await fetch(`/api/portal/multiplayer-events?eventId=${eventId}`, {
                method: 'DELETE',
            });
            const data = await res.json();
            if (data.success) {
                fetchFlights();
            } else {
                alert(data.error || 'Failed to leave');
            }
        } catch (error) {
            console.error('Leave error:', error);
            alert('Failed to leave group flight');
        }
    };

    const isJoined = (flight: GroupFlight) => {
        return flight.participants.some((p: any) => p.pilotId === user?.pilotId);
    };

    const getTimeRemaining = (startTime: string) => {
        const now = new Date();
        const start = new Date(startTime);
        const diff = start.getTime() - now.getTime();

        if (diff < 0) return 'Started';

        const hours = Math.floor(diff / (1000 * 60 * 60));
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));

        if (hours > 24) {
            const days = Math.floor(hours / 24);
            return `in ${days} day${days > 1 ? 's' : ''}`;
        }

        return `in ${hours}h ${minutes}m`;
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-96">
                <Loader2 className="w-8 h-8 animate-spin text-accent-gold" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div>
                <h1 className="text-3xl font-bold text-white mb-2">Group Flights</h1>
                <p className="text-gray-400">Join coordinated flights with other Levant VA pilots</p>
            </div>

            {/* Filter Tabs */}
            <div className="flex gap-2 border-b border-white/10">
                {(['upcoming', 'active', 'completed'] as const).map((tab) => (
                    <button
                        key={tab}
                        onClick={() => setFilter(tab)}
                        className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 ${
                            filter === tab
                                ? 'border-accent-gold text-accent-gold'
                                : 'border-transparent text-gray-400 hover:text-white'
                        }`}
                    >
                        {tab.charAt(0).toUpperCase() + tab.slice(1)}
                    </button>
                ))}
            </div>

            {/* Flights Grid */}
            <div className="grid gap-4">
                {flights.length === 0 ? (
                    <div className="text-center py-12 bg-[#111] border border-white/10 rounded-xl">
                        <Users size={48} className="mx-auto text-gray-600 mb-3" />
                        <p className="text-gray-500">No {filter} group flights</p>
                    </div>
                ) : (
                    flights.map((flight) => {
                        const joined = isJoined(flight);
                        const canJoin = !joined && flight.status === 'scheduled';

                        return (
                            <div key={flight._id} className="bg-[#111] border border-white/10 rounded-xl p-6 hover:border-accent-gold/30 transition-all">
                                <div className="flex items-start justify-between mb-4">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-3 mb-2">
                                            <h3 className="text-xl font-bold text-white">{flight.title}</h3>
                                            {joined && (
                                                <span className="px-2 py-1 bg-green-500/20 text-green-400 text-xs font-bold rounded border border-green-500/30">
                                                    <CheckCircle size={12} className="inline mr-1" />
                                                    JOINED
                                                </span>
                                            )}
                                            {flight.scoringEnabled && (
                                                <span className="px-2 py-1 bg-purple-500/20 text-purple-400 text-xs font-bold rounded border border-purple-500/30">
                                                    <Trophy size={12} className="inline mr-1" />
                                                    COMPETITIVE
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-gray-400 text-sm mb-4">{flight.description}</p>

                                        {/* Flight Details Grid */}
                                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                                            <div className="flex items-center gap-2 text-sm">
                                                <MapPin size={16} className="text-accent-gold" />
                                                <div>
                                                    <p className="text-gray-500 text-xs">Route</p>
                                                    <p className="text-white font-mono">{flight.departureIcao} → {flight.arrivalIcao}</p>
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-2 text-sm">
                                                <Calendar size={16} className="text-blue-400" />
                                                <div>
                                                    <p className="text-gray-500 text-xs">Date (Local)</p>
                                                    <p className="text-white">{new Date(flight.startTime).toLocaleDateString()}</p>
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-2 text-sm">
                                                <Clock size={16} className="text-emerald-400" />
                                                <div>
                                                    <p className="text-gray-500 text-xs">Time (Local)</p>
                                                    <p className="text-white">{new Date(flight.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                                                    <p className="text-gray-500 text-[10px]">{new Date(flight.startTime).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'UTC' })}Z</p>
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-2 text-sm">
                                                <Users size={16} className="text-purple-400" />
                                                <div>
                                                    <p className="text-gray-500 text-xs">Pilots</p>
                                                    <p className="text-white">{flight.participants.length}</p>
                                                </div>
                                            </div>
                                        </div>

                                        {/* Additional Info */}
                                        <div className="flex flex-wrap gap-4 text-xs text-gray-400">
                                            {flight.estimatedFlightTime && (
                                                <span>⏱️ Air Time: {flight.estimatedFlightTime}</span>
                                            )}
                                            {flight.departureAirport && (
                                                <span>📍 {flight.departureAirport}</span>
                                            )}
                                        </div>

                                        {/* Route */}
                                        {flight.route && (
                                            <div className="mt-3 p-3 bg-black/30 rounded-lg border border-white/5">
                                                <p className="text-xs text-gray-500 mb-1">Route</p>
                                                <p className="text-xs text-gray-300 font-mono break-all">{flight.route}</p>
                                            </div>
                                        )}
                                    </div>

                                    {/* Action Button */}
                                    <div className="ml-4 flex flex-col items-end gap-2">
                                        <div className="text-right mb-2">
                                            <p className="text-xs text-gray-500">Starts</p>
                                            <p className="text-sm font-bold text-accent-gold">{getTimeRemaining(flight.startTime)}</p>
                                        </div>

                                        {flight.status === 'scheduled' && (
                                            joined ? (
                                                <button
                                                    onClick={() => handleLeave(flight._id)}
                                                    className="px-4 py-2 bg-red-500/20 text-red-400 rounded-lg hover:bg-red-500/30 transition-colors border border-red-500/30 text-sm font-medium flex items-center gap-2"
                                                >
                                                    <UserMinus size={16} />
                                                    Leave
                                                </button>
                                            ) : (
                                                <button
                                                    onClick={() => handleJoin(flight._id)}
                                                    disabled={joiningId === flight._id}
                                                    className="px-4 py-2 bg-accent-gold text-black rounded-lg hover:bg-accent-gold/90 transition-colors text-sm font-medium flex items-center gap-2"
                                                >
                                                    {joiningId === flight._id ? (
                                                        <Loader2 size={16} className="animate-spin" />
                                                    ) : (
                                                        <UserPlus size={16} />
                                                    )}
                                                    Join Flight
                                                </button>
                                            )
                                        )}
                                    </div>
                                </div>

                                {/* Participants */}
                                {flight.participants.length > 0 && (
                                    <div className="mt-4 pt-4 border-t border-white/10">
                                        <p className="text-xs text-gray-500 mb-2">Registered Pilots ({flight.participants.length})</p>
                                        <div className="flex flex-wrap gap-2">
                                            {flight.participants.slice(0, 10).map((p: any, i: number) => (
                                                <span key={i} className="px-2 py-1 bg-white/5 text-gray-300 text-xs rounded border border-white/10">
                                                    {p.pilotName}
                                                </span>
                                            ))}
                                            {flight.participants.length > 10 && (
                                                <span className="px-2 py-1 bg-white/5 text-gray-500 text-xs rounded border border-white/10">
                                                    +{flight.participants.length - 10} more
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useFlightSocket } from '@/hooks/useFlightSocket';
import { 
    Activity, 
    Wifi, 
    Users, 
    Map as MapIcon, 
    Clock, 
    Plane, 
    Globe, 
    Navigation,
    Loader2,
    Signal,
    Zap,
    AlertTriangle,
    Wind
} from 'lucide-react';
import dynamic from 'next/dynamic';

const DashboardMap = dynamic(() => import('@/components/DashboardMap'), { ssr: false });

export default function OpsCenterPage() {
    const [flights, setFlights] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({
        airborne: 0,
        preflight: 0,
    });
    const [delays, setDelays] = useState<any[]>([]);
    const [wings, setWings] = useState<any[]>([]);

    // Fetch delays & flight wings every 30s
    useEffect(() => {
        const fetchExtras = async () => {
            try {
                const [dRes, wRes] = await Promise.all([
                    fetch('/api/portal/delays'),
                    fetch('/api/portal/flight-wings'),
                ]);
                const dData = await dRes.json();
                const wData = await wRes.json();
                if (dData.success) setDelays(dData.delays);
                if (wData.success) setWings(wData.wings);
            } catch { /* ignore */ }
        };
        fetchExtras();
        const interval = setInterval(fetchExtras, 30000);
        return () => clearInterval(interval);
    }, []);

    // Real-time Pusher — merge incoming flight updates instantly (add OR update)
    useFlightSocket(useCallback((data: any) => {
        if (!data?.callsign) return;
        setFlights(prev => {
            const exists = prev.some(f => f.callsign === data.callsign);
            if (exists) {
                return prev.map(f =>
                    f.callsign === data.callsign
                        ? { ...f, latitude: data.latitude, longitude: data.longitude, altitude: data.altitude, heading: data.heading, groundSpeed: data.groundSpeed ?? data.groundspeed ?? f.groundSpeed, ground_speed: data.groundSpeed ?? data.groundspeed ?? f.ground_speed, status: data.status, phase: data.phase ?? f.phase, ias: data.ias ?? f.ias, verticalSpeed: data.verticalSpeed ?? f.verticalSpeed, departure: data.departure ?? f.departure, arrival: data.arrival ?? f.arrival, equipment: data.equipment ?? f.equipment, comfort_score: data.comfort_score ?? f.comfort_score, fuel: data.fuel ?? f.fuel }
                        : f
                );
            }
            // New flight — add it
            return [...prev, {
                _id: data.callsign,
                callsign: data.callsign,
                pilot: data.pilot || '',
                pilot_name: data.pilot || '',
                departure: data.departure || '',
                departure_icao: data.departure || '',
                arrival: data.arrival || '',
                arrival_icao: data.arrival || '',
                equipment: data.equipment || '',
                aircraft_type: data.equipment || '',
                latitude: data.latitude,
                longitude: data.longitude,
                altitude: data.altitude || 0,
                heading: data.heading || 0,
                groundSpeed: data.groundSpeed || data.groundspeed || 0,
                ground_speed: data.groundSpeed || data.groundspeed || 0,
                verticalSpeed: data.verticalSpeed || 0,
                ias: data.ias || 0,
                fuel: data.fuel || 0,
                phase: data.phase || data.status || '',
                status: data.phase || data.status || '',
                comfort_score: data.comfort_score || 100,
                network: 'LEVANT',
            }];
        });
    }, []));

    useEffect(() => {
        fetchFlights();
        const interval = setInterval(fetchFlights, 15000); // Poll every 15s
        return () => clearInterval(interval);
    }, []); // Re-fetch on mount

    const fetchFlights = async () => {
        try {
            let allFlights: any[] = [];

            // Try ACARS traffic API first for Levant flights
            const trafficRes = await fetch('/api/acars?action=traffic');
            if (trafficRes.ok) {
                const tData = await trafficRes.json();
                if (tData.traffic && Array.isArray(tData.traffic) && tData.traffic.length > 0) {
                    allFlights = tData.traffic.map((f: any) => ({
                        _id: f.callsign,
                        callsign: f.callsign,
                        pilot: f.pilotName || f.pilot_name || '',
                        pilot_name: f.pilotName || f.pilot_name || '',
                        departure: f.departureIcao || f.departure_icao || '',
                        departure_icao: f.departureIcao || f.departure_icao || '',
                        arrival: f.arrivalIcao || f.arrival_icao || '',
                        arrival_icao: f.arrivalIcao || f.arrival_icao || '',
                        equipment: f.aircraftType || f.aircraft_type || '',
                        aircraft_type: f.aircraftType || f.aircraft_type || '',
                        latitude: f.latitude,
                        longitude: f.longitude,
                        altitude: f.altitude,
                        heading: f.heading,
                        groundSpeed: f.groundSpeed || f.ground_speed || 0,
                        ground_speed: f.groundSpeed || f.ground_speed || 0,
                        verticalSpeed: f.verticalSpeed || f.vertical_speed || 0,
                        ias: f.ias || 0,
                        fuel: f.fuel || 0,
                        phase: f.phase || f.status || '',
                        status: f.phase || f.status || '',
                        comfort_score: f.comfortScore || f.comfort_score || 100,
                        network: 'LEVANT',
                    }));
                }
            }

            // Fallback to portal ops/live endpoint
            if (allFlights.length === 0) {
                const res = await fetch(`/api/portal/ops/live?network=off`);
                const data = await res.json();
                if (data.flights) allFlights = data.flights;
            }

            setFlights(allFlights);

            // Calculate mini stats (Levant Only)
            const levantFlights = allFlights.filter((f: any) => f.network === 'LEVANT');
            const airborne = levantFlights.filter((f: any) => f.status === 'Airborne' || f.altitude > 500).length;
            const preflight = levantFlights.length - airborne;

            setStats({
                airborne,
                preflight,
            });
        } catch (err) {
            console.error('Error fetching live ops:', err);
        } finally {
            setLoading(false);
        }
    };

    if (loading && flights.length === 0) return (
        <div className="flex flex-col items-center justify-center min-h-[400px] gap-4">
            <Loader2 className="w-8 h-8 text-accent-gold animate-spin" />
            <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Connecting to Global Ops Network...</p>
        </div>
    );

    return (
        <div className="space-y-6 max-w-[1600px] mx-auto pb-12 h-[calc(100vh-120px)] flex flex-col">
            {/* Header / Stats Bar */}
            <div className="flex flex-col lg:flex-row items-center justify-between gap-6 shrink-0">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-accent-gold rounded-2xl flex items-center justify-center animate-pulse">
                        <Activity className="text-dark-900 w-6 h-6" />
                    </div>
                    <div>
                        <h1 className="text-2xl font-display font-bold text-white uppercase tracking-tight">Live Operations Center</h1>
                        <div className="flex items-center gap-2 text-[10px] font-mono text-emerald-400 uppercase tracking-widest">
                            <span className="w-2 h-2 bg-emerald-500 rounded-full animate-ping" />
                            System Active // Real-time Synchronization
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 w-full lg:w-auto">
                    <MiniStat label="Airborne" value={stats.airborne} icon={<Navigation className="text-blue-400" />} />
                    <MiniStat label="Dispatching" value={stats.preflight} icon={<Clock className="text-yellow-400" />} />
                    <MiniStat label="Total Flights" value={flights.length} icon={<Wifi className="text-emerald-400" />} />
                    <MiniStat label="Network Avg" value="99.9%" icon={<Signal className="text-purple-400" />} />
                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1 grid grid-cols-1 lg:grid-cols-4 gap-6 overflow-hidden min-h-0">
                {/* Left: Global Flight Board */}
                <div className="lg:col-span-1 glass-card flex flex-col min-h-0">
                    <div className="p-4 border-b border-white/[0.06] flex items-center justify-between">
                        <h2 className="text-xs font-bold text-gray-400 uppercase tracking-[0.2em] flex items-center gap-2">
                            <Globe className="w-3 h-3 text-accent-gold" /> Global Flight Board
                        </h2>
                        <span className="text-[10px] font-mono text-gray-600">{flights.length} Active</span>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                        {flights.filter(f => f.network === 'LEVANT').map((f) => ( // Only show Levant flights in list
                            <div key={f._id} className="bg-white/[0.02] border border-white/[0.06] rounded-xl p-4 hover:bg-white/5 transition-all group">
                                <div className="flex justify-between items-start mb-3">
                                    <div>
                                        <p className="text-sm font-black text-white group-hover:text-accent-gold transition-colors">{f.callsign}</p>
                                        <p className="text-[10px] text-gray-500 font-mono">{f.pilot_name}</p>
                                    </div>
                                    <div className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-tighter ${
                                        f.status === 'Airborne' ? 'bg-blue-500/20 text-blue-400' : 'bg-yellow-500/20 text-yellow-400'
                                    }`}>
                                        {f.status}
                                    </div>
                                </div>

                                <div className="flex items-center justify-between gap-2 mb-3">
                                    <div className="text-center">
                                        <p className="text-xs font-bold text-white">{f.departure_icao}</p>
                                        <p className="text-[8px] text-gray-600 uppercase">DEP</p>
                                    </div>
                                    <div className="flex-1 flex flex-col items-center gap-0.5 opacity-30">
                                        <div className="w-full h-[1px] bg-white/10 relative">
                                            <Plane className="w-2 h-2 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 rotate-90" />
                                        </div>
                                    </div>
                                    <div className="text-center">
                                        <p className="text-xs font-bold text-white">{f.arrival_icao}</p>
                                        <p className="text-[8px] text-gray-600 uppercase">ARR</p>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-2 pt-3 border-t border-white/[0.06]">
                                    <div className="flex items-center gap-1.5 font-mono text-[9px] text-gray-500 uppercase">
                                        <Navigation size={10} className="text-blue-500" /> {Math.round(f.altitude)} ft
                                    </div>
                                    <div className="flex items-center gap-1.5 font-mono text-[9px] text-gray-500 uppercase">
                                        <Zap size={10} className="text-accent-gold" /> {Math.round(f.ground_speed)} kt
                                    </div>
                                    <div className="flex items-center gap-1.5 font-mono text-[9px] text-gray-500 uppercase">
                                        <Plane size={10} className="text-emerald-500" /> {Math.round(f.ias || 0)} ias
                                    </div>
                                    <div className="flex items-center gap-1.5 font-mono text-[9px] text-gray-500 uppercase">
                                        <Activity size={10} className="text-purple-500" /> {f.phase || 'N/A'}
                                    </div>
                                </div>
                            </div>
                        ))}

                        {flights.filter(f => f.network === 'LEVANT').length === 0 && (
                            <div className="h-full flex flex-col items-center justify-center text-center opacity-20 py-12">
                                <Plane size={32} className="mb-2" />
                                <p className="text-[10px] font-bold uppercase tracking-widest text-gray-500">No active flights</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Right: Operations Map */}
                <div className="lg:col-span-3 glass-card relative overflow-hidden flex flex-col">
                    <div className="p-4 border-b border-white/[0.06] bg-[#080808]/50 relative z-20 flex items-center justify-between">
                        <h2 className="text-xs font-bold text-gray-400 uppercase tracking-[0.2em] flex items-center gap-2">
                            <MapIcon className="w-3 h-3 text-blue-400" /> Live Map
                        </h2>
                        <div className="flex items-center gap-4">
                            {/* Network Toggles */}
                            <div className="flex bg-white/5 rounded-lg p-1 border border-white/[0.08]">
                            </div>
                        </div>
                    </div>

                    <div className="flex-1 relative z-10">
                         <DashboardMap flights={flights} />
                    </div>

                    {/* Overlay: Fleet Health / ATC Status (Floating) */}
                    <div className="absolute bottom-6 left-6 z-20 space-y-3 pointer-events-none">
                        <div className="glass-panel p-4 rounded-2xl border border-white/[0.08] max-w-[200px] backdrop-blur-2xl">
                             <p className="text-[10px] font-black text-gray-500 uppercase mb-2 tracking-widest">Main Hubs Status</p>
                             <div className="space-y-2">
                                 <HubStatus icao="OJAI" status="Active" pilots={flights.filter(f => f.departure_icao === 'OJAI').length} />
                                 <HubStatus icao="OSDI" status="Active" pilots={flights.filter(f => f.departure_icao === 'OSDI').length} />
                                 <HubStatus icao="ORBI" status="Active" pilots={flights.filter(f => f.departure_icao === 'ORBI').length} />
                             </div>
                        </div>
                    </div>

                    {/* Overlay: Delays & Flight Wings (Right side) */}
                    <div className="absolute bottom-6 right-6 z-20 space-y-3 pointer-events-none max-w-[240px]">
                        {delays.length > 0 && (
                            <div className="glass-panel p-4 rounded-2xl border border-orange-500/20 backdrop-blur-2xl pointer-events-auto">
                                <p className="text-[10px] font-black text-orange-400 uppercase mb-2 tracking-widest flex items-center gap-1.5">
                                    <AlertTriangle size={10} /> Current Delays
                                </p>
                                <div className="space-y-2">
                                    {delays.slice(0, 4).map((d: any, i: number) => (
                                        <div key={i} className="text-[10px]">
                                            <div className="flex items-center gap-1.5">
                                                <span className="font-mono font-bold text-white">{d.callsign}</span>
                                                <span className="text-gray-600">·</span>
                                                <span className="text-gray-500">{d.departure_icao}→{d.arrival_icao}</span>
                                            </div>
                                            <div className="flex flex-wrap gap-1 mt-0.5">
                                                {d.reasons.map((r: string, j: number) => (
                                                    <span key={j} className="text-[8px] bg-orange-500/10 text-orange-400 border border-orange-500/20 rounded px-1.5 py-0.5">{r}</span>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                        {wings.length > 0 && (
                            <div className="glass-panel p-4 rounded-2xl border border-blue-500/20 backdrop-blur-2xl pointer-events-auto">
                                <p className="text-[10px] font-black text-blue-400 uppercase mb-2 tracking-widest flex items-center gap-1.5">
                                    <Users size={10} /> Flight Wings
                                </p>
                                <div className="space-y-2">
                                    {wings.slice(0, 3).map((w: any, i: number) => (
                                        <div key={i} className="text-[10px]">
                                            <div className="flex items-center justify-between">
                                                <span className="font-mono font-bold text-white">{w.route}</span>
                                                <span className="text-blue-400 font-bold">{w.count} pilots</span>
                                            </div>
                                            <div className="flex flex-wrap gap-1 mt-0.5">
                                                {w.pilots.map((p: any, j: number) => (
                                                    <span key={j} className="text-[8px] bg-blue-500/10 text-blue-300 border border-blue-500/20 rounded px-1.5 py-0.5">{p.callsign}</span>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

function MiniStat({ label, value, icon }: any) {
    return (
        <div className="glass-panel px-4 py-3 rounded-xl border border-white/[0.06] flex items-center gap-3 min-w-[140px]">
            <div className="shrink-0">{icon}</div>
            <div>
                <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest leading-none mb-1">{label}</p>
                <p className="text-sm font-display font-black text-white leading-none">{value}</p>
            </div>
        </div>
    );
}

function HubStatus({ icao, status, pilots }: any) {
    return (
        <div className="flex items-center justify-between gap-4">
            <span className="text-[10px] font-mono text-white font-bold">{icao}</span>
            <div className="flex items-center gap-1 px-1.5 py-0.5 bg-white/5 rounded text-[8px] font-mono text-gray-400">
                 {pilots} <Users size={8} />
            </div>
            <span className={`text-[8px] font-black uppercase ${status === 'Active' ? 'text-emerald-400' : 'text-gray-600'}`}>
                {status}
            </span>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { 
    Clock, TrendingDown, Target, Zap, Plane, Calendar, Check, User, Shield,
    ChevronRight, Trophy, Medal, Camera, Loader2, Trash2, X, Award, MapPin, Star, Activity
} from 'lucide-react';
import { toast } from 'sonner';

interface Pilot {
    pilot_id: string;
    first_name: string;
    last_name: string;
    email: string;
    rank: string;
    country: string;
    timezone: string;
    ivao_vid?: string;
    simbrief_id?: string;
    avatar_url?: string;
    total_hours: number;
    transfer_hours: number;
    total_flights: number;
    total_credits: number;
    routes_flown?: string[];
    current_location: string;
    average_landing: number;
    status: string;
    created_at: string;
    email_opt_in: boolean;
    balance: number;
    hoppie_code?: string;
    sim_mode?: string;
}

interface Country {
    code: string;
    name: string;
    flag: string;
    timezones: string[];
}

interface PilotBadge {
    _id: string;
    award_id: {
        _id: string;
        name: string;
        description?: string;
        imageUrl?: string;
        category?: string;
    };
    earned_at: string;
}

const RANKS = [
    { name: 'Cadet', hours: 0 },
    { name: 'Second Officer', hours: 25 },
    { name: 'First Officer', hours: 50 },
    { name: 'Senior First Officer', hours: 100 },
    { name: 'Captain', hours: 250 },
    { name: 'Senior Captain', hours: 500 },
    { name: 'Check Airman', hours: 1000 },
];

function getRankProgress(hours: number) {
    let currentRank = RANKS[0];
    let nextRank = RANKS[1];

    for (let i = 0; i < RANKS.length; i++) {
        if (hours >= RANKS[i].hours) {
            currentRank = RANKS[i];
            nextRank = RANKS[i + 1] || RANKS[i];
        }
    }

    if (currentRank === nextRank) return { currentRank, nextRank, progress: 100 };

    const progressInRank = hours - currentRank.hours;
    const hoursNeeded = nextRank.hours - currentRank.hours;
    const progress = Math.min((progressInRank / hoursNeeded) * 100, 100);

    return { currentRank, nextRank, progress };
}

export default function ProfilePage() {
    const [pilot, setPilot] = useState<Pilot | null>(null);
    const [loading, setLoading] = useState(true);
    const [flightHistory, setFlightHistory] = useState<any[]>([]);
    const [countries, setCountries] = useState<Country[]>([]);
    const [pilotBadges, setPilotBadges] = useState<PilotBadge[]>([]);
    const [uploadingImage, setUploadingImage] = useState(false);
    const [avatarError, setAvatarError] = useState(false);
    const [avatarTimestamp, setAvatarTimestamp] = useState(Date.now());
    const router = useRouter();

    useEffect(() => {
        const fetchCountries = async () => {
            try {
                const res = await fetch('https://restcountries.com/v3.1/all?fields=name,cca2,flag,timezones');
                const data = await res.json();
                const formattedCountries = data
                    .map((c: any) => ({
                        code: c.cca2,
                        name: c.name.common,
                        flag: c.flag,
                        timezones: c.timezones || []
                    }))
                    .sort((a: Country, b: Country) => a.name.localeCompare(b.name));
                setCountries(formattedCountries);
            } catch (error) {
                console.error('Failed to fetch countries:', error);
            }
        };
        fetchCountries();
    }, []);

    useEffect(() => {
        fetchPilotData();

        // Poll for updates every 30 seconds to catch rank changes
        const pollInterval = setInterval(() => {
            fetchPilotData();
        }, 30000);

        return () => clearInterval(pollInterval);
    }, []);

    const fetchPilotData = useCallback(async () => {
        try {
            const sessionRes = await fetch('/api/auth/me');
            const sessionData = await sessionRes.json();

            if (!sessionData.user?.pilotId) {
                setLoading(false);
                return;
            }

            const [pilotRes, flightsRes, badgesRes] = await Promise.all([
                fetch(`/api/pilots?id=${sessionData.user.pilotId}`),
                fetch(`/api/portal/reports/recent?pilotId=${sessionData.user.id}`),
                fetch('/api/awards/my'),
            ]);

            const [data, flightsData, badgesData] = await Promise.all([
                pilotRes.json(),
                flightsRes.json(),
                badgesRes.json(),
            ]);

            if (data.pilot) {
                const cloudName = process.env.NEXT_PUBLIC_CLOUDINARY_CLOUD_NAME || '';
                const pilotWithAvatar = {
                    ...data.pilot,
                    avatar_url: `https://res.cloudinary.com/${cloudName}/image/upload/avatars/pilot_${data.pilot.pilot_id}`
                };
                setPilot(pilotWithAvatar);

                const isDeleted = localStorage.getItem(`avatar_deleted_${data.pilot.pilot_id}`);
                if (isDeleted === 'true') {
                    setAvatarError(true);
                } else {
                    const cachedVersion = localStorage.getItem(`avatar_version_${data.pilot.pilot_id}`);
                    if (cachedVersion) {
                        setAvatarTimestamp(parseInt(cachedVersion, 10));
                    }
                }
            }

            if (flightsData.flights) setFlightHistory(flightsData.flights);
            if (Array.isArray(badgesData)) setPilotBadges(badgesData);
        } catch {
            // silent
        } finally {
            setLoading(false);
        }
    }, []);

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            toast.error('Please upload an image file.');
            return;
        }

        setUploadingImage(true);
        const toastId = toast.loading('Uploading profile picture...');

        try {
            await fetch('/api/cloudinary/delete', { method: 'DELETE' });

            const signRes = await fetch('/api/cloudinary/sign', { method: 'POST' });
            const signData = await signRes.json();
            if (!signRes.ok) throw new Error(signData.error || 'Failed to get upload signature');

            const formData = new FormData();
            formData.append('file', file);
            formData.append('api_key', signData.apiKey);
            formData.append('timestamp', signData.timestamp.toString());
            formData.append('signature', signData.signature);
            formData.append('folder', signData.folder);
            formData.append('public_id', signData.publicId);
            formData.append('overwrite', 'true');
            formData.append('invalidate', 'true');

            const cloudRes = await fetch(`https://api.cloudinary.com/v1_1/${signData.cloudName}/image/upload`, {
                method: 'POST',
                body: formData
            });

            const cloudData = await cloudRes.json();
            if (!cloudRes.ok) throw new Error(cloudData.error?.message || 'Cloudinary upload failed');

            const newVersion = cloudData.version || Date.now();
            localStorage.setItem(`avatar_version_${pilot?.pilot_id}`, newVersion.toString());
            localStorage.removeItem(`avatar_deleted_${pilot?.pilot_id}`);
            setAvatarTimestamp(newVersion);
            setAvatarError(false);
            toast.success('Profile picture updated!', { id: toastId });
        } catch (error: any) {
            console.error('Image upload failed:', error);
            toast.error(error.message || 'Failed to update profile picture', { id: toastId });
        } finally {
            setUploadingImage(false);
            if (e.target) e.target.value = '';
        }
    };

    const handleRemoveAvatar = async () => {
        const toastId = toast.loading('Removing profile picture...');

        try {
            const res = await fetch('/api/cloudinary/delete', {
                method: 'DELETE'
            });

            if (res.ok) {
                if (pilot?.pilot_id) {
                    localStorage.setItem(`avatar_deleted_${pilot.pilot_id}`, 'true');
                    localStorage.removeItem(`avatar_version_${pilot.pilot_id}`);
                }
                setAvatarError(true);
                setAvatarTimestamp(Date.now());
                toast.success('Profile picture removed!', { id: toastId });
            } else {
                const data = await res.json();
                throw new Error(data.error || 'Failed to delete from Cloudinary');
            }
        } catch (error: any) {
            console.error('Avatar removal failed:', error);
            toast.error(error.message || 'Failed to remove profile picture', { id: toastId });
        }
    };

    const getFlagUrl = (code: string) => `https://flagcdn.com/32x24/${code.toLowerCase()}.png`;
    const getCountryName = (code: string) => countries.find(c => c.code === code)?.name || code;

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="text-center">
                    <Loader2 className="w-12 h-12 text-amber-500 animate-spin mx-auto mb-4" />
                    <p className="text-gray-400">Loading profile...</p>
                </div>
            </div>
        );
    }

    if (!pilot) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="text-center">
                    <User className="w-16 h-16 text-gray-700 mx-auto mb-4" />
                    <p className="text-red-400">Pilot not found</p>
                </div>
            </div>
        );
    }

    const totalHours = pilot.total_hours + (pilot.transfer_hours || 0);
    const { currentRank, nextRank, progress } = getRankProgress(totalHours);
    const landingQuality = pilot.average_landing === 0 ? 'neutral' : 
                          Math.abs(pilot.average_landing) < 100 ? 'butter' : 
                          Math.abs(pilot.average_landing) < 200 ? 'good' : 'hard';

    const avatarUrl = `https://res.cloudinary.com/${process.env.NEXT_PUBLIC_CLOUDINARY_CLOUD_NAME || ""}/image/upload/c_fill,w_200,h_200,f_auto,q_auto/v${avatarTimestamp}/avatars/pilot_${pilot.pilot_id}`;

    return (
        <div className="max-w-6xl mx-auto space-y-6 pb-8">
            {/* Header Card with Avatar */}
            <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="bg-gradient-to-br from-[#1a1a1a] via-[#141414] to-[#0f0f0f] rounded-2xl border border-white/[0.04] p-6"
            >
                <div className="flex flex-col md:flex-row gap-6 items-start">
                    {/* Avatar */}
                    <div className="relative group flex-shrink-0">
                        <div className="w-24 h-24 rounded-2xl bg-gradient-to-br from-amber-500/20 to-amber-600/10 p-1">
                            <div className="w-full h-full rounded-xl bg-[#0a0a0a] flex items-center justify-center overflow-hidden border-2 border-amber-500/30">
                                {!avatarError ? (
                                    <img 
                                        key={avatarTimestamp}
                                        src={avatarUrl} 
                                        alt="Avatar" 
                                        className="w-full h-full object-cover" 
                                        onError={() => setAvatarError(true)}
                                    />
                                ) : (
                                    <span className="text-3xl font-bold text-amber-500/60">
                                        {pilot.first_name[0]}{pilot.last_name[0]}
                                    </span>
                                )}
                            </div>

                            {/* Upload Overlay */}
                            <div className="absolute inset-0 rounded-2xl bg-black/60 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                {uploadingImage ? (
                                    <Loader2 className="w-6 h-6 text-white animate-spin" />
                                ) : (
                                    <div className="flex flex-col items-center gap-2">
                                        <label className="cursor-pointer hover:scale-110 transition-transform">
                                            <Camera className="w-6 h-6 text-white" />
                                            <input 
                                                type="file" 
                                                className="hidden" 
                                                accept="image/*" 
                                                onChange={handleImageUpload} 
                                                disabled={uploadingImage}
                                            />
                                        </label>
                                        {pilot.avatar_url && (
                                            <button 
                                                onClick={handleRemoveAvatar}
                                                className="hover:scale-110 transition-transform text-red-400"
                                            >
                                                <Trash2 className="w-5 h-5" />
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Status Badge */}
                        <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-2 border-[#1a1a1a] ${
                            pilot.status === 'Active' ? 'bg-emerald-500' : 'bg-gray-600'
                        }`} />
                    </div>

                    {/* Info */}
                    <div className="flex-1">
                        <div className="flex items-start justify-between mb-3">
                            <div>
                                <h1 className="text-2xl font-bold text-white mb-1">
                                    {pilot.first_name} {pilot.last_name}
                                </h1>
                                <div className="flex items-center gap-3 text-sm">
                                    <span className="text-amber-500 font-mono font-bold">{pilot.pilot_id}</span>
                                    <span className={`flex items-center gap-1 ${pilot.status === 'Active' ? 'text-emerald-400' : 'text-gray-500'}`}>
                                        <div className={`w-2 h-2 rounded-full ${pilot.status === 'Active' ? 'bg-emerald-500' : 'bg-gray-600'}`} />
                                        {pilot.status}
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="flex flex-wrap gap-3 text-xs text-gray-400 mb-4">
                            <div className="flex items-center gap-1.5">
                                <Calendar className="w-3.5 h-3.5" />
                                <span>Joined {new Date(pilot.created_at).toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</span>
                            </div>
                            {pilot.country && (
                                <div className="flex items-center gap-1.5">
                                    <MapPin className="w-3.5 h-3.5" />
                                    <img src={getFlagUrl(pilot.country)} alt="" className="w-4 h-3 rounded" />
                                    <span>{getCountryName(pilot.country)}</span>
                                </div>
                            )}
                        </div>

                        {/* Rank Progress */}
                        <div className="bg-[#0a0a0a] rounded-xl p-4 border border-white/[0.04]">
                            <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-2">
                                    <Shield className="w-4 h-4 text-amber-500" />
                                    <span className="text-xs font-semibold text-white">{currentRank.name}</span>
                                </div>
                                <span className="text-xs text-gray-500">Next: {nextRank.name}</span>
                            </div>
                            <div className="relative h-2 bg-black/50 rounded-full overflow-hidden mb-1">
                                <motion.div 
                                    initial={{ width: 0 }}
                                    animate={{ width: `${progress}%` }}
                                    transition={{ duration: 1, ease: "easeOut" }}
                                    className="absolute inset-y-0 left-0 bg-gradient-to-r from-amber-600 to-amber-500 rounded-full"
                                />
                            </div>
                            <div className="flex justify-between text-[10px] text-gray-500">
                                <span>{totalHours.toFixed(1)}h</span>
                                <span>{nextRank.hours}h</span>
                            </div>
                        </div>
                    </div>
                </div>
            </motion.div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[
                    { label: 'Flight Time', value: `${Math.floor(totalHours)}h`, icon: Clock, color: 'text-amber-500', bg: 'bg-amber-500/10' },
                    { label: 'Avg Landing', value: `${Math.abs(pilot.average_landing)} fpm`, icon: TrendingDown, color: landingQuality === 'butter' ? 'text-emerald-400' : 'text-amber-400', bg: landingQuality === 'butter' ? 'bg-emerald-500/10' : 'bg-amber-500/10' },
                    { label: 'Credits', value: pilot.balance >= 1000 ? `${(pilot.balance / 1000).toFixed(1)}K` : pilot.balance.toString(), icon: Zap, color: 'text-green-400', bg: 'bg-green-500/10' },
                    { label: 'Total Flights', value: pilot.total_flights.toString(), icon: Target, color: 'text-blue-400', bg: 'bg-blue-500/10' },
                ].map((stat, i) => (
                    <motion.div
                        key={stat.label}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: i * 0.1 }}
                        className="bg-[#0a0a0a] border border-white/[0.04] rounded-xl p-4 hover:border-white/[0.08] transition-colors"
                    >
                        <div className="flex items-center justify-between mb-2">
                            <span className="text-[10px] uppercase tracking-wider text-gray-500 font-medium">{stat.label}</span>
                            <div className={`w-8 h-8 rounded-lg ${stat.bg} flex items-center justify-center`}>
                                <stat.icon className={`w-4 h-4 ${stat.color}`} />
                            </div>
                        </div>
                        <div className="text-2xl font-bold text-white">{stat.value}</div>
                    </motion.div>
                ))}
            </div>

            {/* Main Content Grid */}
            <div className="grid lg:grid-cols-3 gap-6">
                {/* Left Column - Pilot Details & Badges */}
                <div className="space-y-6">
                    {/* Pilot Details */}
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.3 }}
                        className="bg-[#0a0a0a] border border-white/[0.04] rounded-xl overflow-hidden"
                    >
                        <div className="px-4 py-3 border-b border-white/[0.04] flex items-center gap-2">
                            <User className="w-4 h-4 text-amber-500" />
                            <h2 className="text-sm font-semibold text-white">Pilot Details</h2>
                        </div>
                        <div className="p-4 space-y-3">
                            {[
                                { label: 'Origin', value: pilot.country ? (
                                    <span className="flex items-center gap-2">
                                        <img src={getFlagUrl(pilot.country)} alt="" className="w-4 h-3 rounded" />
                                        {getCountryName(pilot.country)}
                                    </span>
                                ) : 'Not set' },
                                { label: 'IVAO VID', value: pilot.ivao_vid || 'Not Provided', link: pilot.ivao_vid ? `https://www.ivao.aero/Member.aspx?Id=${pilot.ivao_vid}` : null },
                                { label: 'Routes Flown', value: (pilot.routes_flown?.length || 0).toString() },
                            ].map((item, i) => (
                                <div key={i} className="flex justify-between items-center text-xs">
                                    <span className="text-gray-500">{item.label}</span>
                                    {item.link ? (
                                        <a href={item.link} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-colors">
                                            {item.value}
                                        </a>
                                    ) : (
                                        <span className="text-white">{item.value}</span>
                                    )}
                                </div>
                            ))}
                        </div>
                    </motion.div>

                    {/* Badges */}
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.4 }}
                        className="bg-[#0a0a0a] border border-white/[0.04] rounded-xl overflow-hidden"
                    >
                        <div className="px-4 py-3 border-b border-white/[0.04] flex items-center gap-2">
                            <Trophy className="w-4 h-4 text-amber-500" />
                            <h2 className="text-sm font-semibold text-white">Badges</h2>
                            <span className="ml-auto text-xs text-gray-500">{pilotBadges.length}</span>
                        </div>
                        <div className="p-4">
                            {pilotBadges.length > 0 ? (
                                <div className="grid grid-cols-3 gap-2">
                                    {pilotBadges.map((badge) => (
                                        <div 
                                            key={badge._id} 
                                            className="bg-black/30 rounded-lg p-2 flex flex-col items-center border border-white/[0.04] hover:border-amber-500/30 transition-all cursor-pointer group"
                                        >
                                            {badge.award_id?.imageUrl ? (
                                                <img 
                                                    src={`/img/badge/${badge.award_id.imageUrl}`}
                                                    alt={badge.award_id?.name || 'Badge'}
                                                    className="w-10 h-10 object-contain mb-1 group-hover:scale-110 transition-transform"
                                                />
                                            ) : (
                                                <div className="w-10 h-10 bg-amber-500/10 rounded-full flex items-center justify-center mb-1">
                                                    <Medal className="w-5 h-5 text-amber-500" />
                                                </div>
                                            )}
                                            <span className="text-[9px] text-gray-400 text-center truncate w-full">
                                                {badge.award_id?.name || 'Badge'}
                                            </span>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-8">
                                    <Trophy className="w-10 h-10 text-gray-700 mx-auto mb-2" />
                                    <p className="text-gray-500 text-xs">No badges yet</p>
                                </div>
                            )}
                        </div>
                    </motion.div>
                </div>

                {/* Right Column - Recent Flights */}
                <motion.div 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="lg:col-span-2 bg-[#0a0a0a] border border-white/[0.04] rounded-xl overflow-hidden"
                >
                    <div className="px-4 py-3 border-b border-white/[0.04] flex items-center gap-2">
                        <Activity className="w-4 h-4 text-amber-500" />
                        <h2 className="text-sm font-semibold text-white">Recent Flights</h2>
                        <span className="ml-auto text-xs text-gray-500">{flightHistory.length} flights</span>
                    </div>

                    <div className="divide-y divide-white/[0.04]">
                        {flightHistory.length > 0 ? (
                            flightHistory.slice(0, 10).map((flight, i) => (
                                <motion.div
                                    key={flight._id || i}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.3 + i * 0.05 }}
                                    className="p-4 hover:bg-white/[0.02] transition-colors"
                                >
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3 flex-1">
                                            <div className="w-8 h-8 rounded-lg bg-amber-500/10 flex items-center justify-center flex-shrink-0">
                                                <Plane className="w-4 h-4 text-amber-500" />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <span className="text-sm font-mono font-semibold text-amber-500">{flight.departure_icao}</span>
                                                    <ChevronRight className="w-3 h-3 text-gray-600" />
                                                    <span className="text-sm font-mono font-semibold text-amber-500">{flight.arrival_icao}</span>
                                                </div>
                                                <div className="text-xs text-gray-500">
                                                    {flight.aircraft_type || '-'} • {flight.flight_time ? `${Math.floor(flight.flight_time / 60)}:${String(flight.flight_time % 60).padStart(2, '0')}` : '-'}
                                                </div>
                                            </div>
                                        </div>
                                        <span className={`px-2 py-1 rounded-lg text-xs font-medium border ${
                                            flight.status === 'Accepted' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                                            flight.status === 'Rejected' ? 'bg-red-500/10 text-red-400 border-red-500/20' : 
                                            'bg-amber-500/10 text-amber-400 border-amber-500/20'
                                        }`}>
                                            {flight.status === 'Accepted' && <Check className="w-3 h-3 inline mr-1" />}
                                            {flight.status === 'Rejected' && <X className="w-3 h-3 inline mr-1" />}
                                            {flight.status}
                                        </span>
                                    </div>
                                </motion.div>
                            ))
                        ) : (
                            <div className="p-12 text-center">
                                <Plane className="w-12 h-12 text-gray-700 mx-auto mb-3" />
                                <p className="text-gray-500 text-sm">No flights recorded yet</p>
                                <p className="text-gray-600 text-xs mt-1">Complete your first flight to see it here</p>
                            </div>
                        )}
                    </div>
                </motion.div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { 
    Clock, 
    Plane, 
    MapPin, 
    Fuel, 
    Navigation, 
    Users, 
    Package, 
    TrendingUp, 
    ChevronLeft,
    Calendar,
    CheckCircle2,
    XCircle,
    AlertCircle,
    Activity,
    ArrowRight,
    Star
} from 'lucide-react';
import dynamic from 'next/dynamic';
import LandingAnalysis from '@/components/LandingAnalysis';
const FlightAnalysisChart = dynamic(() => import('@/components/FlightAnalysisChart'), { ssr: false });

export default function PirepDetailPage() {
    const params = useParams();
    const id = params?.id;
    const router = useRouter();
    const [rpt, setRpt] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchReport();
    }, [id]);

    const fetchReport = async () => {
        try {
            const res = await fetch(`/api/portal/reports/detail?id=${id}`);
            const data = await res.json();
            if (data.report) {
                setRpt(data.report);
            }
