'use client';

import { useState, useEffect } from 'react';
import { ShoppingBag, CheckCircle, AlertCircle, Package, ArrowRight, Sparkles, Zap, Star, RefreshCw } from 'lucide-react';

interface StoreItem {
    _id: string;
    name: string;
    description: string;
    price: number;
    category: 'Badge' | 'Perk' | 'Skin' | 'Other';
    image?: string;
    download_url?: string;
    active: boolean;
}

export default function StorePage() {
    const [items, setItems] = useState<StoreItem[]>([]);
    const [balance, setBalance] = useState(0);
    const [ownedItems, setOwnedItems] = useState<string[]>([]);
    const [loading, setLoading] = useState(true);
    const [purchasing, setPurchasing] = useState<string | null>(null);
    const [message, setMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
    const [activeTab, setActiveTab] = useState<'all'>('all');

    const fetchStoreData = async () => {
        try {
            const [storeRes, authRes] = await Promise.all([
                fetch('/api/portal/store/fetch'),
                fetch('/api/auth/me')
            ]);

            const storeData = await storeRes.json();
            const authData = await authRes.json();

            if (storeRes.ok) {
                setItems(storeData.items || []);
            }
            if (authRes.ok) {
                setBalance(authData.user?.balance || 0);
                setOwnedItems(authData.user?.inventory || []);
            }
        } catch (error) {
            console.error('Failed to fetch store data:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchStoreData();
    }, []);

    const handlePurchase = async (itemId: string) => {
        setPurchasing(itemId);
        setMessage(null);
        try {
            const res = await fetch('/api/portal/store/purchase', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ itemId }),
            });
            const data = await res.json();
            if (res.ok) {
                setMessage({ text: data.message, type: 'success' });
                setBalance(data.newBalance);
                setOwnedItems([...ownedItems, itemId]);
            } else {
                setMessage({ text: data.error, type: 'error' });
            }
        } catch (error) {
            setMessage({ text: 'Failed to process purchase', type: 'error' });
        } finally {
            setPurchasing(null);
        }
    };

    const getCategoryStyles = (category: string) => {
        switch (category) {
            case 'Badge': return 'from-purple-500/20 to-pink-500/20 text-purple-400 border-purple-500/30';
            case 'Perk': return 'from-emerald-500/20 to-teal-500/20 text-emerald-400 border-emerald-500/30';
            default: return 'from-gray-500/20 to-slate-500/20 text-gray-400 border-gray-500/30';
        }
    };

    const filteredItems = items;

    return (
        <div className="space-y-8 animate-in fade-in duration-700">
            {/* Premium Hero Section */}
            <div className="relative overflow-hidden rounded-3xl bg-[#0a0a0a] border border-white/[0.06] p-8 md:p-12 shadow-2xl">
                {/* Background Decoration */}
                <div className="absolute -top-24 -right-24 w-96 h-96 bg-accent-gold/5 rounded-full blur-[100px] pointer-events-none" />
                <div className="absolute -bottom-24 -left-24 w-96 h-96 bg-primary-500/5 rounded-full blur-[100px] pointer-events-none" />

                <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-8">
                    <div className="text-center md:text-left">
                        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-accent-gold/10 border border-accent-gold/20 mb-4">
                            <Sparkles className="w-3.5 h-3.5 text-accent-gold" />
                            <span className="text-xs font-bold text-accent-gold uppercase tracking-wider">Pilot Store</span>
                        </div>
                        <h1 className="text-4xl md:text-5xl font-black text-white mb-3 tracking-tight">
                            Exclusive Items
                        </h1>
                        <p className="text-gray-400 text-lg max-w-xl">
                            Unlock badges, perks, and exclusive content with your hard-earned credits
                        </p>
                    </div>
                    <button
                        onClick={() => { setLoading(true); fetchStoreData(); }}
                        disabled={loading}
                        className="flex items-center gap-2 px-4 py-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-gray-300 transition-all disabled:opacity-50"
                    >
                        <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                        <span className="text-sm font-bold">Refresh</span>
                    </button>
                    <div className="flex flex-col items-center">
                        <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-6 border border-white/[0.08] shadow-xl flex flex-col items-center min-w-[240px]">
                            <p className="text-gray-500 text-xs font-bold uppercase tracking-widest mb-2">Current Balance</p>
                            <div className="flex items-center gap-3">
                                <span className="text-4xl font-display font-bold text-white tracking-widest leading-none">
                                    {balance.toLocaleString()}
                                </span>
                                <div className="w-8 h-8 rounded-full bg-accent-gold flex items-center justify-center shadow-[0_0_20px_rgba(251,191,36,0.3)]">
                                    <Zap className="w-4 h-4 text-dark-900 fill-current" />
                                </div>
                            </div>
                            <div className="mt-3 text-[10px] text-gray-500 font-mono">Spendable Credits</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Status Messages */}
            <div className="flex flex-wrap items-center justify-end gap-4">
                {message && (
                    <div className={`px-4 py-2.5 rounded-xl border flex items-center gap-3 animate-in fade-in slide-in-from-right-4 duration-300 ${
                        message.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-rose-500/10 border-rose-500/20 text-rose-400'
                    }`}>
                        {message.type === 'success' ? <CheckCircle className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
                        <span className="text-sm font-bold">{message.text}</span>
                    </div>
                )}
            </div>

            {/* Store List */}
            {loading ? (
                <div className="flex flex-col gap-4">
                    {[1, 2, 3].map(i => (
                        <div key={i} className="h-24 rounded-2xl bg-[#0a0a0a] border border-white/[0.06] animate-pulse" />
                    ))}
                </div>
            ) : filteredItems.length === 0 ? (
                <div className="h-48 rounded-3xl border border-dashed border-white/10 flex flex-col items-center justify-center gap-4 text-gray-500">
                    <Package className="w-12 h-12 opacity-20" />
                    <p className="font-medium">No items found in this collection</p>
                </div>
            ) : (
                <div className="flex flex-col gap-4">
                    {filteredItems.map((item) => (
                        <div key={item._id} className="relative group flex items-center p-4 md:p-6 rounded-2xl bg-[#0a0a0a] border border-white/[0.06] hover:border-white/10 transition-all duration-300 shadow-lg">
                            {/* Glow Effect */}
                            <div className={`absolute -inset-0.5 bg-gradient-to-r opacity-0 group-hover:opacity-10 transition-opacity duration-500 pointer-events-none rounded-2xl ${getCategoryStyles(item.category)}`} />

                            <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center gap-6 w-full">
                                {/* Left: Media/Icon */}
                                <div className="flex-shrink-0 w-16 h-16 md:w-20 md:h-20 rounded-xl bg-gradient-to-br from-dark-700/50 to-dark-900/50 flex items-center justify-center relative border border-white/5">
                                    <span className="text-3xl md:text-4xl group-hover:scale-110 transition-transform duration-500 drop-shadow-xl">
                                        {item.category === 'Badge' ? '🎖️' : item.category === 'Perk' ? '⚡' : item.category === 'Skin' ? '🎨' : '📦'}
                                    </span>
                                </div>

                                {/* Middle: Content */}
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-3 mb-1">
                                        <h3 className="text-lg md:text-xl font-bold text-white group-hover:text-accent-gold transition-colors truncate">
                                            {item.name}
                                        </h3>
                                        <span className={`px-2 py-0.5 rounded text-[9px] uppercase font-black tracking-widest border ${getCategoryStyles(item.category)}`}>
                                            {item.category}
                                        </span>
                                    </div>
                                    <p className="text-gray-400 text-xs md:text-sm leading-relaxed max-w-3xl line-clamp-2 md:line-clamp-none">
                                        {item.description}
                                    </p>
                                </div>

                                {/* Right: Price and Action */}
                                <div className="flex items-center gap-6 md:gap-8 w-full md:w-auto mt-4 md:mt-0 pt-4 md:pt-0 border-t md:border-t-0 border-white/[0.06]">
                                    <div className="flex flex-col flex-shrink-0">
                                        <span className="text-gray-500 text-[9px] uppercase font-bold tracking-[0.2em] mb-1">Price</span>
                                        <div className="flex items-center gap-1.5">
                                            <span className="text-xl font-display font-bold text-white font-mono group-hover:text-accent-gold transition-colors">
                                                {item.price.toLocaleString()}
                                            </span>
                                            <Star className="w-3.5 h-3.5 text-accent-gold fill-current" />
                                        </div>
                                    </div>

                                    <div className="flex-shrink-0 ml-auto md:ml-0">
                                        {ownedItems.includes(item._id) ? (
                                            <div className="bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 px-5 py-2.5 rounded-xl flex items-center gap-2 text-xs font-black uppercase tracking-widest">
                                                <CheckCircle className="w-4 h-4 shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
                                                Acquired
                                            </div>
                                        ) : (
                                            <button
                                                onClick={() => handlePurchase(item._id)}
                                                disabled={purchasing === item._id || balance < item.price}
                                                className="relative overflow-hidden group/btn px-6 py-2.5 rounded-xl bg-white text-dark-950 font-black text-xs uppercase tracking-widest hover:bg-accent-gold transition-all duration-300 disabled:opacity-30 disabled:cursor-not-allowed shadow-[0_4px_20px_rgba(255,255,255,0.05)]"
                                            >
                                                <span className="relative z-10 flex items-center gap-2">
                                                    {purchasing === item._id ? 'Processing...' : 'Purchase'}
                                                    {!purchasing && <ArrowRight className="w-3.5 h-3.5 group-hover/btn:translate-x-1 transition-transform" />}
                                                </span>
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { Check, X, Plane, MapPin, AlertCircle, Loader2, Award, Send, CheckCircle, Clock, ArrowLeft, BookOpen } from 'lucide-react';
import Link from 'next/link';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';

export default function TourDetailPage() {
    const params = useParams();
    const router = useRouter();
    const tourId = params?.id as string;
    const [loading, setLoading] = useState(true);
    const [tour, setTour] = useState<any>(null);
    const [userReports, setUserReports] = useState<any[]>([]);
    const [showSubmitModal, setShowSubmitModal] = useState(false);
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [tourRes, reportsRes] = await Promise.all([
                    fetch(`/api/admin/tours?id=${tourId}`),
                    fetch(`/api/portal/tour-reports?tourId=${tourId}`)
                ]);
                const tourData = await tourRes.json();
                const reportsData = await reportsRes.json();

                if (tourData.tours?.[0]) {
                    setTour(tourData.tours[0]);
                }
                setUserReports(reportsData.reports || []);
            } catch (error) {
                console.error("Failed to fetch data", error);
            } finally {
                setLoading(false);
            }
        }

        if (tourId) fetchData();
    }, [tourId]);

    const handleSubmitReport = async () => {
        setSubmitting(true);
        try {
            const res = await fetch('/api/portal/tour-reports', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    tourId: tour._id,
                    legs: tour.legs.map((leg: any, idx: number) => ({
                        leg_number: idx + 1,
                        departure_icao: leg.departure_icao,
                        arrival_icao: leg.arrival_icao,
                    }))
                })
            });

            const data = await res.json();
            if (res.ok) {
                toast.success(`Report submitted! ${data.report.completed_legs}/${data.report.total_legs} legs verified.`);
                setShowSubmitModal(false);
                window.location.reload();
            } else {
                toast.error(data.error || 'Failed to submit report');
            }
        } catch (error) {
            toast.error('Network error');
        } finally {
            setSubmitting(false);
        }
    };

    const latestReport = userReports[0];
    const hasActiveReport = latestReport && ['Pending', 'NeedsModification'].includes(latestReport.status);
    const isCompleted = latestReport?.status === 'Approved';

    if (loading) return (
        <div className="flex h-96 items-center justify-center">
            <Loader2 className="animate-spin w-12 h-12 text-cyan-400" />
        </div>
    );
    if (!tour) return (
        <div className="p-12 text-center text-red-500">Tour not found</div>
    );

    return (
        <div className="space-y-8">
            {/* Back Button */}
            <Link
                href="/portal/tours"
                className="inline-flex items-center gap-2 text-gray-400 hover:text-white transition-colors"
            >
                <ArrowLeft className="w-4 h-4" />
                Back to Tours
            </Link>

            {/* Hero Banner */}
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="relative h-80 rounded-3xl overflow-hidden border-2 border-white/[0.08]"
            >
                {tour.banner || tour.image ? (
                    <img src={tour.banner || tour.image} alt={tour.name} className="w-full h-full object-cover" />
                ) : (
                    <div className="w-full h-full bg-gradient-to-br from-cyan-500/20 to-blue-500/20" />
                )}
                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/60 to-transparent" />
                <div className="absolute bottom-0 left-0 right-0 p-8">
                    <div className="flex items-center gap-3 mb-4">
                        <span className={`px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-wider backdrop-blur-md shadow-lg ${
                            tour.difficulty === 'easy' ? 'bg-green-500/90 text-white' :
                            tour.difficulty === 'hard' ? 'bg-red-500/90 text-white' :
                            'bg-yellow-500/90 text-black'
                        }`}>
                            {tour.difficulty}
                        </span>
                        {isCompleted && (
                            <span className="px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-wider bg-emerald-500/90 text-white backdrop-blur-md shadow-lg flex items-center gap-1">
                                <CheckCircle className="w-3 h-3" />
                                Completed
                            </span>
                        )}
                        {hasActiveReport && (
                            <span className="px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-wider bg-blue-500/90 text-white backdrop-blur-md shadow-lg flex items-center gap-1">
                                <Clock className="w-3 h-3" />
                                {latestReport.status === 'Pending' ? 'Under Review' : 'Needs Changes'}
                            </span>
                        )}
                    </div>
                    <h1 className="text-5xl font-black text-white mb-3">{tour.name}</h1>
                    <p className="text-gray-200 text-lg max-w-3xl">{tour.description}</p>
                </div>
            </motion.div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Sidebar */}
                <div className="space-y-6">
                    {/* Rewards Card */}
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: 0.2 }}
                        className="bg-[#0a0a0a] border-2 border-white/[0.08] rounded-3xl p-6 space-y-6"
                    >
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-yellow-500/20 to-orange-500/20 border border-yellow-500/30 flex items-center justify-center">
                                <Award className="w-5 h-5 text-yellow-400" />
                            </div>
                            <h3 className="text-lg font-bold text-white">Rewards</h3>
                        </div>

                        <div className="space-y-4">
                            <div className="bg-gradient-to-r from-emerald-500/10 to-green-500/10 border border-emerald-500/30 rounded-2xl p-4">
                                <p className="text-xs text-gray-400 uppercase font-semibold mb-2">Credits</p>
                                <p className="text-3xl font-black text-emerald-400">{tour.reward_credits?.toLocaleString()}</p>
                            </div>

                            {tour.award_image && (
                                <div className="bg-white/5 border border-white/[0.08] rounded-2xl p-4 text-center">
                                    <p className="text-xs text-gray-400 uppercase font-semibold mb-3">Award Badge</p>
                                    <img
                                        src={tour.award_image}
                                        alt="Award"
                                        className="w-20 h-20 mx-auto object-contain"
                                    />
                                </div>
                            )}
                        </div>
                    </motion.div>

                    {/* Stats Card */}
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: 0.3 }}
                        className="bg-[#0a0a0a] border-2 border-white/[0.08] rounded-3xl p-6 space-y-4"
                    >
                        <h3 className="text-lg font-bold text-white">Tour Info</h3>
                        <div className="space-y-3">
                            <div className="flex justify-between">
                                <span className="text-gray-400 text-sm">Total Legs</span>
                                <span className="text-white font-bold">{tour.legs?.length || 0}</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-400 text-sm">Distance</span>
                                <span className="text-white font-bold">{tour.total_distance || 0} nm</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-400 text-sm">Difficulty</span>
                                <span className={`font-bold ${
                                    tour.difficulty === 'easy' ? 'text-green-400' :
                                    tour.difficulty === 'hard' ? 'text-red-400' :
                                    'text-yellow-400'
                                }`}>{tour.difficulty.toUpperCase()}</span>
                            </div>
                        </div>
                    </motion.div>

                    {/* Action Button */}
                    {!isCompleted && !hasActiveReport && (
                        <motion.button
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: 0.4 }}
                            onClick={() => setShowSubmitModal(true)}
                            className="w-full py-4 px-6 rounded-2xl font-bold text-base uppercase tracking-wide bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-600 hover:to-blue-600 text-white shadow-xl shadow-cyan-500/20 hover:shadow-2xl hover:shadow-cyan-500/30 transition-all flex items-center justify-center gap-2"
                        >
                            <Send className="w-5 h-5" />
                            Submit Completion
                        </motion.button>
                    )}

                    {/* Rules Link */}
                    <Link
                        href="/portal/tours/rules"
                        className="block text-center py-3 px-4 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-sm text-cyan-400 hover:text-cyan-300 transition-all"
                    >
                        <BookOpen className="w-4 h-4 inline mr-2" />
                        Tour Rules
                    </Link>
                </div>

                {/* Legs List */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="lg:col-span-2 bg-[#0a0a0a] border-2 border-white/[0.08] rounded-3xl p-8"
                >
                    <div className="flex items-center gap-3 mb-8">
                        <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-cyan-500/20 to-blue-500/20 border border-cyan-500/30 flex items-center justify-center">
                            <MapPin className="w-5 h-5 text-cyan-400" />
                        </div>
                        <h3 className="text-2xl font-black text-white">Flight Legs</h3>
                    </div>

                    <div className="space-y-4">
                        {tour.legs.map((leg: any, idx: number) => {
                            const legReport = latestReport?.legs?.find((l: any) => l.leg_number === idx + 1);
                            const isVerified = legReport?.completed && legReport?.flight_id;

                            return (
                                <motion.div
                                    key={idx}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: idx * 0.05 }}
                                    className={`relative p-6 rounded-2xl border-2 transition-all ${
                                        isVerified
                                            ? 'bg-gradient-to-r from-emerald-500/10 to-green-500/10 border-emerald-500/30'
                                            : 'bg-white/[0.02] border-white/[0.08] hover:border-white/[0.15]'
                                    }`}
                                >
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex items-start gap-4 flex-1">
                                            {/* Leg Number */}
                                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-lg shrink-0 ${
                                                isVerified
                                                    ? 'bg-emerald-500/20 border-2 border-emerald-500/40 text-emerald-400'
                                                    : 'bg-white/5 border-2 border-white/10 text-gray-400'
                                            }`}>
                                                {isVerified ? <Check className="w-6 h-6" /> : idx + 1}
                                            </div>

                                            {/* Route Info */}
                                            <div className="flex-1">
                                                <div className="flex items-center gap-3 mb-2">
                                                    <span className="text-2xl font-black font-mono text-white">{leg.departure_icao}</span>
