                                {latestReport.modification_notes && (
                                    <div className="mt-4 pt-4 border-t border-white/10">
                                        <p className="text-xs text-yellow-400 uppercase font-semibold mb-1">Required Changes</p>
                                        <p className="text-white text-sm">{latestReport.modification_notes}</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}
                </motion.div>
            </div>

            {/* Submit Modal */}
            <AnimatePresence>
                {showSubmitModal && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4"
                        onClick={() => setShowSubmitModal(false)}
                    >
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            onClick={(e) => e.stopPropagation()}
                            className="bg-[#0a0a0a] rounded-3xl border-2 border-white/[0.08] p-8 max-w-md w-full"
                        >
                            <h3 className="text-2xl font-black text-white mb-4">Submit Tour Completion</h3>
                            <p className="text-gray-400 mb-6">
                                This will submit your tour for admin validation. The system will automatically verify your flights for each leg.
                            </p>
                            <div className="flex gap-3">
                                <button
                                    onClick={() => setShowSubmitModal(false)}
                                    className="flex-1 py-3 px-6 rounded-xl bg-white/5 hover:bg-white/10 text-white font-semibold transition-all"
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleSubmitReport}
                                    disabled={submitting}
                                    className="flex-1 py-3 px-6 rounded-xl bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-600 hover:to-blue-600 text-white font-bold transition-all disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {submitting ? (
                                        <>
                                            <Loader2 className="w-4 h-4 animate-spin" />
                                            Submitting...
                                        </>
                                    ) : (
                                        <>
                                            <Send className="w-4 h-4" />
                                            Submit
                                        </>
                                    )}
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

'use client';
import { useState, useEffect, useMemo } from 'react';
import Link from 'next/link';
import { Trophy, Map, ArrowRight, Loader2, Award, BookOpen, CheckCircle, Plane, Search } from 'lucide-react';
import { motion } from 'framer-motion';

interface Tour {
    _id: string;
    name: string;
    description: string;
    image?: string;
    banner?: string;
    award_image?: string;
    legs: any[];
    total_distance: number;
    reward_credits: number;
    difficulty: 'easy' | 'medium' | 'hard';
    active: boolean;
    userProgress?: {
        completed: boolean;
        completedLegs: number;
        totalLegs: number;
    };
}

export default function ToursPage() {
    const [tours, setTours] = useState<Tour[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState<'all' | 'active' | 'completed'>('all');
    const [query, setQuery] = useState('');

    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(false);
    const [loadingMore, setLoadingMore] = useState(false);

    const apiStatus = useMemo(() => {
        if (filter === 'active') return 'active';
        if (filter === 'completed') return 'completed';
        return '';
    }, [filter]);

    const fetchTours = async (opts: { page: number; append: boolean }) => {
        const { page: nextPage, append } = opts;
        try {
            const params = new URLSearchParams();
            if (query.trim()) params.set('q', query.trim());
            if (apiStatus) params.set('status', apiStatus);
            params.set('page', String(nextPage));
            params.set('limit', '12');

            const res = await fetch(`/api/portal/tours?${params.toString()}`);
            const data = await res.json();
            const incoming: Tour[] = data.tours || [];

            const total = typeof data.total === 'number' ? data.total : incoming.length;
            const limit = typeof data.limit === 'number' ? data.limit : 12;

            setTours(prev => {
                const nextTours = append ? [...prev, ...incoming] : incoming;
                setHasMore(nextTours.length < total && incoming.length >= limit);
                return nextTours;
            });
        } catch (error) {
            console.error('Failed to fetch tours', error);
        } finally {
            setLoading(false);
            setLoadingMore(false);
        }
    };

    useEffect(() => {
        setLoading(true);
        setPage(1);
        fetchTours({ page: 1, append: false });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [apiStatus]);

    useEffect(() => {
        const t = setTimeout(() => {
            setLoading(true);
            setPage(1);
            fetchTours({ page: 1, append: false });
        }, 300);
        return () => clearTimeout(t);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [query]);

    const handleLoadMore = async () => {
        if (loadingMore || !hasMore) return;
        const next = page + 1;
        setLoadingMore(true);
        setPage(next);
        await fetchTours({ page: next, append: true });
    };

    if (loading) return (
        <div className="flex h-96 items-center justify-center">
            <Loader2 className="animate-spin w-12 h-12 text-cyan-400" />
        </div>
    );

    return (
        <div className="space-y-8">
            {/* Hero Header */}
            <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-cyan-500/10 via-blue-500/10 to-purple-500/10 border border-white/10 p-8">
                <div className="absolute inset-0 bg-[url('/grid.svg')] opacity-10" />
                <div className="relative">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-cyan-500 to-blue-500 flex items-center justify-center shadow-lg shadow-cyan-500/20">
                            <Trophy className="w-7 h-7 text-white" />
                        </div>
                        <div>
                            <h1 className="text-4xl font-black text-white tracking-tight">World Tours</h1>
                            <p className="text-gray-400 text-sm mt-1">Complete multi-leg journeys around the world</p>
                        </div>
                    </div>
                    <Link
                        href="/portal/tours/rules"
                        className="inline-flex items-center gap-2 px-4 py-2 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-sm text-cyan-400 hover:text-cyan-300 transition-all"
                    >
                        <BookOpen className="w-4 h-4" />
                        Read Tour Rules & Guidelines
                    </Link>
                </div>
            </div>

            {/* Filter Tabs */}
            <div className="flex flex-col gap-3">
                <div className="flex gap-2 flex-wrap">
                {[{ key: 'all', label: 'All Tours' }, { key: 'active', label: 'Active' }, { key: 'completed', label: 'Completed' }].map((tab) => (
                    <button
                        key={tab.key}
                        onClick={() => setFilter(tab.key as any)}
                        className={`px-6 py-3 rounded-xl text-sm font-bold uppercase tracking-wider transition-all ${
                            filter === tab.key
