'use client';

import { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { Navigation2, MapPin, Plane } from 'lucide-react';

// Fix for default marker icons
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

const DefaultIcon = L.icon({
    iconUrl: (markerIcon as any).src || markerIcon,
    shadowUrl: (markerShadow as any).src || markerShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

// Dynamic Aircraft Icon - Clean & Flat
const createAircraftIcon = (heading: number, isGlobal?: boolean) => {
    const fill = isGlobal ? '#9ca3af' : '#60a5fa';
    const stroke = isGlobal ? '#6b7280' : '#3b82f6';
    return L.divIcon({
        html: `<svg width="24" height="24" viewBox="0 0 256 256" fill="none"
                style="transform:rotate(${heading}deg);transform-origin:center center;filter:drop-shadow(0 2px 4px rgba(0,0,0,0.5))">
            <path d="M128 24 L140 108 L208 140 L208 156 L140 136 L140 200 L168 220 L168 232 L128 216 L88 232 L88 220 L116 200 L116 136 L48 156 L48 140 L116 108 Z"
                  fill="${fill}" stroke="${stroke}" stroke-width="2" stroke-linejoin="round"/>
        </svg>`,
        className: '',
        iconSize: [24, 24],
        iconAnchor: [12, 12],
        popupAnchor: [0, -12]
    });
};

interface Flight {
    callsign: string;
    pilot: any; // Can be string (IVAO) or object (VA)
    departure: string;
    arrival: string;
    equipment: string;
    latitude: number;
    longitude: number;
    altitude: number;
    heading: number;
    groundSpeed: number;
    ias: number;
    verticalSpeed: number;
    fuel: number;
    phase: string;
    status: string;
    gForce?: number;
    comfort_score?: number;
    isGlobal?: boolean;
    network?: string;
}

export default function DashboardMap({ flights = [] }: { flights?: Flight[] }) {
    const [mounted, setMounted] = useState(false);
    const [mapKey] = useState(() => `map-${Date.now()}`);

    useEffect(() => {
        setMounted(true);
    }, []);

    if (!mounted) {
        return (
            <div className="h-full w-full bg-[#0f0f0f] flex items-center justify-center">
                <div className="text-gray-600 text-xs uppercase tracking-widest animate-pulse">Loading Map...</div>
            </div>
        );
    }

    return (
        <>
            <MapContainer 
            key={mapKey}
            center={[20, 0]} 
            zoom={2} 
            style={{ height: '100%', width: '100%', background: '#0f0f0f' }}
            zoomControl={false}
            attributionControl={false}
            className="z-10"
        >
            <TileLayer
                url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
                attribution='&copy; <a href="https://carto.com/">CARTO</a>'
            />

            {flights
                .filter(flight => 
                    flight && 
                    typeof flight.latitude === 'number' && 
                    typeof flight.longitude === 'number'
                )
                .map((flight, idx) => (
                    <Marker 
                        key={`${flight.callsign}-${idx}`} 
                        position={[flight.latitude, flight.longitude]}
                        icon={createAircraftIcon(Number(flight.heading) || 0, flight.isGlobal)}
                    >
                        <Popup className="custom-popup" offset={[0, -5]}>
                            <div className="bg-[#1a1a1a] rounded-lg border border-gray-800 shadow-2xl overflow-hidden min-w-[260px] text-white">
                                {/* Header */}
                                <div className="bg-[#242424] p-3 border-b border-gray-800 flex justify-between items-center">
                                    <div>
                                        <div className="text-blue-400 font-mono font-bold text-sm leading-tight">{flight.callsign}</div>
                                        <div className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                            {typeof flight.pilot === 'string' ? flight.pilot : `${flight.pilot?.first_name} ${flight.pilot?.last_name}`}
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-1.5">
                                        {flight.network && flight.network !== 'LVT' && (
                                            <div className="px-1.5 py-0.5 bg-indigo-500/20 rounded text-[8px] font-bold text-indigo-400 border border-indigo-500/30">
                                                {flight.network}
                                            </div>
                                        )}
                                        <div className="px-2 py-0.5 bg-gray-800 rounded text-[9px] font-mono font-bold text-gray-400 border border-gray-700">
                                            {flight.equipment}
                                        </div>
                                    </div>
                                </div>

                                <div className="p-4 space-y-4">
                                    {/* Route */}
                                    <div className="flex items-center justify-between text-center gap-4">
                                        <div className="flex-1">
                                            <div className="text-[8px] text-gray-600 uppercase font-bold tracking-widest mb-1">Departure</div>
                                            <div className="text-sm font-bold font-mono">{flight.departure}</div>
                                        </div>
                                        <Plane size={14} className="text-gray-700" />
                                        <div className="flex-1">
                                            <div className="text-[8px] text-gray-600 uppercase font-bold tracking-widest mb-1">Arrival</div>
                                            <div className="text-sm font-bold font-mono">{flight.arrival}</div>
                                        </div>
                                    </div>

                                    {/* Phase Badge */}
                                    {flight.phase && (
                                        <div className="flex justify-center">
                                            <span className={`text-[8px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full border ${
                                                flight.phase === 'Cruise' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                                                flight.phase === 'Descent' || flight.phase === 'Approach' ? 'bg-orange-500/10 text-orange-400 border-orange-500/20' :
                                                flight.phase === 'Climb' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                                                'bg-gray-500/10 text-gray-400 border-gray-500/20'
                                            }`}>{flight.phase}</span>
                                        </div>
                                    )}

                                    {/* Stats Grid */}
                                    <div className="grid grid-cols-3 gap-2 bg-black/40 p-2.5 rounded-lg border border-gray-800/50">
                                        <div className="text-center">
                                            <div className="text-[7px] text-gray-500 uppercase font-bold mb-1">ALT</div>
                                            <div className="text-[10px] font-mono font-bold">{Math.round(flight.altitude || 0).toLocaleString()}<span className="text-[7px] text-gray-600">ft</span></div>
                                        </div>
                                        <div className="text-center border-x border-gray-800/50">
                                            <div className="text-[7px] text-gray-500 uppercase font-bold mb-1">GS</div>
                                            <div className="text-[10px] font-mono font-bold">{Math.round(flight.groundSpeed || 0)} <span className="text-[7px] text-gray-600">KTS</span></div>
                                        </div>
                                        <div className="text-center">
                                            <div className="text-[7px] text-gray-500 uppercase font-bold mb-1">V/S</div>
                                            <div className={`text-[10px] font-mono font-bold ${(flight.verticalSpeed || 0) > 0 ? 'text-emerald-500' : (flight.verticalSpeed || 0) < 0 ? 'text-rose-500' : 'text-gray-400'}`}>
                                                {(flight.verticalSpeed || 0) > 0 ? '+' : ''}{Math.round(flight.verticalSpeed || 0)}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Secondary Stats */}
                                    <div className="grid grid-cols-3 gap-2 text-center">
                                        <div>
                                            <div className="text-[7px] text-gray-600 uppercase font-bold">IAS</div>
                                            <div className="text-[9px] font-mono text-gray-400">{Math.round(flight.ias || 0)} kt</div>
                                        </div>
                                        <div>
                                            <div className="text-[7px] text-gray-600 uppercase font-bold">HDG</div>
                                            <div className="text-[9px] font-mono text-gray-400">{Math.round(flight.heading || 0)}°</div>
                                        </div>
                                        <div>
                                            <div className="text-[7px] text-gray-600 uppercase font-bold">FUEL</div>
                                            <div className="text-[9px] font-mono text-gray-400">{flight.fuel ? `${Math.round(flight.fuel)}lb` : '—'}</div>
                                        </div>
                                    </div>

                                    {/* Passenger Comfort */}
                                    {!flight.isGlobal && (
                                        <div className="pt-2 border-t border-gray-800/50">
                                            <div className="flex justify-between items-center mb-1.5 px-0.5">
                                                <div className="text-[8px] font-bold text-gray-600 uppercase tracking-widest">Pax Satisfaction</div>
                                                <div className={`text-[10px] font-mono font-bold ${(!flight.comfort_score || flight.comfort_score > 70) ? 'text-emerald-400' : 'text-rose-400'}`}>
                                                    {flight.comfort_score ?? 100}%
                                                </div>
                                            </div>
                                            <div className="h-1 w-full bg-black/60 rounded-full overflow-hidden">
                                                <div 
                                                    className={`h-full transition-all duration-700 ${(!flight.comfort_score || flight.comfort_score > 70) ? 'bg-emerald-500' : 'bg-rose-500'}`}
                                                    style={{ width: `${flight.comfort_score ?? 100}%` }}
                                                />
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </Popup>
                    </Marker>
                ))}
        </MapContainer>
        <style jsx global>{`
            .custom-popup .leaflet-popup-content-wrapper {
                background: transparent !important;
                padding: 0 !important;
                border: none !important;
                box-shadow: none !important;
            }
            .custom-popup .leaflet-popup-tip {
                background: #1f2937 !important;
                opacity: 0.8 !important;
            }
        `}</style>
        </>
    );
}

import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { Activity, CheckCircle, AlertCircle, RefreshCcw } from 'lucide-react';

interface DeployLog {
  _id: string;
  version: string;
  deployedAt: string;
  status: string;
  commitMessage: string;
  environment: string;
}

export const DeploymentHistory = () => {
  const [logs, setLogs] = useState<DeployLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [stableVersion, setStableVersion] = useState('');

  const fetchLogs = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/admin/deploy-logs');
      const data = await res.json();
      setLogs(data.logs || []);
      setStableVersion(data.stableVersion);
    } catch (err) {
      console.error('Failed to fetch deploy logs:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleSetStable = async (version: string) => {
    try {
      const res = await fetch('/api/admin/set-stable', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ version })
      });
      if (res.ok) {
        setStableVersion(version);
        alert(`Version ${version} is now marked as STABLE.`);
      }
    } catch (err) {
      console.error('Failed to set stable version:', err);
    }
  };

  useEffect(() => {
    fetchLogs();
  }, []);

  return (
    <div className="glass-card p-6 rounded-2xl border border-white/[0.08] backdrop-blur-md overflow-hidden bg-black/20">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-xl font-bold flex items-center gap-2 text-white">
          <Activity size={20} className="text-accent-gold" />
          System Deployment History
        </h3>
        <button 
          onClick={fetchLogs}
          disabled={loading}
          className="p-2 hover:bg-white/10 rounded-full transition-colors text-gray-400 hover:text-white disabled:opacity-50"
        >
          <RefreshCcw size={16} className={loading ? 'animate-spin' : ''} />
        </button>
      </div>

      <div className="overflow-x-auto custom-scrollbar">
        <table className="w-full text-left text-sm">
          <thead className="text-gray-400 border-b border-white/[0.06] uppercase tracking-widest text-[10px]">
            <tr>
              <th className="pb-3 font-medium">Version</th>
              <th className="pb-3 font-medium">Changes / Commit</th>
              <th className="pb-3 font-medium">Timestamp</th>
              <th className="pb-3 font-medium text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/5">
            {logs.length === 0 && !loading && (
              <tr>
                <td colSpan={4} className="py-10 text-center text-gray-500 italic text-xs">
                  No deployment logs found in database.
                </td>
              </tr>
            )}
            {logs.map((log, index) => (
              <tr key={log._id} className="hover:bg-white/5 transition-colors group">
                <td className="py-4">
                  <div className="flex items-center gap-2">
                    <span className={`px-2 py-1 rounded text-xs font-mono font-bold ${
                      log.version === stableVersion 
                      ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' 
                      : 'bg-white/5 text-gray-400 border border-transparent'
                    }`}>
                      {log.version}
                    </span>
                    {log.version === stableVersion && (
                      <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
                    )}
                  </div>
                </td>
                <td className="py-4 text-gray-300 max-w-xs truncate font-medium">
                  {log.commitMessage || 'Automated build'}
                </td>
                <td className="py-4 text-gray-500 font-mono text-[11px]">
                  {format(new Date(log.deployedAt), 'MMM dd, HH:mm:ss')}
                </td>
                <td className="py-4 text-right">
                  {log.version !== stableVersion ? (
                    <button 
                      onClick={() => handleSetStable(log.version)}
                      className="text-[10px] uppercase tracking-wider font-bold px-3 py-1.5 rounded-lg bg-accent-gold/10 text-accent-gold border border-accent-gold/20 hover:bg-accent-gold hover:text-black transition-all opacity-0 group-hover:opacity-100"
                    >
                      Set Stable
                    </button>
                  ) : (
                    <div className="flex items-center justify-end gap-1.5 text-emerald-400/60 font-bold uppercase text-[10px] tracking-widest">
                      <CheckCircle size={10} />
                      Current Stable
                    </div>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {loading && (
        <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px] flex items-center justify-center">
            <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 border-2 border-accent-gold/30 border-t-accent-gold rounded-full animate-spin" />
                <span className="text-[10px] text-accent-gold font-bold uppercase tracking-widest">Fetching Logs...</span>
            </div>
        </div>
      )}
    </div>
  );
};

/**
 * Flight Analysis Button Component
 * Trigger to view post-flight debriefing from PIREP pages
 */

'use client';

import { useState } from 'react';
import PostFlightDebriefing from './PostFlightDebriefing';
import type { FlightAnalysisReport, FlightChartData } from '@/types/flightAnalysis';

interface FlightAnalysisButtonProps {
    flightId: string;
    variant?: 'primary' | 'secondary' | 'outline';
    size?: 'sm' | 'md' | 'lg';
    className?: string;
}

export default function FlightAnalysisButton({
    flightId,
    variant = 'primary',
    size = 'md',
    className = '',
}: FlightAnalysisButtonProps) {
    const [isLoading, setIsLoading] = useState(false);
    const [showDebriefing, setShowDebriefing] = useState(false);
    const [report, setReport] = useState<FlightAnalysisReport | null>(null);
    const [chartData, setChartData] = useState<FlightChartData | null>(null);
    const [error, setError] = useState<string | null>(null);

    const loadAnalysis = async () => {
        setIsLoading(true);
        setError(null);

        try {
            const response = await fetch(`/api/flight-analysis/${flightId}`);
            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.error || 'Failed to load flight analysis');
            }

            setReport(data.report);
            setChartData(data.chartData);
            setShowDebriefing(true);
        } catch (err: any) {
            console.error('Error loading flight analysis:', err);
            setError(err.message);
            alert(`Error: ${err.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    const variantClasses = {
        primary: 'bg-blue-600 hover:bg-blue-700 text-white',
        secondary: 'bg-gray-600 hover:bg-gray-700 text-white',
        outline: 'border-2 border-blue-600 text-blue-600 hover:bg-blue-50',
    };

    const sizeClasses = {
        sm: 'px-3 py-1.5 text-sm',
        md: 'px-4 py-2 text-base',
        lg: 'px-6 py-3 text-lg',
    };

    return (
        <>
            <button
                onClick={loadAnalysis}
                disabled={isLoading}
                className={`
                    ${variantClasses[variant]}
                    ${sizeClasses[size]}
                    ${className}
                    rounded-lg font-medium transition-colors
                    disabled:opacity-50 disabled:cursor-not-allowed
                    flex items-center gap-2
                `}
            >
                {isLoading ? (
                    <>
                        <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                            <circle
                                className="opacity-25"
                                cx="12"
                                cy="12"
                                r="10"
                                stroke="currentColor"
                                strokeWidth="4"
                                fill="none"
                            />
                            <path
                                className="opacity-75"
                                fill="currentColor"
                                d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                            />
                        </svg>
                        <span>Loading Analysis...</span>
                    </>
                ) : (
                    <>
                        <svg
                            className="w-5 h-5"
                            fill="none"
                            stroke="currentColor"
                            viewBox="0 0 24 24"
                        >
                            <path
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeWidth={2}
                                d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"
                            />
                        </svg>
                        <span>View Flight Analysis</span>
                    </>
                )}
            </button>

            {showDebriefing && report && chartData && (
                <PostFlightDebriefing
                    flightId={flightId}
                    report={report}
                    chartData={chartData}
                    onClose={() => setShowDebriefing(false)}
                />
            )}
        </>
    );
}

'use client';

import React from 'react';
import {
