                        <p className="text-[10px] text-gray-500 font-bold uppercase tracking-[0.2em] mt-1">Full Mission Reconstruction</p>
                    </div>

                    <div className="flex gap-6">
                        <ChartLegend color="#d4af37" label="Alt (FT)" />
                        <ChartLegend color="#34d399" label="Speed (KTS)" />
                        <ChartLegend color="#fb7185" label="V/S (FPM)" />
                    </div>
                </div>

                <div className="h-[450px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                            <defs>
                                <linearGradient id="colorAlt" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#d4af37" stopOpacity={0.2}/>
                                    <stop offset="95%" stopColor="#d4af37" stopOpacity={0}/>
                                </linearGradient>
                                <linearGradient id="colorGs" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#34d399" stopOpacity={0.2}/>
                                    <stop offset="95%" stopColor="#34d399" stopOpacity={0}/>
                                </linearGradient>
                                <linearGradient id="colorVs" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#fb7185" stopOpacity={0.2}/>
                                    <stop offset="95%" stopColor="#fb7185" stopOpacity={0}/>
                                </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" stroke="#ffffff05" vertical={false} />
                            <XAxis 
                                dataKey="timestamp"
                                stroke="#ffffff15"
                                fontSize={9}
                                tickFormatter={(val) => {
                                    const d = new Date(val);
                                    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false });
                                }}
                                axisLine={false}
                                tickLine={false}
                                minTickGap={60}
                            />
                            <YAxis 
                                yAxisId="left"
                                stroke="#ffffff20" 
                                fontSize={10}
                                tickFormatter={(val) => `${val}ft`}
                                width={60}
                                axisLine={false}
                                tickLine={false}
                            />
                            <YAxis 
                                yAxisId="right"
                                orientation="right"
                                stroke="#ffffff20" 
                                fontSize={10}
                                tickFormatter={(val) => `${val}kts`}
                                width={60}
                                axisLine={false}
                                tickLine={false}
                            />
                            <Tooltip content={<CustomTooltip />} />
                            <Area 
                                yAxisId="left"
                                type="monotone" 
                                dataKey="altitude" 
                                name="Altitude" 
                                unit="ft"
                                stroke="#d4af37" 
                                strokeWidth={3}
                                fillOpacity={1} 
                                fill="url(#colorAlt)"
                                activeDot={{ r: 5, stroke: '#d4af37', strokeWidth: 2, fill: '#000' }}
                            />
                            <Area 
                                yAxisId="right"
                                type="monotone" 
                                dataKey="speed" 
                                name="Ground Speed" 
                                unit="kts"
                                stroke="#34d399" 
                                strokeWidth={2}
                                strokeDasharray="5 5"
                                fillOpacity={1} 
                                fill="url(#colorGs)"
                                activeDot={{ r: 5, stroke: '#34d399', strokeWidth: 2, fill: '#000' }}
                            />
                            <Area 
                                yAxisId="right"
                                type="monotone" 
                                dataKey="vs" 
                                name="Vertical Speed" 
                                unit="fpm"
                                stroke="#fb7185" 
                                strokeWidth={2}
                                fillOpacity={1} 
                                fill="url(#colorVs)"
                                activeDot={{ r: 5, stroke: '#fb7185', strokeWidth: 2, fill: '#000' }}
