/**
 * Flight Phase Detection - Finite State Machine
 * High-fidelity phase detection based on telemetry data
 */

import { FlightPhase } from '@/types/flight';
import type { Telemetry } from '@/types/flight';

// ============================================================================
// PHASE DETECTION THRESHOLDS
// ============================================================================

const THRESHOLDS = {
    TAXI_SPEED: 30,              // knots
    TAKEOFF_SPEED: 80,           // knots
    CLIMB_VS_MIN: 300,           // fpm
    CRUISE_VS_RANGE: 200,        // fpm (+/- range)
    DESCENT_VS_MAX: -300,        // fpm
    APPROACH_ALT: 3000,          // feet AGL
    LANDING_SPEED: 60,           // knots
    GROUND_SPEED: 40,            // knots (considered on ground)
    MIN_FLIGHT_ALT: 100,         // feet AGL
};

// ============================================================================
// PHASE TRANSITION CONDITIONS
// ============================================================================

interface PhaseConditions {
    altitude: number;
    groundSpeed: number;
    verticalSpeed: number;
    indicatedAirspeed: number;
    onGround: boolean;
    engineRunning: boolean;
}

export class FlightPhaseFSM {
    private currentPhase: FlightPhase = FlightPhase.PREFLIGHT;
    private previousPhase: FlightPhase = FlightPhase.PREFLIGHT;
    private phaseStartTime: Date = new Date();
    private phaseHistory: Array<{ phase: FlightPhase; timestamp: Date; duration: number }> = [];
    private departureAltitude: number = 0;
    private cruiseAltitude: number = 0;

    constructor(initialPhase: FlightPhase = FlightPhase.PREFLIGHT) {
        this.currentPhase = initialPhase;
        this.phaseStartTime = new Date();
    }

    /**
     * Update phase based on current telemetry
     */
    update(telemetry: Telemetry, conditions: Partial<PhaseConditions> = {}): {
        phase: FlightPhase;
        changed: boolean;
        duration: number;
    } {
        const cond: PhaseConditions = {
            altitude: telemetry.alt,
            groundSpeed: telemetry.groundspeed || 0,
            verticalSpeed: telemetry.v_speed,
            indicatedAirspeed: telemetry.ias || 0,
            onGround: this.isOnGround(telemetry),
            engineRunning: conditions.engineRunning ?? true,
        };

        const newPhase = this.detectPhase(cond);
        const changed = newPhase !== this.currentPhase;

        if (changed) {
            this.transitionTo(newPhase);
        }

        const duration = Date.now() - this.phaseStartTime.getTime();

        return {
            phase: this.currentPhase,
            changed,
            duration: Math.floor(duration / 1000), // seconds
        };
    }

    /**
     * Core FSM logic - determines next phase
     */
    private detectPhase(cond: PhaseConditions): FlightPhase {
        const { altitude, groundSpeed, verticalSpeed, indicatedAirspeed, onGround } = cond;

        switch (this.currentPhase) {
            case FlightPhase.PREFLIGHT:
                // PREFLIGHT -> TAXI_OUT
                if (onGround && groundSpeed > 5 && groundSpeed < THRESHOLDS.TAXI_SPEED) {
                    return FlightPhase.TAXI_OUT;
                }
                break;

            case FlightPhase.TAXI_OUT:
                // TAXI_OUT -> TAKEOFF
                if (groundSpeed > THRESHOLDS.TAKEOFF_SPEED && verticalSpeed > 100) {
                    this.departureAltitude = altitude;
                    return FlightPhase.TAKEOFF;
                }
                // TAXI_OUT -> PREFLIGHT (abort)
                if (groundSpeed < 5) {
                    return FlightPhase.PREFLIGHT;
                }
                break;

            case FlightPhase.TAKEOFF:
                // TAKEOFF -> CLIMB
                if (altitude - this.departureAltitude > THRESHOLDS.MIN_FLIGHT_ALT && 
                    verticalSpeed > THRESHOLDS.CLIMB_VS_MIN) {
                    return FlightPhase.CLIMB;
                }
                break;

            case FlightPhase.CLIMB:
                // CLIMB -> CRUISE
                if (Math.abs(verticalSpeed) < THRESHOLDS.CRUISE_VS_RANGE) {
                    this.cruiseAltitude = altitude;
                    return FlightPhase.CRUISE;
                }
                break;

            case FlightPhase.CRUISE:
                // CRUISE -> DESCENT
                if (verticalSpeed < THRESHOLDS.DESCENT_VS_MAX) {
                    return FlightPhase.DESCENT;
                }
                // CRUISE -> CLIMB (step climb)
                if (verticalSpeed > THRESHOLDS.CLIMB_VS_MIN && altitude > this.cruiseAltitude + 1000) {
                    return FlightPhase.CLIMB;
                }
                break;

            case FlightPhase.DESCENT:
                // DESCENT -> APPROACH
                if (altitude - this.departureAltitude < THRESHOLDS.APPROACH_ALT) {
                    return FlightPhase.APPROACH;
                }
                // DESCENT -> CRUISE (level off)
                if (Math.abs(verticalSpeed) < THRESHOLDS.CRUISE_VS_RANGE) {
                    return FlightPhase.CRUISE;
                }
                break;

            case FlightPhase.APPROACH:
                // APPROACH -> LANDING
                if (altitude - this.departureAltitude < 500 && verticalSpeed < -100) {
                    return FlightPhase.LANDING;
                }
                break;

            case FlightPhase.LANDING:
                // LANDING -> TAXI_IN
                if (onGround && groundSpeed < THRESHOLDS.LANDING_SPEED && groundSpeed > 5) {
                    return FlightPhase.TAXI_IN;
                }
                // LANDING -> ARRIVED
                if (onGround && groundSpeed < 5) {
                    return FlightPhase.ARRIVED;
                }
                break;

            case FlightPhase.TAXI_IN:
                // TAXI_IN -> ARRIVED
                if (groundSpeed < 5) {
                    return FlightPhase.ARRIVED;
                }
                break;

            case FlightPhase.ARRIVED:
                // Terminal state
                break;

            case FlightPhase.CANCELLED:
                // Terminal state
                break;
        }

        return this.currentPhase;
    }

    /**
     * Transition to new phase
     */
    private transitionTo(newPhase: FlightPhase): void {
        const now = new Date();
        const duration = now.getTime() - this.phaseStartTime.getTime();

        // Record phase history
        this.phaseHistory.push({
            phase: this.currentPhase,
            timestamp: this.phaseStartTime,
            duration: Math.floor(duration / 1000),
        });

        this.previousPhase = this.currentPhase;
        this.currentPhase = newPhase;
        this.phaseStartTime = now;

        console.log(`[FSM] Phase transition: ${this.previousPhase} -> ${newPhase}`);
    }

    /**
     * Determine if aircraft is on ground
     */
    private isOnGround(telemetry: Telemetry): boolean {
        const groundSpeed = telemetry.groundspeed || 0;
        const altitude = telemetry.alt;
        const verticalSpeed = telemetry.v_speed;

        // On ground if:
        // - Low altitude AND low vertical speed
        // - OR very low ground speed
        return (
            (altitude < this.departureAltitude + 50 && Math.abs(verticalSpeed) < 50) ||
            groundSpeed < THRESHOLDS.GROUND_SPEED
        );
    }

    /**
     * Get current phase
     */
    getCurrentPhase(): FlightPhase {
        return this.currentPhase;
    }

    /**
     * Get phase history
     */
    getPhaseHistory(): Array<{ phase: FlightPhase; timestamp: Date; duration: number }> {
        return [...this.phaseHistory];
    }

    /**
     * Get time in current phase (seconds)
     */
    getTimeInPhase(): number {
        return Math.floor((Date.now() - this.phaseStartTime.getTime()) / 1000);
    }

    /**
     * Reset FSM
     */
    reset(): void {
        this.currentPhase = FlightPhase.PREFLIGHT;
        this.previousPhase = FlightPhase.PREFLIGHT;
        this.phaseStartTime = new Date();
        this.phaseHistory = [];
        this.departureAltitude = 0;
        this.cruiseAltitude = 0;
    }

    /**
     * Force phase (for testing or manual override)
     */
    forcePhase(phase: FlightPhase): void {
        this.transitionTo(phase);
    }
}

/**
 * Helper function to get phase display name
 */
export function getPhaseDisplayName(phase: FlightPhase): string {
    const names: Record<FlightPhase, string> = {
        [FlightPhase.PREFLIGHT]: 'Pre-Flight',
        [FlightPhase.TAXI_OUT]: 'Taxi Out',
        [FlightPhase.TAKEOFF]: 'Takeoff',
        [FlightPhase.CLIMB]: 'Climb',
        [FlightPhase.CRUISE]: 'Cruise',
        [FlightPhase.DESCENT]: 'Descent',
        [FlightPhase.APPROACH]: 'Approach',
        [FlightPhase.LANDING]: 'Landing',
        [FlightPhase.TAXI_IN]: 'Taxi In',
        [FlightPhase.ARRIVED]: 'Arrived',
        [FlightPhase.CANCELLED]: 'Cancelled',
    };
    return names[phase] || phase;
}

/**
 * Get phase color for UI
 */
export function getPhaseColor(phase: FlightPhase): string {
    const colors: Record<FlightPhase, string> = {
        [FlightPhase.PREFLIGHT]: '#6B7280',
        [FlightPhase.TAXI_OUT]: '#F59E0B',
        [FlightPhase.TAKEOFF]: '#EF4444',
        [FlightPhase.CLIMB]: '#10B981',
        [FlightPhase.CRUISE]: '#3B82F6',
        [FlightPhase.DESCENT]: '#8B5CF6',
        [FlightPhase.APPROACH]: '#EC4899',
        [FlightPhase.LANDING]: '#F97316',
        [FlightPhase.TAXI_IN]: '#F59E0B',
        [FlightPhase.ARRIVED]: '#10B981',
        [FlightPhase.CANCELLED]: '#EF4444',
    };
    return colors[phase] || '#6B7280';
}

/**
 * Flight Scoring System
 * Deducts points for violations and poor performance
 * Now configurable via VA Settings
 */

import type { Telemetry, FlightPhase } from '@/types/flight';
import type { OperationalLimits, ScoringWeights } from '@/types/settings';
import { DEFAULT_VA_SETTINGS } from '@/types/settings';

// ============================================================================
// VIOLATION TYPES
// ============================================================================

export interface Violation {
    type: ViolationType;
    timestamp: Date;
    severity: 'minor' | 'moderate' | 'severe';
    penalty: number;
    details: string;
    telemetry?: Partial<Telemetry>;
}

export enum ViolationType {
    EXCESSIVE_G_LOAD = 'excessive_g_load',
    LOW_G_LOAD = 'low_g_load',
    OVERSPEED = 'overspeed',
    TAXI_OVERSPEED = 'taxi_overspeed',
    HARD_LANDING = 'hard_landing',
    FLAP_OVERSPEED = 'flap_overspeed',
    GEAR_OVERSPEED = 'gear_overspeed',
    STRUCTURAL_STRESS = 'structural_stress',
}

// ============================================================================
// FLIGHT SCORING ENGINE
// ============================================================================

export class FlightScoringEngine {
    private score: number = 100;
    private violations: Violation[] = [];
    private gForceHistory: number[] = [];
    private maxGForce: number = 1.0;
    private minGForce: number = 1.0;
    private landingRate: number = 0;

    // Dynamic configuration from VA Settings
    private limits: OperationalLimits;
    private weights: ScoringWeights;

    constructor(
        limits?: OperationalLimits,
        weights?: ScoringWeights,
        initialScore: number = 100
    ) {
        this.limits = limits || DEFAULT_VA_SETTINGS.operational_limits;
        this.weights = weights || DEFAULT_VA_SETTINGS.scoring_weights;
        this.score = initialScore;
    }

    /**
     * Update scoring based on current telemetry
     */
    update(telemetry: Telemetry, phase: FlightPhase, aircraftData?: {
        vmo?: number;
        flapExtended?: boolean;
        gearExtended?: boolean;
        gForce?: number;
    }): void {
        const gForce = aircraftData?.gForce || this.estimateGForce(telemetry);
        this.gForceHistory.push(gForce);

        // Track extremes
        this.maxGForce = Math.max(this.maxGForce, gForce);
        this.minGForce = Math.min(this.minGForce, gForce);

        // Check G-Force violations
        this.checkGForce(gForce, telemetry);

        // Check speed violations
        this.checkSpeed(telemetry, phase, aircraftData);

        // Check landing
        if (phase === 'landing') {
            this.checkLanding(telemetry);
        }
    }

    /**
     * Check G-Force limits
     */
    private checkGForce(gForce: number, telemetry: Telemetry): void {
        if (gForce > this.limits.g_force_limits.max) {
            this.addViolation({
                type: ViolationType.EXCESSIVE_G_LOAD,
                timestamp: new Date(),
                severity: gForce > this.limits.g_force_limits.structural_warning ? 'severe' : 'moderate',
                penalty: this.weights.penalty_excessive_g,
                details: `Excessive G-load: ${gForce.toFixed(2)}G (max: ${this.limits.g_force_limits.max}G)`,
                telemetry,
            });
        }

        if (gForce < this.limits.g_force_limits.min && gForce > 0) {
            this.addViolation({
                type: ViolationType.LOW_G_LOAD,
                timestamp: new Date(),
                severity: 'minor',
                penalty: this.weights.penalty_low_g,
                details: `Low G-load: ${gForce.toFixed(2)}G (min: ${this.limits.g_force_limits.min}G)`,
                telemetry,
            });
        }

        // Structural stress warning
        if (gForce > this.limits.g_force_limits.structural_warning) {
            this.addViolation({
                type: ViolationType.STRUCTURAL_STRESS,
                timestamp: new Date(),
                severity: 'severe',
                penalty: this.weights.penalty_structural_stress,
                details: `STRUCTURAL STRESS WARNING: ${gForce.toFixed(2)}G - Risk of airframe damage`,
                telemetry,
            });
        }
    }

    /**
     * Check speed violations
     */
    private checkSpeed(
        telemetry: Telemetry,
        phase: FlightPhase,
        aircraftData?: {
            vmo?: number;
            flapExtended?: boolean;
            gearExtended?: boolean;
        }
    ): void {
        const ias = telemetry.ias || telemetry.groundspeed || 0;
        const groundSpeed = telemetry.groundspeed || 0;
        const vmo = aircraftData?.vmo || 350; // Default VMO

        // Taxi overspeed
        if ((phase === 'taxi_out' || phase === 'taxi_in') && groundSpeed > this.limits.max_taxi_speed) {
            this.addViolation({
                type: ViolationType.TAXI_OVERSPEED,
                timestamp: new Date(),
                severity: 'minor',
                penalty: this.weights.penalty_taxi_overspeed,
                details: `Taxi overspeed: ${groundSpeed.toFixed(0)} kts (max: ${this.limits.max_taxi_speed} kts)`,
                telemetry,
            });
        }

        // VMO overspeed (with configurable buffer)
        const overspeedThreshold = vmo + this.limits.overspeed_buffer;
        if (ias > overspeedThreshold) {
            this.addViolation({
                type: ViolationType.OVERSPEED,
                timestamp: new Date(),
                severity: ias > overspeedThreshold + 20 ? 'severe' : 'moderate',
                penalty: this.weights.penalty_overspeed,
                details: `OVERSPEED: ${ias.toFixed(0)} kts (VMO+buffer: ${overspeedThreshold} kts)`,
                telemetry,
            });
        }

        // Flap overspeed
        if (aircraftData?.flapExtended && ias > this.limits.flap_overspeed) {
            this.addViolation({
                type: ViolationType.FLAP_OVERSPEED,
                timestamp: new Date(),
                severity: 'moderate',
                penalty: this.weights.penalty_flap_overspeed,
                details: `Flap overspeed: ${ias.toFixed(0)} kts (max: ${this.limits.flap_overspeed} kts)`,
                telemetry,
            });
        }

        // Gear overspeed
        if (aircraftData?.gearExtended && ias > this.limits.gear_overspeed) {
            this.addViolation({
                type: ViolationType.GEAR_OVERSPEED,
                timestamp: new Date(),
                severity: 'moderate',
                penalty: this.weights.penalty_gear_overspeed,
                details: `Gear overspeed: ${ias.toFixed(0)} kts (max: ${this.limits.gear_overspeed} kts)`,
                telemetry,
            });
        }
    }

    /**
     * Check landing performance
     */
    private checkLanding(telemetry: Telemetry): void {
        const vSpeed = telemetry.v_speed;

        // Only record on touchdown (transition from negative to positive/zero)
        if (vSpeed < -100 && this.landingRate === 0) {
            this.landingRate = vSpeed;
            const absVSpeed = Math.abs(vSpeed);

            // Hard landing (exceeds max landing FPM)
            if (absVSpeed > this.limits.max_landing_fpm) {
                this.addViolation({
                    type: ViolationType.HARD_LANDING,
                    timestamp: new Date(),
                    severity: 'severe',
                    penalty: this.weights.penalty_hard_landing,
                    details: `HARD LANDING: ${absVSpeed.toFixed(0)} fpm (max: ${this.limits.max_landing_fpm} fpm)`,
                    telemetry,
                });
            }
            // Rough landing
            else if (absVSpeed > this.weights.landing_rough) {
                this.addViolation({
                    type: ViolationType.HARD_LANDING,
                    timestamp: new Date(),
                    severity: 'moderate',
                    penalty: this.weights.penalty_rough_landing,
                    details: `Rough landing: ${absVSpeed.toFixed(0)} fpm`,
                    telemetry,
                });
            }
            // Firm landing
            else if (absVSpeed > this.weights.landing_firm) {
                this.addViolation({
                    type: ViolationType.HARD_LANDING,
                    timestamp: new Date(),
                    severity: 'minor',
                    penalty: this.weights.penalty_firm_landing,
                    details: `Firm landing: ${absVSpeed.toFixed(0)} fpm`,
                    telemetry,
                });
            }
            // Butter landing bonus
            else if (absVSpeed < this.weights.landing_excellent) {
                this.score += this.weights.bonus_butter_landing;
                console.log(`[SCORING] BUTTER LANDING! +${this.weights.bonus_butter_landing} points`);
            }
        }
    }

    /**
     * Add violation and deduct points
     */
    private addViolation(violation: Violation): void {
        this.violations.push(violation);
        this.score = Math.max(0, this.score - violation.penalty);

        console.warn(`[SCORING] ${violation.details} (-${violation.penalty} points, Score: ${this.score})`);
    }

    /**
     * Estimate G-force from vertical speed change
     */
    private estimateGForce(telemetry: Telemetry): number {
        // Simple estimation: G = 1 + (ΔV / (g * Δt))
        // For now, return 1.0 as baseline
        // In production, calculate from actual acceleration data
        return 1.0;
    }

    /**
     * Get current score
     */
    getScore(): number {
        return Math.round(this.score);
    }

    /**
     * Get all violations
     */
    getViolations(): Violation[] {
        return [...this.violations];
    }

    /**
     * Get violations by severity
     */
    getViolationsBySeverity(severity: 'minor' | 'moderate' | 'severe'): Violation[] {
        return this.violations.filter(v => v.severity === severity);
    }

    /**
     * Get G-force statistics
     */
    getGForceStats(): {
        max: number;
        min: number;
        average: number;
    } {
        const avg = this.gForceHistory.length > 0
            ? this.gForceHistory.reduce((a, b) => a + b, 0) / this.gForceHistory.length
            : 1.0;

        return {
            max: this.maxGForce,
            min: this.minGForce,
            average: avg,
        };
    }

    /**
     * Get landing rate
     */
    getLandingRate(): number {
        return this.landingRate;
    }

    /**
     * Get landing grade
     */
    getLandingGrade(): 'Excellent' | 'Good' | 'Fair' | 'Firm' | 'Rough' | 'Hard' | 'N/A' {
        if (this.landingRate === 0) return 'N/A';

        const rate = Math.abs(this.landingRate);
        if (rate < this.weights.landing_excellent) return 'Excellent';
        if (rate < this.weights.landing_good) return 'Good';
        if (rate < this.weights.landing_fair) return 'Fair';
        if (rate < this.weights.landing_firm) return 'Firm';
        if (rate < this.weights.landing_rough) return 'Rough';
        return 'Hard';
    }

    /**
     * Get performance summary
     */
    getSummary(): {
        score: number;
        grade: string;
        violations: number;
        landingRate: number;
        landingGrade: string;
        gForceStats: ReturnType<FlightScoringEngine['getGForceStats']>;
    } {
        return {
            score: this.getScore(),
            grade: this.getGrade(),
            violations: this.violations.length,
            landingRate: this.landingRate,
            landingGrade: this.getLandingGrade(),
            gForceStats: this.getGForceStats(),
        };
    }

    /**
     * Get overall grade
     */
    private getGrade(): string {
        const score = this.score;
        if (score >= 95) return 'A+';
        if (score >= 90) return 'A';
        if (score >= 85) return 'A-';
        if (score >= 80) return 'B+';
        if (score >= 75) return 'B';
        if (score >= 70) return 'B-';
        if (score >= 65) return 'C+';
        if (score >= 60) return 'C';
        if (score >= 55) return 'C-';
        if (score >= 50) return 'D';
        return 'F';
    }

    /**
     * Reset scoring
     */
    reset(): void {
        this.score = 100;
        this.violations = [];
        this.gForceHistory = [];
        this.maxGForce = 1.0;
        this.minGForce = 1.0;
        this.landingRate = 0;
    }
}

/**
 * Navigation Utilities
 * Cross-track error calculation and route deviation detection
 */

import type { Telemetry, RouteWaypoint } from '@/types/flight';

// ============================================================================
// CONSTANTS
// ============================================================================

const EARTH_RADIUS_NM = 3440.065; // Nautical miles
const DEVIATION_THRESHOLD_NM = 5; // 5 NM deviation triggers alert

// ============================================================================
// GREAT CIRCLE CALCULATIONS
// ============================================================================

/**
 * Convert degrees to radians
 */
function toRadians(degrees: number): number {
    return degrees * (Math.PI / 180);
}

/**
 * Convert radians to degrees
 */
function toDegrees(radians: number): number {
    return radians * (180 / Math.PI);
}

/**
 * Calculate great circle distance between two points (Haversine formula)
 */
export function calculateDistance(
    lat1: number,
    lon1: number,
    lat2: number,
    lon2: number
): number {
    const φ1 = toRadians(lat1);
    const φ2 = toRadians(lat2);
    const Δφ = toRadians(lat2 - lat1);
    const Δλ = toRadians(lon2 - lon1);

    const a = Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
              Math.cos(φ1) * Math.cos(φ2) *
              Math.sin(Δλ / 2) * Math.sin(Δλ / 2);

    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

    return EARTH_RADIUS_NM * c;
}

/**
 * Calculate bearing from point A to point B
 */
export function calculateBearing(
    lat1: number,
    lon1: number,
    lat2: number,
    lon2: number
): number {
    const φ1 = toRadians(lat1);
    const φ2 = toRadians(lat2);
    const Δλ = toRadians(lon2 - lon1);

    const y = Math.sin(Δλ) * Math.cos(φ2);
    const x = Math.cos(φ1) * Math.sin(φ2) -
              Math.sin(φ1) * Math.cos(φ2) * Math.cos(Δλ);

    const θ = Math.atan2(y, x);
    return (toDegrees(θ) + 360) % 360;
}

// ============================================================================
// CROSS-TRACK ERROR
// ============================================================================

/**
 * Calculate cross-track error (XTE)
 * Returns the perpendicular distance from current position to the great circle path
 */
export function calculateCrossTrackError(
    currentLat: number,
    currentLon: number,
    startLat: number,
    startLon: number,
    endLat: number,
    endLon: number
): number {
    const δ13 = calculateDistance(startLat, startLon, currentLat, currentLon) / EARTH_RADIUS_NM;
    const θ13 = toRadians(calculateBearing(startLat, startLon, currentLat, currentLon));
    const θ12 = toRadians(calculateBearing(startLat, startLon, endLat, endLon));

    const δxt = Math.asin(Math.sin(δ13) * Math.sin(θ13 - θ12));

    return Math.abs(toDegrees(δxt) * EARTH_RADIUS_NM);
}

/**
 * Calculate along-track distance
 * Returns the distance along the great circle path from start to the closest point to current position
 */
export function calculateAlongTrackDistance(
    currentLat: number,
    currentLon: number,
    startLat: number,
    startLon: number,
    endLat: number,
    endLon: number
): number {
    const δ13 = calculateDistance(startLat, startLon, currentLat, currentLon) / EARTH_RADIUS_NM;
    const θ13 = toRadians(calculateBearing(startLat, startLon, currentLat, currentLon));
    const θ12 = toRadians(calculateBearing(startLat, startLon, endLat, endLon));

    const δxt = Math.asin(Math.sin(δ13) * Math.sin(θ13 - θ12));
    const δat = Math.acos(Math.cos(δ13) / Math.cos(δxt));

    return toDegrees(δat) * EARTH_RADIUS_NM;
}

// ============================================================================
// ROUTE DEVIATION DETECTION
// ============================================================================

export interface RouteDeviation {
    crossTrackError: number;      // NM
    alongTrackDistance: number;   // NM
    isDeviated: boolean;
    severity: 'normal' | 'warning' | 'alert';
    message: string;
    closestWaypoint?: RouteWaypoint;
    nextWaypoint?: RouteWaypoint;
}

/**
 * Check if aircraft is deviating from planned route
 */
export function checkRouteDeviation(
    telemetry: Telemetry,
    route: RouteWaypoint[]
): RouteDeviation {
    if (route.length < 2) {
        return {
            crossTrackError: 0,
            alongTrackDistance: 0,
            isDeviated: false,
            severity: 'normal',
            message: 'No route defined',
        };
    }

    // Find the current leg (closest two waypoints)
    const { from, to, index } = findCurrentLeg(telemetry, route);

    // Calculate cross-track error
    const xte = calculateCrossTrackError(
        telemetry.lat,
        telemetry.lng,
        from.lat,
        from.lng,
        to.lat,
        to.lng
    );

    // Calculate along-track distance
    const atd = calculateAlongTrackDistance(
        telemetry.lat,
        telemetry.lng,
        from.lat,
        from.lng,
        to.lat,
        to.lng
    );

    // Determine severity
    let severity: 'normal' | 'warning' | 'alert' = 'normal';
    let message = `On course (XTE: ${xte.toFixed(1)} NM)`;

    if (xte > DEVIATION_THRESHOLD_NM * 2) {
        severity = 'alert';
        message = `ROUTE DEVIATION ALERT: ${xte.toFixed(1)} NM off course`;
    } else if (xte > DEVIATION_THRESHOLD_NM) {
        severity = 'warning';
        message = `Route deviation warning: ${xte.toFixed(1)} NM off course`;
    }

    return {
        crossTrackError: xte,
        alongTrackDistance: atd,
        isDeviated: xte > DEVIATION_THRESHOLD_NM,
        severity,
        message,
        closestWaypoint: from,
        nextWaypoint: to,
    };
}

/**
 * Find the current leg of the route
 */
function findCurrentLeg(
    telemetry: Telemetry,
    route: RouteWaypoint[]
): { from: RouteWaypoint; to: RouteWaypoint; index: number } {
    let minDistance = Infinity;
    let closestIndex = 0;

    // Find closest waypoint
    for (let i = 0; i < route.length; i++) {
        const distance = calculateDistance(
            telemetry.lat,
            telemetry.lng,
            route[i].lat,
            route[i].lng
        );
        if (distance < minDistance) {
            minDistance = distance;
            closestIndex = i;
        }
    }

    // Determine if we're heading to or from this waypoint
    const from = closestIndex > 0 ? route[closestIndex - 1] : route[closestIndex];
    const to = closestIndex < route.length - 1 ? route[closestIndex + 1] : route[closestIndex];

    return { from, to, index: closestIndex };
}

/**
 * Calculate estimated time to next waypoint
 */
export function calculateETA(
    currentLat: number,
    currentLon: number,
    waypointLat: number,
    waypointLon: number,
    groundSpeed: number
): number {
    const distance = calculateDistance(currentLat, currentLon, waypointLat, waypointLon);

    if (groundSpeed <= 0) return 0;

    return (distance / groundSpeed) * 60; // minutes
}

/**
 * Calculate fuel required to next waypoint
 */
export function calculateFuelToWaypoint(
    currentLat: number,
    currentLon: number,
    waypointLat: number,
    waypointLon: number,
    groundSpeed: number,
    fuelBurnRate: number
): number {
    const eta = calculateETA(currentLat, currentLon, waypointLat, waypointLon, groundSpeed);
    return (eta / 60) * fuelBurnRate; // gallons
}

/**
 * Check if aircraft is within approach range of destination
 */
export function isInApproachRange(
    telemetry: Telemetry,
    destinationLat: number,
    destinationLon: number,
    rangeNM: number = 50
): boolean {
    const distance = calculateDistance(
        telemetry.lat,
        telemetry.lng,
        destinationLat,
        destinationLon
    );
    return distance <= rangeNM;
}

/**
 * Calculate progress along route (0-100%)
 */
export function calculateRouteProgress(
    telemetry: Telemetry,
    route: RouteWaypoint[]
): number {
    if (route.length < 2) return 0;

    const totalDistance = calculateDistance(
        route[0].lat,
        route[0].lng,
        route[route.length - 1].lat,
        route[route.length - 1].lng
    );

    const distanceFromStart = calculateDistance(
        route[0].lat,
        route[0].lng,
        telemetry.lat,
        telemetry.lng
    );

    return Math.min(100, (distanceFromStart / totalDistance) * 100);
}

/**
 * Format distance for display
 */
export function formatDistance(nm: number): string {
    if (nm < 1) {
        return `${(nm * 6076).toFixed(0)} ft`;
    }
    return `${nm.toFixed(1)} NM`;
}

/**
 * Format bearing for display
 */
export function formatBearing(degrees: number): string {
    const directions = ['N', 'NNE', 'NE', 'ENE', 'E', 'ESE', 'SE', 'SSE', 'S', 'SSW', 'SW', 'WSW', 'W', 'WNW', 'NW', 'NNW'];
    const index = Math.round(degrees / 22.5) % 16;
    return `${Math.round(degrees)}° ${directions[index]}`;
}

import GlobalConfig from '@/models/GlobalConfig';
import { PilotModel } from '@/models';
import Flight from '@/models/Flight';

export interface CreditBreakdown {
    base: number;
    landing: number;
    onTime: number;
    fuelEfficiency: number;
    longHaul: number;
    hubToHub: number;
    newRoute: number;
    firstFlight: number;
    taxiSpeed: number;
    lightViolation: number;
    overspeed: number;
    multiplier: number;
    total: number;
    details: string[];
}

// Hub airports for hub-to-hub bonus
const HUBS = ['OJAI', 'ORBI', 'OSDI', 'OERK', 'OMDB', 'OTHH'];

export async function calculateFlightCredits(params: {
    pilotId: string;
    departureIcao: string;
    arrivalIcao: string;
    landingRate: number;
    flightTimeMinutes: number;
    fuelUsed?: number;
    plannedFuel?: number;
    log?: any;
    isEventFlight?: boolean;
}): Promise<CreditBreakdown> {
    const { pilotId, departureIcao, arrivalIcao, landingRate, flightTimeMinutes, fuelUsed, plannedFuel, log, isEventFlight } = params;

    const config = await GlobalConfig.findOne({ key: 'LVT_MAIN' }).lean() as any;
    if (!config) {
        return { base: 100, landing: 0, onTime: 0, fuelEfficiency: 0, longHaul: 0, hubToHub: 0, newRoute: 0, firstFlight: 0, taxiSpeed: 0, lightViolation: 0, overspeed: 0, multiplier: 1, total: 100, details: ['Base: +100 CR'] };
    }

    const details: string[] = [];
    let multiplier = 1.0;

    // --- Base XP ---
    const base = config.cr_base_flight || 100;
    details.push(`Base flight: +${base} CR`);

    // --- Landing Rate Bonus/Penalty ---
    let landing = 0;
    const absRate = Math.abs(landingRate);
    if (absRate <= 150) {
        landing = config.cr_greaser_bonus || 50;
        details.push(`Greaser landing (${landingRate} fpm): +${landing} CR`);
    } else if (absRate <= 350) {
        landing = config.cr_firm_bonus || 25;
        details.push(`Firm but fair (${landingRate} fpm): +${landing} CR`);
    } else if (absRate >= 400 && absRate <= 600) {
        landing = config.cr_hard_landing_penalty || -50;
        details.push(`Hard landing (${landingRate} fpm): ${landing} CR`);
    } else if (absRate > 600) {
        landing = (config.cr_hard_landing_penalty || -50) * 2;
        details.push(`Very hard landing (${landingRate} fpm): ${landing} CR`);
    }

    // --- Fuel Efficiency ---
    let fuelEfficiency = 0;
    if (fuelUsed && plannedFuel && plannedFuel > 0) {
        const fuelDiffPercent = Math.abs(fuelUsed - plannedFuel) / plannedFuel * 100;
        if (fuelDiffPercent <= 5) {
            fuelEfficiency = config.cr_fuel_efficiency_bonus || 30;
            details.push(`Fuel efficiency (within 5%): +${fuelEfficiency} CR`);
        }
    }

    // --- Long Haul ---
    let longHaul = 0;
    const flightHours = flightTimeMinutes / 60;
    if (flightHours >= 8) {
        longHaul = config.cr_long_haul_8h || 250;
        details.push(`Long haul 8h+: +${longHaul} CR`);
    } else if (flightHours >= 4) {
        longHaul = config.cr_long_haul_4h || 100;
        details.push(`Long haul 4h+: +${longHaul} CR`);
    }

    // --- Hub-to-Hub ---
    let hubToHub = 0;
    if (HUBS.includes(departureIcao) && HUBS.includes(arrivalIcao) && departureIcao !== arrivalIcao) {
        hubToHub = config.cr_hub_to_hub_bonus || 50;
        details.push(`Hub-to-hub flight: +${hubToHub} CR`);
    }

    // --- New Route Discovery ---
    let newRoute = 0;
    const pilot = await PilotModel.findOne({ pilot_id: pilotId }).select('routes_flown last_flight_date').lean() as any;
    const routeKey = `${departureIcao}-${arrivalIcao}`;
    if (pilot && !pilot.routes_flown?.includes(routeKey)) {
        newRoute = config.cr_new_route_bonus || 50;
        details.push(`New route discovery: +${newRoute} CR`);
    }

    // --- First Flight of the Day ---
    let firstFlight = 0;
    if (pilot?.last_flight_date) {
        const lastDate = new Date(pilot.last_flight_date);
        const today = new Date();
        if (lastDate.toDateString() !== today.toDateString()) {
            firstFlight = 1; // flag for multiplier
            multiplier *= config.cr_first_flight_multiplier || 1.2;
            details.push(`First flight of the day: ${config.cr_first_flight_multiplier || 1.2}x multiplier`);
        }
    } else {
        firstFlight = 1;
        multiplier *= config.cr_first_flight_multiplier || 1.2;
        details.push(`First flight ever: ${config.cr_first_flight_multiplier || 1.2}x multiplier`);
    }

    // --- Event Multiplier ---
    if (isEventFlight) {
        multiplier *= config.cr_event_multiplier || 2.0;
        details.push(`Event flight: ${config.cr_event_multiplier || 2.0}x multiplier`);
    }

    // --- Professionalism Penalties from ACARS log ---
    let taxiSpeed = 0;
    let lightViolation = 0;
    let overspeed = 0;

    if (log?.deductions && Array.isArray(log.deductions)) {
        for (const d of log.deductions) {
            const reason = (d.reason || '').toLowerCase();
            if (reason.includes('taxi') && reason.includes('speed')) {
                taxiSpeed += config.cr_taxi_speed_penalty || -10;
            }
            if (reason.includes('light') || reason.includes('strobe') || reason.includes('landing light')) {
                lightViolation += config.cr_light_violation_penalty || -15;
            }
            if (reason.includes('overspeed') || reason.includes('over speed') || reason.includes('vmo')) {
                overspeed += config.cr_overspeed_penalty || -50;
            }
        }
        if (taxiSpeed) details.push(`Taxi speed violation: ${taxiSpeed} CR`);
        if (lightViolation) details.push(`Light violation: ${lightViolation} CR`);
        if (overspeed) details.push(`Overspeed penalty: ${overspeed} CR`);
    }

    // --- On-Time Bonus (placeholder — needs estimated vs actual comparison) ---
    const onTime = 0;

    // --- Calculate Total ---
    const rawTotal = base + landing + onTime + fuelEfficiency + longHaul + hubToHub + newRoute + taxiSpeed + lightViolation + overspeed;
    const total = Math.max(0, Math.round(rawTotal * multiplier));

    details.push(`---`);
    details.push(`Multiplier: ${multiplier.toFixed(2)}x`);
    details.push(`Total: ${total} CR`);

    return {
        base, landing, onTime, fuelEfficiency, longHaul, hubToHub, newRoute,
        firstFlight, taxiSpeed, lightViolation, overspeed, multiplier, total, details,
    };
}

/**
 * Award flight credits to a pilot's balance and update routes_flown and last_flight_date
 */
export async function awardFlightCredits(pilotId: string, credits: number, departureIcao: string, arrivalIcao: string): Promise<void> {
    const routeKey = `${departureIcao}-${arrivalIcao}`;
    await PilotModel.findOneAndUpdate(
        { pilot_id: pilotId },
        {
            $inc: { balance: credits },
            $addToSet: { routes_flown: routeKey },
            $set: { last_flight_date: new Date() },
        }
    );
}

/**
 * Email Service
 * Comprehensive email notification system with Nodemailer
 */

import nodemailer from 'nodemailer';
import type { Transporter } from 'nodemailer';
import {
    EmailNotificationType,
    EmailPriority,
} from '@/types/notifications';
import type {
    EmailTemplateData,
    EmailNotification,
} from '@/types/notifications';

// ============================================================================
// EMAIL CONFIGURATION
// ============================================================================

interface EmailConfig {
    host: string;
    port: number;
    secure: boolean;
    auth: {
        user: string;
        pass: string;
    };
    tls: {
        rejectUnauthorized: boolean;
        minVersion: string;
    };
    from: {
        name: string;
        email: string;
    };
}

const emailConfig: EmailConfig = {
    host: process.env.SMTP_HOST || 'smtp.gmail.com',
    port: parseInt(process.env.SMTP_PORT || '587'),
    secure: process.env.SMTP_SECURE === 'true',
    auth: {
        user: process.env.SMTP_USER || '',
        pass: process.env.SMTP_PASSWORD || '',
    },
    tls: {
        rejectUnauthorized: false,
        minVersion: 'TLSv1.2',
    },
    from: {
        name: process.env.EMAIL_FROM_NAME || 'Levant Virtual Airline',
        email: process.env.EMAIL_FROM || 'noreply@levant-va.com',
    },
};

// ============================================================================
// EMAIL SERVICE CLASS
// ============================================================================

export class EmailService {
    private transporter!: Transporter;
    private isConfigured: boolean;

    constructor() {
        this.isConfigured = this.validateConfig();

        if (this.isConfigured) {
            this.transporter = nodemailer.createTransport({
                host: emailConfig.host,
                port: emailConfig.port,
                secure: emailConfig.secure,
                auth: emailConfig.auth,
                tls: emailConfig.tls,
                connectionTimeout: 10000,
                greetingTimeout: 5000,
                socketTimeout: 15000,
            } as any);

            this.transporter.verify((error: any) => {
                if (error) {
                    console.error('[EmailService] SMTP connection verification failed:', error.message);
                    console.error('[EmailService] Host:', emailConfig.host, 'Port:', emailConfig.port);
                } else {
                    console.log('[EmailService] SMTP server connection verified and ready');
                    console.log('[EmailService] Host:', emailConfig.host, 'Port:', emailConfig.port);
                }
            });
        } else {
            console.warn('Email service not configured. Emails will be logged only.');
        }
    }

    private validateConfig(): boolean {
        return !!(
            emailConfig.host &&
            emailConfig.auth.user &&
            emailConfig.auth.pass
        );
    }

    /**
     * Send email
     */
    async sendEmail(
        to: string,
        subject: string,
        html: string,
        text: string,
        priority: EmailPriority = EmailPriority.NORMAL
    ): Promise<{ success: boolean; messageId?: string; error?: string }> {
        if (!this.isConfigured) {
            console.log('[EMAIL] Would send:', { to, subject });
            return { success: false, error: 'Email service not configured' };
        }

        try {
            const info: any = await this.transporter.sendMail({
                from: `"${emailConfig.from.name}" <${emailConfig.from.email}>`,
                to,
                subject,
                html,
                text,
                priority: this.getPriorityHeader(priority) as any,
            });

            console.log('[EMAIL] Sent:', info.messageId);
            return { success: true, messageId: info.messageId };
        } catch (error: any) {
            console.error('[EmailService] Failed to send email');
            console.error('[EmailService] Recipient:', to);
            console.error('[EmailService] Subject:', subject);
            console.error('[EmailService] Error:', error.message);
            console.error('[EmailService] SMTP Host:', emailConfig.host, 'Port:', emailConfig.port);
            return { success: false, error: error.message };
        }
    }

    /**
     * Send notification email using template
     */
    async sendNotification(
        type: EmailNotificationType,
        to: string,
        data: EmailTemplateData,
        priority?: EmailPriority
    ): Promise<{ success: boolean; messageId?: string; error?: string }> {
        const template = this.getTemplate(type, data);
        const emailPriority = priority || this.getDefaultPriority(type);

        return this.sendEmail(
            to,
            template.subject,
            template.html,
            template.text,
            emailPriority
        );
    }

    /**
     * Get email template
     */
    private getTemplate(
        type: EmailNotificationType,
        data: EmailTemplateData
    ): { subject: string; html: string; text: string } {
        const templates = {
            welcome: this.getWelcomeTemplate,
            registration_approved: this.getRegistrationApprovedTemplate,
            registration_rejected: this.getRegistrationRejectedTemplate,
            account_blacklisted: this.getAccountBlacklistedTemplate,
            password_reset: this.getPasswordResetTemplate,
            pirep_approved: this.getPIREPApprovedTemplate,
            pirep_rejected: this.getPIREPRejectedTemplate,
            group_flight_reminder_24h: this.getGroupFlightReminder24hTemplate,
            group_flight_reminder_1h: this.getGroupFlightReminder1hTemplate,
            badge_earned: this.getBadgeEarnedTemplate,
            rank_promotion: this.getRankPromotionTemplate,
            loa_approved: this.getLOAApprovedTemplate,
            loa_rejected: this.getLOARejectedTemplate,
            event_results: this.getEventResultsTemplate,
        };

        const templateFn = templates[type as keyof typeof templates];
        if (templateFn) {
            return templateFn.call(this, data);
        }

        return this.getGenericTemplate(type, data);
    }

    /**
     * Get priority header
     */
    private getPriorityHeader(priority: EmailPriority): string {
        const map: Record<EmailPriority, string> = {
            [EmailPriority.LOW]: 'low',
            [EmailPriority.NORMAL]: 'normal',
            [EmailPriority.HIGH]: 'high',
            [EmailPriority.URGENT]: 'high',
        };
        return map[priority];
    }

    /**
     * Get default priority for notification type
     */
    private getDefaultPriority(type: EmailNotificationType): EmailPriority {
        const urgentTypes = [EmailNotificationType.PASSWORD_RESET, EmailNotificationType.ACCOUNT_BLACKLISTED, EmailNotificationType.GROUP_FLIGHT_REMINDER_1H];
        const highTypes = [EmailNotificationType.REGISTRATION_APPROVED, EmailNotificationType.PIREP_APPROVED, EmailNotificationType.RANK_PROMOTION];

        if (urgentTypes.includes(type)) return EmailPriority.URGENT;
        if (highTypes.includes(type)) return EmailPriority.HIGH;
        return EmailPriority.NORMAL;
    }

