        [EventType.LANDING_CHALLENGE]: '🛬',
        [EventType.FUEL_EFFICIENCY]: '⛽',
        [EventType.SPEED_RUN]: '⚡',
        [EventType.LONG_HAUL]: '🌍',
        [EventType.PERFECT_SCORE]: '💯',
        [EventType.GROUP_FLIGHT]: '👥',
